-- Poems batch 303
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('57ba996f-adf5-4f25-bf99-8fcc98085e88','與持國約游環溪大風不果往又過曾氏值主人之病','劉攽','宋','宋诗','song-poetry','','[]','人事不如意，出門安可期。',24,'全唐诗/poet.song.35000.json','["人事不如意，出門安可期。", "終須賞春物，那問主人爲。"]'),
('438f10ca-432e-4b87-b550-16ed9e4db0d3','蓮池','劉攽','宋','宋诗','song-poetry','','[]','蓮花水底紅，荷葉岸邊風。',24,'全唐诗/poet.song.35000.json','["蓮花水底紅，荷葉岸邊風。", "五月蟬鳴後，君應愛此中。"]'),
('c39fd73a-fea7-4d34-989d-94c3d5d0898e','東樓','劉攽','宋','宋诗','song-poetry','','[]','樓前淮水上，遠樹似魚鱗。',24,'全唐诗/poet.song.35000.json','["樓前淮水上，遠樹似魚鱗。", "來帆與去櫂，腸斷倚欄人。"]'),
('1235e0c1-b3ba-4c81-bcae-4bef229c7692','長門曲  其一','劉攽','宋','宋诗','song-poetry','','[]','凝笳來鳳輦，玉宇開深殿。',24,'全唐诗/poet.song.35000.json','["凝笳來鳳輦，玉宇開深殿。", "君恩春風迴，那向秋時怨。"]'),
('6c5591a2-c9aa-4a16-aa3e-e863480002ea','長門曲  其二','劉攽','宋','宋诗','song-poetry','','[]','君心似明月，月缺應再圓。',24,'全唐诗/poet.song.35000.json','["君心似明月，月缺應再圓。", "但令黄河水，到海還上天。"]'),
('89ca226d-c9e8-4096-bc96-94ad2f956159','書堂對雪  其一','劉攽','宋','宋诗','song-poetry','','[]','幽居遠人境，竹柏映吾廬。',24,'全唐诗/poet.song.35000.json','["幽居遠人境，竹柏映吾廬。", "滿目山林意，今晨霰雪初。"]'),
('f20d1751-640d-498e-b984-9f35070f5051','書堂對雪  其二','劉攽','宋','宋诗','song-poetry','','[]','積風寒玉折，驚鳥落花餘。',24,'全唐诗/poet.song.35000.json','["積風寒玉折，驚鳥落花餘。", "定有麕麚迹，環林未掃除。"]'),
('72fcec61-f090-4069-a458-8c90ad3ad567','雨後回文','劉攽','宋','宋诗','song-poetry','','[]','綠水池光冷，青苔砌色寒。',24,'全唐诗/poet.song.35000.json','["綠水池光冷，青苔砌色寒。", "竹幽啼鳥亂，庭暗落花殘。"]'),
('f40c4043-874d-48fc-9308-4a212e858f47','旅舍不寐作回文四句','劉攽','宋','宋诗','song-poetry','','[]','定雲浮黑月，驚風觸巢鳥。',24,'全唐诗/poet.song.35000.json','["定雲浮黑月，驚風觸巢鳥。", "暝燈客單寢，短夢恨遲曉。"]'),
('1c4fd2c0-cd6e-461d-9dd8-0d90024976f3','勤道堂','劉攽','宋','宋诗','song-poetry','','[]','西秦公子樗名里，南楚真仙漆種園。',32,'全唐诗/poet.song.35000.json','["西秦公子樗名里，南楚真仙漆種園。", "誰顧世人多大笑，偶題勤道志忘言。"]'),
('3e9ba7f4-ede8-4b98-907b-81b3695d34ce','初暑馬上  其一','劉攽','宋','宋诗','song-poetry','','[]','負弩前呼地起塵，炎風烈日正隨人。',32,'全唐诗/poet.song.35000.json','["負弩前呼地起塵，炎風烈日正隨人。", "暫投茅舍支拳坐，却是從前倦客身。"]'),
('ba8ec292-26a9-442e-bdf3-d910f4cc1f0b','初暑馬上  其二','劉攽','宋','宋诗','song-poetry','','[]','荆扉茅屋水平流，竹簟棋盤局未收。',32,'全唐诗/poet.song.35000.json','["荆扉茅屋水平流，竹簟棋盤局未收。", "無用詢他名與姓，忙閒有分不相投。"]'),
('da63e5d3-cf71-420b-9928-84c57203d37e','初暑馬上  其三','劉攽','宋','宋诗','song-poetry','','[]','臧孫御叔悉名卿，飲酒何妨傲雨行。',32,'全唐诗/poet.song.35000.json','["臧孫御叔悉名卿，飲酒何妨傲雨行。", "未似驅車日當午，敢嫌高士笑勞生。"]'),
('7bc81a62-9ce0-4472-9160-abf6c46c8928','貝州亂二首  其一','劉攽','宋','宋诗','song-poetry','','[]','軍書羽騎曉紛紛，兵起清河一日聞。',32,'全唐诗/poet.song.35000.json','["軍書羽騎曉紛紛，兵起清河一日聞。", "多少衣冠盡塗地，憑高依約見妖氛。"]'),
('9f5b6e2d-0ff3-431c-8b12-397bbaa05e13','貝州亂二首  其二','劉攽','宋','宋诗','song-poetry','','[]','金印他時恩澤侯，專城意氣凜生秋。',32,'全唐诗/poet.song.35000.json','["金印他時恩澤侯，專城意氣凜生秋。", "軍中成敗如翻水，空使明堂旰食憂。"]'),
('cfe06ccd-2dd1-488f-a64f-9316c8793adc','遊章運判園亭  其一','劉攽','宋','宋诗','song-poetry','','[]','自有林亭不種花，總將春色寄鄰家。',32,'全唐诗/poet.song.35000.json','["自有林亭不種花，總將春色寄鄰家。", "桃紅梅白須尋得，暮去朝來不算賒。"]'),
('07535ece-1706-43cc-a5a9-aad3358337ce','遊章運判園亭  其二','劉攽','宋','宋诗','song-poetry','','[]','客舍栽花欲爲主，出門騎馬即天涯。',32,'全唐诗/poet.song.35000.json','["客舍栽花欲爲主，出門騎馬即天涯。", "何時置得尋常地，管領春風屬自家。"]'),
('28ceeeea-b203-454c-9608-5286d31792b3','旅館','劉攽','宋','宋诗','song-poetry','','[]','滿月還成破鏡飛，流螢清露夜依依。',32,'全唐诗/poet.song.35000.json','["滿月還成破鏡飛，流螢清露夜依依。", "弄兒看織無窮樂，咫尺嵩雲不得歸。"]'),
('bd501972-1f0d-4382-a40c-842832a937f9','九蕊芙蓉','劉攽','宋','宋诗','song-poetry','','[]','托根不近芙蓉苑，移植猶依瘴癘鄉。',32,'全唐诗/poet.song.35000.json','["托根不近芙蓉苑，移植猶依瘴癘鄉。", "並蕊連心九相似，看來還使九回腸。"]'),
('64a32c32-b64d-4e5f-90a3-973c1cadb7ef','九月吉日澗上望芙蓉因尋菊今歲特晚青蕊未作憮然有懷','劉攽','宋','宋诗','song-poetry','','[]','百芳不奈秋風急，唯有芙蓉特拒霜。',32,'全唐诗/poet.song.35000.json','["百芳不奈秋風急，唯有芙蓉特拒霜。", "本以南州積炎德，一爲名誤客殊方。"]'),
('b5779f55-1059-4811-856b-44c14ae4748e','寄關西兄弟','劉攽','宋','宋诗','song-poetry','','[]','曉風吹盡淮南雪，昨夜汀州白芷生。',32,'全唐诗/poet.song.35000.json','["曉風吹盡淮南雪，昨夜汀州白芷生。", "遥想春光西北去，倩傳相憶向秦城。"]'),
('b522870e-190a-439b-9a06-ddbef9303a1d','閶闔臺  其一','劉攽','宋','宋诗','song-poetry','','[]','看雪望春何處好，城腰山腹暫來登。',32,'全唐诗/poet.song.35000.json','["看雪望春何處好，城腰山腹暫來登。", "人知容足無餘願，便是章華與九層。"]'),
('d138f4fd-4f68-4cab-9b79-2ea80ed01c63','閶闔臺  其二','劉攽','宋','宋诗','song-poetry','','[]','紅日駸駸還暗夜，輕車去去只微塵。',32,'全唐诗/poet.song.35000.json','["紅日駸駸還暗夜，輕車去去只微塵。", "老夫獨立聊觀化，驚怪往來無限人。"]'),
('ea2159e3-b597-4675-aad1-df76198952ef','納凉明教臺','劉攽','宋','宋诗','song-poetry','','[]','臺上井泉冰冷滑，城隅川色劍光芒。',32,'全唐诗/poet.song.35000.json','["臺上井泉冰冷滑，城隅川色劍光芒。", "多慚簿領相寬假，全得南風一日凉。"]'),
('df90a3e6-a176-4971-b43e-d25893c6ae13','梅雨','劉攽','宋','宋诗','song-poetry','','[]','梅實初黄暮雨深，寶刀生鏽鏡昏沈。',32,'全唐诗/poet.song.35000.json','["梅實初黄暮雨深，寶刀生鏽鏡昏沈。", "年年卑濕身無病，自覺能勝百鍊金。"]'),
('b8715b85-399d-43d1-9c1d-9ccd7802a60c','隠語三首呈通判庫部  其一','劉攽','宋','宋诗','song-poetry','','[]','梧上生枝復隔年，白頭傾蓋兩歡然。',32,'全唐诗/poet.song.35000.json','["梧上生枝復隔年，白頭傾蓋兩歡然。", "滿城童子垂髫髮，竹馬羊車戲路邊。"]'),
('06a33d17-ce47-4bef-8bce-75c161c62f6e','隠語三首呈通判庫部  其二','劉攽','宋','宋诗','song-poetry','','[]','邯鄲度曲盡新聲，稚萼韶華稍向榮。',32,'全唐诗/poet.song.35000.json','["邯鄲度曲盡新聲，稚萼韶華稍向榮。", "珠箔曲鈎遮密坐，瑶臺靜室伴深行。"]'),
('526344b5-b692-4bed-b096-035d1a2ace73','隠語三首呈通判庫部  其三','劉攽','宋','宋诗','song-poetry','','[]','宮柳飛花暗度春，斛愁容貯奈傷神。',32,'全唐诗/poet.song.35000.json','["宮柳飛花暗度春，斛愁容貯奈傷神。", "曼聲試作鷄鳴曲，何必陽關無故人。"]'),
('16d52d81-05c6-4923-a62b-ddf93de05dd5','新開湖上待潛珠不出偶書戲孫莘老二首  其一','劉攽','宋','宋诗','song-poetry','','[]','貝闕藏珠安在哉，九淵深絕若爲媒。',32,'全唐诗/poet.song.35000.json','["貝闕藏珠安在哉，九淵深絕若爲媒。", "風波可畏且歸去，漫道扁舟湖上來。"]'),
('cd459fb2-31b5-4205-9ac0-f13ca0c4b8d1','新開湖上待潛珠不出偶書戲孫莘老二首  其二','劉攽','宋','宋诗','song-poetry','','[]','合浦因人去不還，隋侯未值報恩年。',32,'全唐诗/poet.song.35000.json','["合浦因人去不還，隋侯未值報恩年。", "欲憑泉客傳微信，夜久凉風月滿川。"]'),
('dbd1389e-a6eb-45c9-90ef-64ffec70bb1b','入汜水寄仲馮','劉攽','宋','宋诗','song-poetry','','[]','沙起河津迷積霧，雲遮晚日怯層山。',32,'全唐诗/poet.song.35000.json','["沙起河津迷積霧，雲遮晚日怯層山。", "客行正似摴蒱局，疊馬來過第二關。"]'),
('6249d359-77c0-42d3-b6c5-92934dee12e3','新燕','劉攽','宋','宋诗','song-poetry','','[]','主人恩厚與相依，畫棟危檐晝啟扉。',32,'全唐诗/poet.song.35000.json','["主人恩厚與相依，畫棟危檐晝啟扉。", "豈是有心希鵠雁，衆雛成就即歸飛。"]'),
('c09f8a66-966a-49f0-9ee6-8713e16fbbf1','出都','劉攽','宋','宋诗','song-poetry','','[]','王孫蓮勺鹵中困，文叔蕪蔞亭下寒。',32,'全唐诗/poet.song.35000.json','["王孫蓮勺鹵中困，文叔蕪蔞亭下寒。", "塵俗豈知湖海士，敝裘羸馬出長安。"]'),
('d2719c55-ca53-455a-aa79-5c01df196adb','致齋太常寺以杖畫地成二首  其一','劉攽','宋','宋诗','song-poetry','','[]','少有閒人訪寂寥，薄雲淡日早春朝。',32,'全唐诗/poet.song.35000.json','["少有閒人訪寂寥，薄雲淡日早春朝。", "庭花弄蕊萱生笋，時見東風趁柳條。"]'),
('6defc5d1-8c87-4ec3-8e6f-355d76f1c8f1','致齋太常寺以杖畫地成二首  其二','劉攽','宋','宋诗','song-poetry','','[]','杖藤爲筆沙爲紙，閒立庭前試草書。',32,'全唐诗/poet.song.35000.json','["杖藤爲筆沙爲紙，閒立庭前試草書。", "無奈春風猶掣肘，等閒撩亂入衣裾。"]'),
('80f5e16d-488b-4271-93f2-54ca7331ef4f','寧陵陂  其一','劉攽','宋','宋诗','song-poetry','','[]','十里菰蒲百頃陂，秋風嫋嫋蕩漣漪。',32,'全唐诗/poet.song.35000.json','["十里菰蒲百頃陂，秋風嫋嫋蕩漣漪。", "旅遊已信江湖遠，水國猶將晝夢疑。"]'),
('603f35b3-245f-45a9-88c6-087d0100308e','寧陵陂  其二','劉攽','宋','宋诗','song-poetry','','[]','屈鈎結網老農妻，鼓檝鳴榔舊牧兒。',32,'全唐诗/poet.song.35000.json','["屈鈎結網老農妻，鼓檝鳴榔舊牧兒。", "世事誰令山海變，可憐機械亦相隨。"]'),
('3097930f-6c0b-40a7-92e2-e2a331fa38ca','長春花','劉攽','宋','宋诗','song-poetry','','[]','雪霜雨露平分盡，舊紫新紅次第開。',32,'全唐诗/poet.song.35000.json','["雪霜雨露平分盡，舊紫新紅次第開。", "自是餘花芳意薄，那知春去不重來。"]'),
('2c244720-d23a-4b74-9d55-b07b530dd81e','次子由韵三首  其一','劉攽','宋','宋诗','song-poetry','','[]','流霞飲過已忘寒，和筆螭坳墨色乾。',32,'全唐诗/poet.song.35000.json','["流霞飲過已忘寒，和筆螭坳墨色乾。", "溫室前頭問名木，此身知不誤儒冠。"]'),
('b30642e2-b747-4eae-99c3-8fcc2d3ae8b7','次子由韵三首  其二','劉攽','宋','宋诗','song-poetry','','[]','四朝傳說直臣言，萬事多君與輊軒。',32,'全唐诗/poet.song.35000.json','["四朝傳說直臣言，萬事多君與輊軒。", "重到彤墀揮翰處，想知雲夢一時吞。"]'),
('3f98b230-4f01-4dc5-8804-deb66e7a1ca1','次子由韵三首  其三','劉攽','宋','宋诗','song-poetry','','[]','華光勸講想天臨，白髮儒先遇主心。',32,'全唐诗/poet.song.35000.json','["華光勸講想天臨，白髮儒先遇主心。", "仍寄史臣揮直筆，聖謨文思與幾深。"]'),
('6f4b148a-2046-46c7-9adc-6683fc71a9b1','泊淮上','劉攽','宋','宋诗','song-poetry','','[]','風波繚繞半天下，鬢髮蒼筤一丈夫。',32,'全唐诗/poet.song.35000.json','["風波繚繞半天下，鬢髮蒼筤一丈夫。", "惆悵江湖向時月，又來淮浦照檣烏。"]'),
('deabfce3-9c15-441f-85d1-83422c255594','久旱作問詩  其一','劉攽','宋','宋诗','song-poetry','','[]','問雲何意復歸山，應恃無心欲占閒。',32,'全唐诗/poet.song.35000.json','["問雲何意復歸山，應恃無心欲占閒。", "我爲閒多忙折我，勸雲爲雨莫空還。"]'),
('2b558620-4bb3-4365-8b6e-fe9615dce62a','久旱作問詩  其二','劉攽','宋','宋诗','song-poetry','','[]','問風何意掃雲開，本爲虞琴喚汝來。',32,'全唐诗/poet.song.35000.json','["問風何意掃雲開，本爲虞琴喚汝來。", "桑麥青乾天不雨，更將何物阜民財。"]'),
('9d617250-1d30-4536-b9c2-d02d4a7fed67','久旱作問詩  其三','劉攽','宋','宋诗','song-poetry','','[]','問山何意及郊農，天欲爲霖不見容。',32,'全唐诗/poet.song.35000.json','["問山何意及郊農，天欲爲霖不見容。", "少閉土囊誅嘯虎，也教雲氣得從龍。"]'),
('bfd37ff0-55f8-4f5f-9714-6f5d0d9750a4','遣悶二首  其一','劉攽','宋','宋诗','song-poetry','','[]','好飲本來身少事，徒歌非是曲彌高。',32,'全唐诗/poet.song.35000.json','["好飲本來身少事，徒歌非是曲彌高。", "若能全療詩書癖，用底聊均筆硯勞。"]'),
('f6187e3f-afd7-4891-9222-3c48c6e084f0','遣悶二首  其二','劉攽','宋','宋诗','song-poetry','','[]','草荒三徑尋常綠，樹掩雙扉丈尺高。',32,'全唐诗/poet.song.35000.json','["草荒三徑尋常綠，樹掩雙扉丈尺高。", "燕語不如鶑語靜，蜂飛猶勝蝶飛勞。"]'),
('c475b772-79eb-4874-a950-10e9000d26ac','感懷','劉攽','宋','宋诗','song-poetry','','[]','澤雉呼雌日出飛，林鴉失子夜深啼。',32,'全唐诗/poet.song.35000.json','["澤雉呼雌日出飛，林鴉失子夜深啼。", "勞生未盡無生理，外境移心不得齊。"]'),
