('f49bed76-101e-4887-bb96-53dbd528bbda','和原甫謁武信殿  其二','劉攽','宋','宋诗','song-poetry','','[]','願借前籌敢决疑，斡回天地聳當時。',32,'全唐诗/poet.song.35000.json','["願借前籌敢决疑，斡回天地聳當時。", "舊傳太尉條侯策，今見宣王六月詩。"]'),
('02d32428-45df-4632-ad53-5863f938727c','望廬山','劉攽','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蒼山去郭三十里，日暮雲收獨立時。',32,'全唐诗/poet.song.35000.json','["蒼山去郭三十里，日暮雲收獨立時。", "應是塵埃能瞇眼，幾人曾有望山詩。"]'),
('f4f75678-6581-4163-9e5d-8934a84f466b','次韵和王待制絕句  其一','劉攽','宋','宋诗','song-poetry','','[]','病軀何處識君恩，卧地無令四體勤。',32,'全唐诗/poet.song.35000.json','["病軀何處識君恩，卧地無令四體勤。", "客誦舍人詩句好，幾將筆硯一時焚。"]'),
('845cd3a8-a589-4d0d-a583-f1d1f8459499','次韵和王待制絕句  其二','劉攽','宋','宋诗','song-poetry','','[]','無年何日蘇凋瘵，死市空嗟費杖笞。',32,'全唐诗/poet.song.35000.json','["無年何日蘇凋瘵，死市空嗟費杖笞。", "舊尹告新應有意，若爲閒暇得遊嬉。"]'),
('ac884381-0992-49c3-8324-ff49ffb9264f','次韵和王待制絕句  其三','劉攽','宋','宋诗','song-poetry','','[]','蔡邕倒屣貴公子，阮籍清談林下游。',32,'全唐诗/poet.song.35000.json','["蔡邕倒屣貴公子，阮籍清談林下游。", "人事差池不如古，祇將朱墨繼爲州。"]'),
('790446e8-1396-4645-8e2e-26ee8234b700','寄韓玉汝待制  其一','劉攽','宋','宋诗','song-poetry','','[]','南雲不到飛狐口，朔雪來從累雁門。',32,'全唐诗/poet.song.35000.json','["南雲不到飛狐口，朔雪來從累雁門。", "仗節仍煩鑿空使，乘槎徑取濁河源。"]'),
('cec90d93-6ca5-4886-b1e0-05d166ca0679','寄韓玉汝待制  其二','劉攽','宋','宋诗','song-poetry','','[]','嫖姚不復顧家爲，誰謂東山久未歸。',32,'全唐诗/poet.song.35000.json','["嫖姚不復顧家爲，誰謂東山久未歸。", "卷耳幸容携婉孌，皇華何啻有光輝。"]'),
('fa8f48cb-c1e1-4ed3-92dc-3d291206c1d4','秋盡野次  其一','劉攽','宋','宋诗','song-poetry','','[]','丹椒結子菊花黄，山路秋高草木香。',32,'全唐诗/poet.song.35000.json','["丹椒結子菊花黄，山路秋高草木香。", "日出鷄鳴下喬樹，人來犬吠透疏篁。"]'),
('9311917f-57de-4108-b8f8-bd34f97f89e2','秋盡野次  其二','劉攽','宋','宋诗','song-poetry','','[]','湖水彌天未覺秋，暫辭鞍馬寄扁舟。',32,'全唐诗/poet.song.35000.json','["湖水彌天未覺秋，暫辭鞍馬寄扁舟。", "菰蒲無禁魚無稅，誰似溪翁得自由。"]'),
('7ab3ed5f-31f5-4478-b37d-18d3daa75f52','舟中夜飲憶和弟聯句','劉攽','宋','宋诗','song-poetry','','[]','人生如浮雲，聚散苦不定。',120,'全唐诗/poet.song.35000.json','["人生如浮雲，聚散苦不定。", "向來詩酒歡，雖唱誰與應。", "蟋蟀鳴在戶，玉衡逼冬孟。", "悠悠千里思，寂寂中夜靜。", "豈曰無他人，不如我同姓。", "吁嗟繫名利，有若置機穽。", "窘然塵埃中，耻無六翮勁。", "訪戴舟已慚，攀嵇駕難命。", "臨觴置不飲，引領起獨咏。", "莽莽天地昏，誰知我心怲。"]'),
('92ace673-b795-4d1b-9ca7-9b74a3096dbb','寄獻淮西大哥給事','劉攽','宋','宋诗','song-poetry','','[]','千里提封盛府開，照淮紅旆晚徘徊。',64,'全唐诗/poet.song.35000.json','["千里提封盛府開，照淮紅旆晚徘徊。", "地靈固有壺公舊，時泰不同唐相來。", "韋斷陳編占藥喜，珠揮新什咏蘭陔。", "阿連今羨南飛翼，酒影猶能入壽杯。"]'),
('d5ff5a8e-4601-4d6a-8dae-a467e6bd2c72','題古畫山水障子','劉攽','宋','宋诗','song-poetry','','[]','應是塵外境，不隨陵谷遷。',24,'全唐诗/poet.song.35000.json','["應是塵外境，不隨陵谷遷。", "江山猶舊日，松柏又千年。"]'),
('1c91219b-f38b-49dd-90f3-2b8c38b6c5e1','山水屏','劉攽','宋','宋诗','song-poetry','','[]','吾家古屏來江南，白晝水墨漬烟嵐。',98,'全唐诗/poet.song.35000.json','["吾家古屏來江南，白晝水墨漬烟嵐。", "我行北方未嘗見，衆道巫峽仍湘潭。", "山頭老樹長參天，水上衰公撐釣船。", "青蓑擁身稚子眠，得魚不賣心悠然。", "久嫌時世趣向狹，頗思種藥依林泉。", "桃源仙家不可到，但願屏上山水置眼前。"]'),
('910a6a67-af11-41f6-a485-fa33b18b3408','于秘校示郊園棠木連理圖偶題長句','劉攽','宋','宋诗','song-poetry','','[]','昨得伻圖與賦詩，野棠并幹上交枝。',64,'全唐诗/poet.song.35000.json','["昨得伻圖與賦詩，野棠并幹上交枝。", "始疑和氣偏回復，可是常情悅附離。", "愛樹去思吾豈敢，高門陰德子應知。", "濟南固有終軍辨，傳布仍煩老畫師。"]'),
('6c4b813f-611e-41de-8b7b-f2b6c905c761','壁畫古槎歌','劉攽','宋','宋诗','song-poetry','','[]','南山大樹楓與樗，百年不到生理枯。',96,'全唐诗/poet.song.35000.json','["南山大樹楓與樗，百年不到生理枯。", "老枝錯落麋奮角，病根蟉結龍垂鬍。", "風霜不知春不改，古苔懸蔓相縈带。", "豈知高堂素壁上，畫圖能令觀者愛。", "野夫晨興坐樹邊，偶說此槎來上天。", "暫乘西風犯牛斗，却看東海成桑田。"]'),
('cf6e4792-d677-4910-b5cc-0f3fe7067cc1','和江鄰幾梅聖俞同蔡學士觀宋家書畫','劉攽','宋','宋诗','song-poetry','','[]','中郎石經天下傳，江翁說詩當世賢。',208,'全唐诗/poet.song.35000.json','["中郎石經天下傳，江翁說詩當世賢。", "南昌子真亦祿仕，讀書養性希神仙。", "雄豪相遇古莫及，所至衣冠爭願焉。", "貴公子孫誰是勝，廣平家書盈萬千。", "當時交友皆父行，賈生論議欺老先。", "開門迎客車結轍，而此三士相周旋。", "牙籤插架塵土絕，寶軸出囊瑶玉聯。", "前秦篆籀頗磨滅，中世粉墨仍新鮮。", "咨嗟古人不可見，但覺能者心意專。", "知音自昔貴一遇，千歲相望猶比肩。", "况有清詩紀實事，豪壯入耳如哀絃。", "鄙夫觀書識難字，古文愈野心謂然。", "要當乘興過君所，刮膜一使頭風痊。"]'),
('efc15d48-23b4-4207-9be2-3d674a10f502','楊寺丞書畫','劉攽','宋','宋诗','song-poetry','','[]','楊侯古書數十軸，草隸缺殘猶可讀。',130,'全唐诗/poet.song.35000.json','["楊侯古書數十軸，草隸缺殘猶可讀。", "古書流傳動千歲，書可倣摹古容僞。", "愛君苦心能辨之，等捐千金不爲費。", "世嘗售名不售真，物可見形難見神。", "重令志士一惆悵，念有遺寶隨埃塵。", "東牆西牆畫滿屋，瑟琶小兒理新曲。", "鄙夫長安交遊少，騎馬能來與君熟。", "萬事好惡我自知，不作浮沈爲人更耳目。"]'),
('ff664fac-9de6-4e37-84bd-e71c4c932407','許州寒食','劉攽','宋','宋诗','song-poetry','','[]','灌嬰臺畔路憧憧，寒食追遊喜退公。',64,'全唐诗/poet.song.35000.json','["灌嬰臺畔路憧憧，寒食追遊喜退公。", "堤柳媚烟行細綠，野橋橫水陣殘紅。", "鞦韆冷颺梨花雨，蹴踘高騰燕子風。", "幾處笙歌幾家哭，却愁迴馬夕陽中。"]'),
('c6ce6f33-6373-4370-a0a6-5675268868e3','禁烟遊園','劉攽','宋','宋诗','song-poetry','','[]','寒食風光雨歛塵，病餘寒極强頒春。',64,'全唐诗/poet.song.35000.json','["寒食風光雨歛塵，病餘寒極强頒春。", "傳呼廣陌雙摇旆，乘興名園一柅輪。", "列座賓寮皆俊雅，繞池花木盡奇珍。", "長吟淺醉歸時晚，蠟炬熒煌改火新。"]'),
('d0b89097-cdff-4e19-90a1-321941b36b4f','畫蟹','劉攽','宋','宋诗','song-poetry','','[]','後蚓智不足，捕鼠功豈具。',48,'全唐诗/poet.song.35000.json','["後蚓智不足，捕鼠功豈具。", "一爲丹青錄，能使萬目顧。", "氣凌龜龍蟄，勢經滄海渡。", "微物亦有動，將非逢學誤。"]'),
('91a96b37-a087-45a6-a81a-fdfb58fd119f','蟹','劉攽','宋','宋诗','song-poetry','','[]','稻熟水波老，霜螯已上罾。',48,'全唐诗/poet.song.35000.json','["稻熟水波老，霜螯已上罾。", "味尤堪薦酒，香美最宜橙。", "殻薄胭脂染，膏腴琥珀凝。", "情知烹大鼎，何似莫橫行。"]'),
('b9e80aa1-92b9-4cfa-ad19-e718d8806aac','宜城酒','劉攽','宋','宋诗','song-poetry','','[]','九醖宜城酒，人傳峴首碑。',24,'全唐诗/poet.song.35000.json','["九醖宜城酒，人傳峴首碑。", "古今情不別，更問習家池。"]'),
('0b48f141-5f27-41f5-b057-2d7c2cc6179a','郢州','劉攽','宋','宋诗','song-poetry','','[]','但見蒼山插霄漢，石城古木高崔嵬。',32,'全唐诗/poet.song.35000.json','["但見蒼山插霄漢，石城古木高崔嵬。", "城頭層樓又清絕，尚有遺音名白雪。"]'),
('b254aa15-e10c-4ae9-aea7-19c839ca279f','澄心堂紙','劉攽','宋','宋诗','song-poetry','','[]','當時百金售一幅，澄心堂中千萬軸。',32,'全唐诗/poet.song.35000.json','["當時百金售一幅，澄心堂中千萬軸。", "後人聞名寧復得，就令得之當不識。"]'),
('b15ebb9e-12c0-4aa5-beb8-7531d75c7db5','襄州淳于髡墓','劉攽','宋','宋诗','song-poetry','','[]','微言動相國，大笑絕冠纓。',48,'全唐诗/poet.song.35000.json','["微言動相國，大笑絕冠纓。", "流轉有餘智，滑稽全姓名。", "師儒空稷下，衡蓋盡南荆。", "贅婿不爲辱，旅墳知客卿。"]'),
('91aa1a64-60f5-4c8c-953e-e9a3baafdfa3','別茶嬌','劉攽','宋','宋诗','song-poetry','','[]','畫堂銀燭徹宵明，白玉佳人唱渭城。',32,'全唐诗/poet.song.35000.json','["畫堂銀燭徹宵明，白玉佳人唱渭城。", "唱盡一杯須起舞，關河風月不勝情。"]'),
('d0d888bd-faf9-488a-99c2-4ec0a9fdc22d','荔枝  其一','劉攽','宋','宋诗','song-poetry','','[]','南州積炎德，嘉樹凌冬綠。',168,'全唐诗/poet.song.35000.json','["南州積炎德，嘉樹凌冬綠。", "薰風海上來，丹荔逾夏熟。", "煌煌錦繡林，亭亭翡翠屋。", "鵲頭爛晨霞，天酒瑩寒玉。", "流聲感中華，採掇如不足。", "開元百馬死，漢堠五里促。", "君王玉食間，此薦知不辱。", "迨今糟粕餘，猶足驚凡目。", "憶初成上林，四方會奇木。", "使臣得安榴，天馬來首蓿。", "拔芽自幽遐，托地幸滲漉。", "我欲咎真宰，喟茲限荒服。", "將非名實雄，百果爲羞縮。", "區區化工意，聊爾存衆族。"]'),
('e3afd2ae-f4cb-44cb-8c07-bdc362d560ee','荔枝  其二','劉攽','宋','宋诗','song-poetry','','[]','錦筵火齊砌金柈，五月甘漿破齒寒。',64,'全唐诗/poet.song.35000.json','["錦筵火齊砌金柈，五月甘漿破齒寒。", "南國已隨朱夏熟，北人猶指畫圖看。", "烟嵐不續丹櫻獻，玉座空悲羯鼓殘。", "相見任誇雙蒂美，多情莫唱水晶丸。"]'),
('827aa9f9-5b0b-4ac8-871b-aaf9c4919b30','橄欖','劉攽','宋','宋诗','song-poetry','','[]','南珍富奇異，疇昔頗窮覽。',168,'全唐诗/poet.song.35000.json','["南珍富奇異，疇昔頗窮覽。", "夷荒無書傳，從古陋鉛槧。", "苞封走中土，天序異離坎。", "有香已變衰，有色多黯謭。", "今君此堂上，珍物惟橄欖。", "青膚鏤瓊瑩，翠顆森菡萏。", "若爲幽人貞，久見君子淡。", "甘懷彼包羞，日新此剛敢。", "清泉薦芳茗，臭味獨潛感。", "澡雪清煩酲，滌除瑩玄覽。", "靈均採時菊，西伯嗜昌歜。", "廟鼎實調梅，壯士仍嘗膽。", "由來超俗好，諸絕不言慘。", "殷勤謝凡口，薤白空三噉。"]'),
('bd4e2cd9-a10c-4c4e-855e-2761177f0247','題招提院靜照堂','劉攽','宋','宋诗','song-poetry','','[]','千金買境欲辭喧，長日觀心復照昏。',32,'全唐诗/poet.song.35000.json','["千金買境欲辭喧，長日觀心復照昏。", "多少勝緣從靜起，爲師無意入都門。"]'),
('447496cc-3f23-487a-9f72-fa53316942e6','南湖詩  其一','劉攽','宋','宋诗','song-poetry','','[]','湖波微漲日初長，水面花香柳綠黄。',64,'全唐诗/poet.song.35000.json','["湖波微漲日初長，水面花香柳綠黄。", "沙鳥喧嘲隨笑語，鯈魚驚躍近舟航。", "春心處處迷芳草，醉眼依依亂夕陽。", "信似習池風物好，偷閑剩醉兩三場。"]'),
('c22941ac-4c12-411d-b6ba-285e37463eed','南湖詩  其二','劉攽','宋','宋诗','song-poetry','','[]','一樽芳酒數篇詩，坐待南湖夕景低。',64,'全唐诗/poet.song.35000.json','["一樽芳酒數篇詩，坐待南湖夕景低。", "日照杏花堆火齊，水涵天色湛玻璃。", "靜中魚鳥渾相忘，醉裏風光時易迷。", "還有漁舟澹客興，誰言不似武陵溪。"]'),
('1eeb732c-d7bb-4afd-8e3b-d1ebe70d88eb','潁水作寄陳州諸故人','劉攽','宋','宋诗','song-poetry','','[]','不知潁水清如此，欲比蓬萊似是非。',64,'全唐诗/poet.song.35000.json','["不知潁水清如此，欲比蓬萊似是非。", "察見淵魚寧有意，往來鷗鳥已忘機。", "濟川便樂風波息，洗耳都疑世事違。", "甚悔衡門臨沁水，還思冠者試春衣。"]'),
('a39921d3-1602-414c-935b-361f6ca5dea5','咏列子','劉攽','宋','宋诗','song-poetry','','[]','禦寇卧鄭都，子陽歸之粟。',72,'全唐诗/poet.song.35000.json','["禦寇卧鄭都，子陽歸之粟。", "固辭得無受，妻子怨窘束。", "君非自知我，人事故反覆。", "俛仰未及終，類傌首邦族。", "始知至人心，避榮乃避辱。", "如何當路子，擾擾事干祿。"]'),
('fc84feec-5c60-471b-9de6-b3fa32dbf4df','大安病酒留半日王守復來招不往送酒解酲因小飲江月館','劉攽','宋','宋诗','song-poetry','','[]','江驛春酲半日留，更煩送酒爲扶頭。',32,'全唐诗/poet.song.35000.json','["江驛春酲半日留，更煩送酒爲扶頭。", "柳花漠漠嘉陵岸，別是天涯一段愁。"]'),
('65e845c3-4ba7-44a3-882c-065b62532888','還館  其一','劉攽','宋','宋诗','song-poetry','','[]','步向端門足力遲，仰瞻雙闕隔褵褷。',32,'全唐诗/poet.song.35000.json','["步向端門足力遲，仰瞻雙闕隔褵褷。", "三年江海都如夢，老態今朝始自知。"]'),
('41c32728-7c5d-477a-af4a-71139ee3093f','還館  其二','劉攽','宋','宋诗','song-poetry','','[]','下馬呼人問直廬，歸牆因讀舊時書。',32,'全唐诗/poet.song.35000.json','["下馬呼人問直廬，歸牆因讀舊時書。", "黄花綠葉庭槐影，噪雀鳴蟬宛自初。"]'),
('3ddfc04c-bbfc-40fb-82b9-5ea3e0ca0c1f','次韵王四館宿  其一','劉攽','宋','宋诗','song-poetry','','[]','雪殘梧竹夜猶寒，春入林花露已團。',64,'全唐诗/poet.song.35000.json','["雪殘梧竹夜猶寒，春入林花露已團。", "絕境自宜仁者靜，寤歌非爲碩人寬。", "不眠紅燭停俄頃，刻意新書計若干。", "等是前賢遊集地，似君尤更覺才難。"]'),
('473098be-d98c-4cc7-bd6b-357761de9f6b','次韵王四館宿  其二','劉攽','宋','宋诗','song-poetry','','[]','蓬萊宮闕冠雲霓，月出丹淵日墮西。',64,'全唐诗/poet.song.35000.json','["蓬萊宮闕冠雲霓，月出丹淵日墮西。", "和暖時花元有信，黄昏歸翼自無迷。", "讀書難字存雌蜺，落筆雄辭在碧鷄。", "五十衰年融過二，强顔何計可思齊。"]'),
('81e06c40-7a58-413d-a144-4f3594edbf29','次韵王四館宿  其三','劉攽','宋','宋诗','song-poetry','','[]','天星出屈勢闌干，五夜傳呼禁漏殘。',64,'全唐诗/poet.song.35000.json','["天星出屈勢闌干，五夜傳呼禁漏殘。", "虎豹深沉九關遠，鷦鷯栖息一枝安。", "病親黄卷憐燈闇，老厭青綾怯歲寒。", "長有江湖未歸夢，更將衰白鏡中看。"]'),
('299e5bb5-c188-4367-aae8-032fba2ed460','次韵王四館宿  其四','劉攽','宋','宋诗','song-poetry','','[]','月白天虛星斗橫，夜深高閣勢崢嶸。',32,'全唐诗/poet.song.35000.json','["月白天虛星斗橫，夜深高閣勢崢嶸。", "怪來耳冷人聲絕，會是齋居近太清。"]'),
('7be7735b-f00f-4410-abe4-5506e183ccd1','初秋館中呈諸公','劉攽','宋','宋诗','song-poetry','','[]','掖垣星宿上清居，金馬文章次石渠。',64,'全唐诗/poet.song.35000.json','["掖垣星宿上清居，金馬文章次石渠。", "雨定楓槐含秀爽，秋還樓閣長空虛。", "上知景伯無人事，恩許黄香未見書。", "不奈客嘲聊自解，下流仍復愧應璩。"]'),
('4cff1e44-427a-4b30-9b98-f8dd1864083b','題平山馬鋪','劉攽','宋','宋诗','song-poetry','','[]','長亭前望勢崔嵬，地坼東南宇宙開。',32,'全唐诗/poet.song.35000.json','["長亭前望勢崔嵬，地坼東南宇宙開。", "韋杜去天真五尺，行人新自日邊來。"]'),
('44a96dca-44d8-41f9-aa6e-17332aabaaa2','燈夕','劉攽','宋','宋诗','song-poetry','','[]','燒燈陶永夜，擊鼓勸沽酒。',48,'全唐诗/poet.song.35000.json','["燒燈陶永夜，擊鼓勸沽酒。", "清月不作霜，微風乍摇柳。", "忽忽車轉轂，戢戢人舉首。", "歡樂聊及時，與誰論薄厚。"]'),
('8c805fbb-950c-4d7c-b090-07a8db16511c','次韵和王舍人燈夕見寄','劉攽','宋','宋诗','song-poetry','','[]','南陌東城樂賞同，翠華雕輦度香風。',64,'全唐诗/poet.song.35000.json','["南陌東城樂賞同，翠華雕輦度香風。", "春催火樹無窮外，天壓歌聲不盡中。", "侍宴君歸青瑣閣，倦遊身作白髯翁。", "憑將酒客鴟夷頌，並謝張松與孟公。"]'),
('61e7d60c-2aa4-4fe9-a880-7566bcc8fe20','燈夕陳大夫來會張承議以病不出有詩贈陳次韵和之','劉攽','宋','宋诗','song-poetry','','[]','千燈光影徹春宵，紅日明霞晃綺寮。',64,'全唐诗/poet.song.35000.json','["千燈光影徹春宵，紅日明霞晃綺寮。", "上客歡娛得驚坐，佳人歌笑敵藍橋。", "雪花带雨塵都埽，寒色兼風酒易消。", "一去章街盡眉嫵，臂圍猶怯月邊朝。"]'),
('43bbd216-15a6-42e7-bb63-23a9825caa92','燈夕寄呈張學士','劉攽','宋','宋诗','song-poetry','','[]','東風一雨解萌芽，暖景重城有萬家。',64,'全唐诗/poet.song.35000.json','["東風一雨解萌芽，暖景重城有萬家。", "霽後燈光猶妬月，春遲火樹却催花。", "數聲水調矜遺俗，十里珠簾勝館娃。", "璧府謫仙歸未得，會將騎鶴向人夸。"]'),
('c79faa05-d4d8-4d1f-9c1e-138750ed9cf8','三峽橋','劉攽','宋','宋诗','song-poetry','','[]','三峽橋西路不通，水深石怪自蟠龍。',32,'全唐诗/poet.song.35000.json','["三峽橋西路不通，水深石怪自蟠龍。", "一聞馬足皆驚起，倏忽雲遮五老峰。"]'),
('82d09316-d657-4b07-a5ef-be0c29dad7ea','寄荆公','劉攽','宋','宋诗','song-poetry','','[]','青苗助役兩妨農，天下嗷嗷怨相公。',32,'全唐诗/poet.song.35000.json','["青苗助役兩妨農，天下嗷嗷怨相公。", "惟有蝗蟲偏感德，又隨台旆過江東。"]'),
