('ff6defbc-91b0-4f0e-b8d8-808a97c96e5e','漁父二首  其一','李觀','宋','宋诗','song-poetry','','[]','八月九月蘆花飛，南溪老人垂釣歸。',64,'全唐诗/poet.song.35000.json','["八月九月蘆花飛，南溪老人垂釣歸。", "秋山入簾翠滴滴，野艇倚檻雲依依。", "却把魚竿尋小徑，閒梳鶴髮對斜暉。", "翻嫌四皓曾多事，出爲儲王定是非。"]'),
('1224ca09-b51e-4eaf-94c4-e6f1f0da2a65','漁父二首  其二','李觀','宋','宋诗','song-poetry','','[]','村寺鐘聲渡遠灘，半輪殘月落前山。',32,'全唐诗/poet.song.35000.json','["村寺鐘聲渡遠灘，半輪殘月落前山。", "徐徐撥棹却歸灣，浪疊朝霞錦繡翻。"]'),
('5b68c985-a8ee-4200-8cad-90b6c725d58d','震山巖','李觀','宋','宋诗','song-poetry','','[]','鮮日媚晴靄，泉石閑融融。',72,'全唐诗/poet.song.35000.json','["鮮日媚晴靄，泉石閑融融。", "酒味醴於春，挹翠迎春風。", "坐映珪壁秀，六合開情悰。", "昔人袖全璞，傲睨追冥鴻。", "里閭味前塵，慨慕滋無窮。", "蓄藴非一身，出處固異同。"]'),
('7cabfe53-a303-412d-bcac-81cc139c6693','東湖','李觀','宋','宋诗','song-poetry','','[]','萬象城東雅入詩，半湖雲靄捲殘暉。',64,'全唐诗/poet.song.35000.json','["萬象城東雅入詩，半湖雲靄捲殘暉。", "老龍惜雨慵離蟄，迷鷺逢人慣不飛。", "岸僻自宜安釣石，水清誰礙濯塵衣。", "使君公退便遊此，却恐吾皇急詔歸。"]'),
('222019b4-5df6-499c-82a9-424de2eb8482','題翠微亭','李觀','宋','宋诗','song-poetry','','[]','竹根穿石嘴，松影入泉心。',24,'全唐诗/poet.song.35000.json','["竹根穿石嘴，松影入泉心。", "不致玄玄處，白雲徒自深。"]'),
('3696eda9-36b3-4baa-81b2-d1af469099ec','出宰清江省親秀水','李觀','宋','宋诗','song-poetry','','[]','天闕抵清江，萍泛七千里。',60,'全唐诗/poet.song.35000.json','["天闕抵清江，萍泛七千里。", "心目駐庭闈，恍如尋尺耳。", "河伯念微衷，風師薦嘉祉。", "澄瀾協順飆，天際堪屈指。", "歸歟膝下歡，奚獨老萊子。"]'),
('c923e76e-cf6d-4bf4-8466-e861e0e77e42','化成巖','李觀','宋','宋诗','song-poetry','','[]','交臂尋幽歲已殘，瘦藤枯石重躋攀。',64,'全唐诗/poet.song.35000.json','["交臂尋幽歲已殘，瘦藤枯石重躋攀。", "忽逢陰洞龍開室，下瞰寒溪玉繞山。", "猿鳥窺簾如舊識，藤蘿引徑入蹊閒。", "遊人自向紅塵去，日莫老僧催閉關。"]'),
('749ff550-9155-4d98-89f3-0410c6e6564d','句','李觀','宋','宋诗','song-poetry','','[]','養拙藏愚春復春。',8,'全唐诗/poet.song.35000.json','["養拙藏愚春復春。"]'),
('68fcd49e-6141-4470-97bb-f29812bd5fbf','覆驗餘姚道中','王存','宋','宋诗','song-poetry','','[]','一夫死非命，滌驗更兩吏。',72,'全唐诗/poet.song.35000.json','["一夫死非命，滌驗更兩吏。", "一囚坐法誅，三覆與衆棄。", "去年交阯敗，殺戮無賤貴。", "江淮屢歲眚，積殍溝壑穢。", "聖人於赤子，愛重若彼至。", "謹小以遺大，誰其原帝意。"]'),
('fd2098e8-f27e-46bf-9551-02704eb5c667','送程給事知越州','王存','宋','宋诗','song-poetry','','[]','集仙詞職瑣闈郎，曾領共工使出疆。',64,'全唐诗/poet.song.35000.json','["集仙詞職瑣闈郎，曾領共工使出疆。", "萬里初還遼海節，一麾俄綰會稽章。", "金環賜带饒新貴，熊軾褰帷過故鄉。", "政事有餘詩筆健，卧龍山直鑑湖光。"]'),
('0d4e6dcc-b5f8-4593-9e45-db078d791e08','子陵釣臺','王存','宋','宋诗','song-poetry','','[]','嚴公英魄去何之，江上空餘舊釣磯。',64,'全唐诗/poet.song.35000.json','["嚴公英魄去何之，江上空餘舊釣磯。", "古木蒼煙鸜鵒噪，清波白石鷺鷥飛。", "山中秋色香粳熟，壠下朝寒赤鯉肥。", "何事夷齊恥周粟，一生憔悴首陽薇。"]'),
('e8118330-1b67-4fe7-af1e-31606a27a346','史院席上奉和首相吳公原韵','王存','宋','宋诗','song-poetry','','[]','上聖思論著，前言摭緒餘。',48,'全唐诗/poet.song.35000.json','["上聖思論著，前言摭緒餘。", "瓊筵初賜醴，石室載紬書。", "徽範貽來者，成功念昔歟。", "欲知開局盛，門擁相君車。"]'),
('31fa7728-9dae-4c37-a099-b69952990ceb','送刁景純歸京口','王存','宋','宋诗','song-poetry','','[]','因公東還輒悲咤，重厚士風須長者。',32,'全唐诗/poet.song.35000.json','["因公東還輒悲咤，重厚士風須長者。", "少年流輩輕老人，去矣唐山舊林下。"]'),
('5c6c5e60-469e-4169-ade3-dac4979b9724','登北固山','王存','宋','宋诗','song-poetry','','[]','晚登北固頂，俛視南徐城。',48,'全唐诗/poet.song.35000.json','["晚登北固頂，俛視南徐城。", "廢壘何茫茫，山川迥縱橫。", "千載競誰有，六朝空戰爭。", "豪氣不可問，古墳人正耕。"]'),
('c9f32ebd-a21e-48ba-9687-2a970063e638','遊焦山','王存','宋','宋诗','song-poetry','','[]','連山擁滄江，峭絕視茲鮮。',48,'全唐诗/poet.song.35000.json','["連山擁滄江，峭絕視茲鮮。", "由來一氣結，殊不麗衆巘。", "林深鳥聲悅，境靜人自遠。", "方吾抱幽介，對此萬慮遣。"]'),
('f512db48-10bb-435a-a63b-9f04ef627f7b','靜照堂','王存','宋','宋诗','song-poetry','','[]','曾過槜李古禪關，十五年來夢想閒。',64,'全唐诗/poet.song.35000.json','["曾過槜李古禪關，十五年來夢想閒。", "聞說新堂增勝概，又憐遊客變衰顔。", "香檀印篆銷晨暮，題墨籠紗記往還。", "能了一心隨處靜，何須辛苦遠人寰。"]'),
('7b186833-dcf5-4cda-916d-cb6633a8da27','過丹陽舊居','王存','宋','宋诗','song-poetry','','[]','漂泊經故園，繫舟款柴扉。',108,'全唐诗/poet.song.35000.json','["漂泊經故園，繫舟款柴扉。", "破屋他人居，昔鄰今或非。", "父老迎我飲，祝我晝錦衣。", "我謝父老言，朴拙非所祈。", "一官走塵土，實迫寒與饑。", "去鄉未幾載，頗覺侶儔稀。", "人事已可嗟，况當白首歸。", "泚泚練塘水，綠楊蔭漁磯。", "有田尚可耕，誓將父老依。"]'),
('a183571e-7d3d-4434-9ed0-749af3e72e92','歸京口','王存','宋','宋诗','song-poetry','','[]','倦宦歸來故國春，北樓千尺絕飛塵。',64,'全唐诗/poet.song.35000.json','["倦宦歸來故國春，北樓千尺絕飛塵。", "江山雄偉增人氣，城壁蕭條類此身。", "眼底交遊隨物老，樽前歌舞逐時新。", "十年舊事無人問，目送斜陽下廣津。"]'),
('3345e903-e08d-48ec-a7f6-fe1ace4b4c2f','却客致假山石','王存','宋','宋诗','song-poetry','','[]','乞得林官就道閒，誅茅結宇即成灣。',32,'全唐诗/poet.song.36000.json','["乞得林官就道閒，誅茅結宇即成灣。", "閉門自有林巒秀，不用辛勤作假山。"]'),
('f46148cb-2137-4c07-b023-190667942624','句  其一','王存','宋','宋诗','song-poetry','','[]','病鸞方振翼，饑隼乍離韝。',12,'全唐诗/poet.song.36000.json','["病鸞方振翼，饑隼乍離韝。"]'),
('53920f0e-4f70-4fcd-9860-7ad8d6a5ff5b','句  其二','王存','宋','宋诗','song-poetry','','[]','珠韉錫御恩猶在，玉輦親扶事已空。',16,'全唐诗/poet.song.36000.json','["珠韉錫御恩猶在，玉輦親扶事已空。"]'),
('b9fcba25-91ab-4005-9253-d8138eb2fedd','句  其三','王存','宋','宋诗','song-poetry','','[]','二載京峴居，過從不獲屢。',12,'全唐诗/poet.song.36000.json','["二載京峴居，過從不獲屢。"]'),
('f61ff0e0-bba1-4097-b658-756eea430671','句  其四','王存','宋','宋诗','song-poetry','','[]','族居自買百閒屋，月賜官糜六萬錢。',16,'全唐诗/poet.song.36000.json','["族居自買百閒屋，月賜官糜六萬錢。"]'),
('79b67f43-5381-4b7c-8997-978db9274fc9','踞湖山六題 踞湖山','馬雲','宋','宋诗','song-poetry','','["\u592a\u6e56"]','山臨太湖上，寺隠青蘿間。',72,'全唐诗/poet.song.36000.json','["山臨太湖上，寺隠青蘿間。", "五塢洞壑邃，衆峰屏障環。", "濃嵐面光彩，驚波背潺湲。", "雲歸定僧寂，月伴樵夫還。", "林墅掩蒙密，級磴容躋攀。", "錢氏建圭社，此地爲家山。"]'),
('a0d143f7-21e1-4928-ba75-d3583d6c3a93','踞湖山六題 芳桂塢','馬雲','宋','宋诗','song-poetry','','[]','森森芳桂樹，團團削青玉。',72,'全唐诗/poet.song.36000.json','["森森芳桂樹，團團削青玉。", "春花飛澗戶，秋實墜岩曲。", "霜條封翠紫，風葉摇香綠。", "下有幽棲人，結芳避世俗。", "學仙讀丹經，好道探藥籙。", "植根滿群峰，不使樵夫觸。"]'),
('fe2ad5fc-7efa-4f9b-a83f-24291874bed0','踞湖山六題 飛泉塢','馬雲','宋','宋诗','song-poetry','','[]','高崖落飛泉，深源味冷冽。',72,'全唐诗/poet.song.36000.json','["高崖落飛泉，深源味冷冽。", "雲津留玉乳，石髓澄金屑。", "淙淙危磴響，滴滴蒼蘚缺。", "濺沫灑明珠，滿澗融寒雪。", "岩夫就潄飲，姬子臨浣潔。", "不獨愈痼疾，自可清內熱。"]'),
('15d80326-64d2-4432-a9e4-c96912d8d7fa','踞湖山六題 修竹塢','馬雲','宋','宋诗','song-poetry','','[]','檀欒遍岩川，幽谷氣象鮮。',72,'全唐诗/poet.song.36000.json','["檀欒遍岩川，幽谷氣象鮮。", "風玉自宮徵，秋籟成管絃。", "夕靄起碧霧，晨曦生綠煙。", "花繁紫鳳飽，質勁蒼虬攣。", "藤蘿交密蔭，仰不見雲天。", "欲訪桃源路，塢塢疑相連。"]'),
('2355f721-437b-41b4-87ce-8dc8915ad4ac','踞湖山六題 丹霞塢','馬雲','宋','宋诗','song-poetry','','[]','東澗岩谷秀，粲然金碧麗。',72,'全唐诗/poet.song.36000.json','["東澗岩谷秀，粲然金碧麗。", "亙野丹氣明，向曙霏烟霽。", "磴瀉紅玉泉，林紆赤鳳髻。", "日出諸峰上，月皎半天際。", "幽谷紓絳繒，層崖榮錦罽。", "羨此山居人，蕭然遠塵世。"]'),
('39929517-7a62-425b-ab64-ac33f9d8e1f0','踞湖山六題 白雲塢','馬雲','宋','宋诗','song-poetry','','[]','君尋白雲塢，最近林澗西。',72,'全唐诗/poet.song.36000.json','["君尋白雲塢，最近林澗西。", "永日抱幽石，因風度清溪。", "炎隨夏景變，凉高秋氣凄。", "素靄生巘崿，練光带虹霓。", "潤澤施天下，還返故山棲。", "深惟賢士志，出處可與齊。"]'),
('0e6f940e-ac72-45bd-a516-f5eda2f25636','訪踞湖山人仇君隠居','馬雲','宋','宋诗','song-poetry','','[]','雞犬眠雲白日空，暮春花木滿川紅。',64,'全唐诗/poet.song.36000.json','["雞犬眠雲白日空，暮春花木滿川紅。", "茶甌香沸松林火，藥杵聲清石澗風。", "玉帛未聞招處士，神仙今喜識臺翁。", "夕陽半局殘棋在，醉倚岩邊紫桂叢。"]'),
('b0dcae4d-f289-419a-8f41-2c50009aeb88','重建羊侯祠和王原叔句','馬雲','宋','宋诗','song-poetry','','[]','漢水舒舒山崇崇，岧然峴首稱清雄。',320,'全唐诗/poet.song.36000.json','["漢水舒舒山崇崇，岧然峴首稱清雄。", "南方强吳恃割據，選命儒將登元戎。", "太康以來千餘載，荆州遺愛思羊公。", "江山襟带號形勝，藉此因成輔晉功。", "公謂高賢事迹異，視之閑暇無匆匆。", "測知當日登臨意，景物亦與今朝同。", "新就峰巔作亭舍，面勢豁若凌烟虹。", "蒼蒼雲木望不盡，浩蕩古意深何窮。", "盤回小徑至釣石，俯視凝碧相連通。", "叢篁森束林蓊鬰，又從其下興祠宮。", "迅湍急瀨鳴湱湱，濃嵐翠靄霏濛濛。", "晦晴氣象隨變易，朝昏萬狀殊初終。", "閣老分符二千石，旟竿刻隼車畫熊。", "管內民租絕逋負，里社歌鼓歡年豐。", "府門晝扃官事退，時引賓佐嬉其中。", "崖條嶺蔓雜丹白，澗花滿眼羅青紅。", "磴道迤邐陟縈屈，飄若巾屨騰秋空。", "豈獨遊觀樂閑燕，圖樹佳政希前風。", "經由粗得究本末，强顔模寫慚非工。", "音辭鄙俚雖一唱，下詞寒苦無怡融。"]'),
('d71adc40-5724-4194-a1fe-93a18d985df2','登仙奕山','盧侗','宋','宋诗','song-poetry','','[]','畏對青山老一秋，逢春又向碧巖遊。',32,'全唐诗/poet.song.36000.json','["畏對青山老一秋，逢春又向碧巖遊。", "憑空爲問蓬萊客，何物能消萬古愁。"]'),
('ad0bffc1-c279-4c53-8750-12bedfbb60fb','西龍潭','方子容','宋','宋诗','song-poetry','','[]','風雲未借且潛藏，峰上誰歟起道場。',64,'全唐诗/poet.song.36000.json','["風雲未借且潛藏，峰上誰歟起道場。", "禪子坐聽金竺語，老人拜獻玉函方。", "法輪廣大乾坤轉，巖洞幽深日月長。", "千古不愁爲佛護，夜潭勤禮玉毫光。"]'),
('04aa4550-376a-4a83-bfde-756825d7e830','偕循守周彥質過蘇東坡白鶴新居和東坡韵','方子容','宋','宋诗','song-poetry','','[]','豹隠南山鶴在陰，浮羅一望白雲深。',64,'全唐诗/poet.song.36000.json','["豹隠南山鶴在陰，浮羅一望白雲深。", "巧工且縮居旁手，烈士誰知負壯心。", "嗟我抗塵仍走路，羨君叩寂且求音。", "如何東嶺神仙境，肯約衰翁數訪臨。"]'),
('457bc50c-3721-43ef-8b83-21ff470c6613','再訪東坡用前韵','方子容','宋','宋诗','song-poetry','','[]','東嶺新成桃李陰，春光日日向人深。',64,'全唐诗/poet.song.36000.json','["東嶺新成桃李陰，春光日日向人深。", "遥瞻廣厦驚凡目，自是中台巧運心。", "輪奐欲形張老頌，調歌先聽伯牙音。", "料公不負南堂約，應許衰翁領客臨。"]'),
('bece0b61-008f-4950-8e56-2f239fcecdac','八咏警戒  其一','吳處厚','宋','宋诗','song-poetry','','[]','慎言渾不畏，言出患常隨。',48,'全唐诗/poet.song.36000.json','["慎言渾不畏，言出患常隨。", "須信機樞發，難容駟馬追。", "三緘事可見，兩舌業當知。", "口是起羞本，願君且再思。"]'),
('4e4e627a-6917-405f-9f22-083a46177711','八咏警戒  其二','吳處厚','宋','宋诗','song-poetry','','[]','忍事有何妨，勿令心火揚。',48,'全唐诗/poet.song.36000.json','["忍事有何妨，勿令心火揚。", "火揚猶可滅，心忿固多傷。", "堪嘆波羅蜜，可憐歌利王。", "從心更從刃，字意好端詳。"]'),
('d04fd242-d970-4d96-88e7-302c8700be3e','八咏警戒  其三','吳處厚','宋','宋诗','song-poetry','','[]','國法須遵守，金科盡詔條。',48,'全唐诗/poet.song.36000.json','["國法須遵守，金科盡詔條。", "一毫如有犯，三尺不相饒。", "豈肯容奸黠，何須恃貴驕。", "自然逢吉慶，神理亦昭昭。"]'),
('fca0f7ef-4075-487c-a8f3-65c0df67ab14','八咏警戒  其四','吳處厚','宋','宋诗','song-poetry','','[]','人非莫舉揚，萬事且包荒。',48,'全唐诗/poet.song.36000.json','["人非莫舉揚，萬事且包荒。", "殿上便猶掩，車中吐不妨。", "在他誠所短，於己有何長。", "須是常規檢，回頭自忖量。"]'),
('eb1b4cb6-9c64-4271-a8a6-ecae6905c7fd','八咏警戒  其五','吳處厚','宋','宋诗','song-poetry','','[]','無私仍克己，克己又無私。',48,'全唐诗/poet.song.36000.json','["無私仍克己，克己又無私。", "一事兼修飾，終身在省思。", "公清多斂怨，高亢易招危。", "更切循卑退，方應履坦夷。"]'),
('3db502c0-87d1-4935-a78e-6392706a714a','八咏警戒  其六','吳處厚','宋','宋诗','song-poetry','','[]','直道更和光，雙修譽乃彰。',48,'全唐诗/poet.song.36000.json','["直道更和光，雙修譽乃彰。", "直須和輔助，和頼直交相。", "恃直終多訐，偏和又少剛。", "能和又能直，行己自芬芳。"]'),
('63d8ef88-a9d0-4334-a4bc-be00dd3c49a3','八咏警戒  其七','吳處厚','宋','宋诗','song-poetry','','[]','此箇如端的，除非六句修。',48,'全唐诗/poet.song.36000.json','["此箇如端的，除非六句修。", "永爲几杖誡，更遺子孫謀。", "本立方生道，農勤乃有秋。", "茲詩雖淺近，至理可推求。"]'),
('5a59f5e8-8852-4257-ae4a-ae0f56a2a26f','八咏警戒  其八','吳處厚','宋','宋诗','song-poetry','','[]','天應降吉祥，天理本茫茫。',48,'全唐诗/poet.song.36000.json','["天應降吉祥，天理本茫茫。", "舒慘雖無定，榮枯却有常。", "益謙尤效驗，福善更昭彰。", "籠絡無疏漏，恢恢網四張。"]'),
('d067cda0-91b0-4651-a2aa-0107c0599dcb','九江琵琶亭','吳處厚','宋','宋诗','song-poetry','','[]','夜泊潯陽宿酒樓，琵琶亭畔荻花秋。',32,'全唐诗/poet.song.36000.json','["夜泊潯陽宿酒樓，琵琶亭畔荻花秋。", "雲沉鳥沒事已往，月白風清江自流。"]'),
('5554fc52-7f40-478e-9ee3-706f7fb2aa5f','送客西陵','吳處厚','宋','宋诗','song-poetry','','[]','若邪溪畔醉秋風，獵獵船旗照水紅。',32,'全唐诗/poet.song.36000.json','["若邪溪畔醉秋風，獵獵船旗照水紅。", "後夜錢塘酒樓上，夢魂應繞浙江東。"]'),
('328bba9a-2157-4ff6-9e14-2320790bb57e','戲王安國','吳處厚','宋','宋诗','song-poetry','','[]','飛卿昔號溫鍾夔，思道通俛還魁肥。',64,'全唐诗/poet.song.36000.json','["飛卿昔號溫鍾夔，思道通俛還魁肥。", "江淹善啖筆五色，庾信能文腰十圍。", "只知外貌乏粉澤，誰料滿腹填珠璣。", "相逢把酒洛陽社，不管淋漓身上衣。"]'),
('f0c78b77-b612-45c0-97d5-db205e588f3f','偈一首','吳處厚','宋','宋诗','song-poetry','','[]','是身如泡幻，盡非真實相。',48,'全唐诗/poet.song.36000.json','["是身如泡幻，盡非真實相。", "况茲紙上影，妄外更生妄。", "到岸不須船，無風休起浪。", "唯當清靜觀，妙法了無象。"]'),
('e8769162-34df-4687-a956-26edeb83c427','自諸暨抵剡四首  其一','吳處厚','宋','宋诗','song-poetry','','[]','莫嘆塵泥汩，且圖山水遊。',48,'全唐诗/poet.song.36000.json','["莫嘆塵泥汩，且圖山水遊。", "幾峰天姥翠，一舸剡溪秋。", "不見戴安道，有懷王子猷。", "西風無限意，盡屬釣魚舟。"]'),
('983f0366-2827-4740-848a-b2d7b14b1747','自諸暨抵剡四首  其二','吳處厚','宋','宋诗','song-poetry','','[]','夷猶雙槳去，莫不辨東西。',48,'全唐诗/poet.song.36000.json','["夷猶雙槳去，莫不辨東西。", "夕照偏依樹，秋光半落溪。", "風高一雁小，雲薄四天低。", "莽蕩孤帆卸，水村楊柳堤。"]'),
('13773e25-eb80-4cb6-9eb1-f02492e48613','自諸暨抵剡四首  其三','吳處厚','宋','宋诗','song-poetry','','[]','秋渚涵空碧，秋山刷眼青。',48,'全唐诗/poet.song.36000.json','["秋渚涵空碧，秋山刷眼青。", "排頭煙樹老，撲面水風腥。", "上瀨復下瀨，長亭仍短亭。", "夜船明月好，客夢滿流螢。"]'),
('bf40b584-39b8-4e11-9974-dd713a22b852','自諸暨抵剡四首  其四','吳處厚','宋','宋诗','song-poetry','','[]','出得雲門路，風凄日夕曛。',48,'全唐诗/poet.song.36000.json','["出得雲門路，風凄日夕曛。", "船撐鑒湖月，路接沃洲雲。", "山色周遭見，溪流屈曲分。", "一觴還一咏，誰似右將軍。"]'),
('b2742372-5e34-4784-99c0-bf45ef43bbef','遊沃洲山真封院','吳處厚','宋','宋诗','song-poetry','','[]','幼年曾讀樂天碑，及壯亦覽高僧傳。',384,'全唐诗/poet.song.36000.json','["幼年曾讀樂天碑，及壯亦覽高僧傳。", "聞有沃洲風景佳，脚未能到心空羨。", "近至新昌披縣圖，此山乃在吾廐圈。", "想像時時掛夢魂，欲一遊之念無便。", "夜來人報天姥雪，今日趁晴初出縣。", "酸風瞥瞥吹我鬚，寒氣稜稜刮人面。", "半膝短衫翻以輕，獨脚小轎快而健。", "不知路入幽澗長，但覺山隨白雲轉。", "靠昏投宿梅林村，侵卯便過真封院。", "新霜滑澾行李難，一步一拄一回眩。", "養馬坡前秋草黄，駿骨已埋無復見。", "放鶴峰頭樹影孤，鶴不來歸雲漫漫。", "入門觸物皆荒凉，塵几蠹經三五卷。", "餓鴉叫噪繞生臺，野雀毰毸集寒殿。", "老杉千尺惟空腔，猶有枯藤半縈纏。", "憶昔江左全盛時，十有八人皆俊彥。", "或吟或嘯或遨嬉，不覺回頭垂纓弁。", "林泉耽味久成癖，魚鳥留連老忘倦。", "前有道猷後法潛，錫杖卓泉堅志願。", "晚則道林經構之，左右前後遂完繕。", "煙霞一窟直幾錢，買醭商量價何賤。", "聚徒數百日高談，供有香花齋有麵。", "歲時浸久山浸荒，種粟燒畬耕掘遍。", "茂林髠𩯝無幾存，莽蕩周回空一片。"]'),
('19a7acc5-6e99-417e-9477-76d3dadd633b','遊五泄山','吳處厚','宋','宋诗','song-poetry','','[]','煙霞一塢兩山源，石壁寒垂瀑布泉。',64,'全唐诗/poet.song.36000.json','["煙霞一塢兩山源，石壁寒垂瀑布泉。", "人事是非空繚繞，水聲今古自潺湲。", "月留吟客眠寒榻，風送樵翁下翠巔。", "檀篆未消鑪火燠，夜長人靜好談禪。"]'),
('cbfa04a7-fcc3-4d61-b2fd-1e8490cffc5e','留題雲門山雍熙院','吳處厚','宋','宋诗','song-poetry','','[]','三寺峙若鼎，四山合如環。',48,'全唐诗/poet.song.36000.json','["三寺峙若鼎，四山合如環。", "偷携野人杖，默叩禪翁關。", "草樹冬不老，雲煙秋更閑。", "飄飄物外興，又逐歸禽還。"]'),
('837b99fb-415a-46be-a53b-0bfc12622144','題王正叔㶏景亭','吳處厚','宋','宋诗','song-poetry','','[]','亂鶑啼處柳飛花，拍拍春流漲曉沙。',32,'全唐诗/poet.song.36000.json','["亂鶑啼處柳飛花，拍拍春流漲曉沙。", "正是江南梅子熟，年年離恨寄天涯。"]'),
('9c463a43-8f32-41f5-adee-7ff37e77234f','玉京洞','吳處厚','宋','宋诗','song-poetry','','[]','秉燭携筇步步前，玉京迢遞訪神仙。',32,'全唐诗/poet.song.36000.json','["秉燭携筇步步前，玉京迢遞訪神仙。", "四時自有壺中景，一罅都迷物外天。"]'),
('be978f0a-1c5a-48f2-b61c-a9de23f06177','郎官湖','吳處厚','宋','宋诗','song-poetry','','[]','郎官湖上郎官遊，只教閑客生閑愁。',32,'全唐诗/poet.song.36000.json','["郎官湖上郎官遊，只教閑客生閑愁。", "烟波蕩漾四五頃，風月凄凉三百秋。"]'),
('e4e0545f-ad63-47c9-a87d-044dd2bc07eb','秋興亭懷古','吳處厚','宋','宋诗','song-poetry','','[]','漢沔當年控上游，孫權曾此困曹劉。',32,'全唐诗/poet.song.36000.json','["漢沔當年控上游，孫權曾此困曹劉。", "三分霸業千張紙，萬古斜陽一釣舟。"]'),
('e093ab79-e358-413a-8376-e455cdfe737a','句  其一','吳處厚','宋','宋诗','song-poetry','','[]','會景亭高石作層。',8,'全唐诗/poet.song.36000.json','["會景亭高石作層。"]'),
('28d7bff8-cc75-4e0d-bdcd-e7b1445e31c2','句  其二','吳處厚','宋','宋诗','song-poetry','','[]','江漢滔滔一向東，暮江澄湛夕陽紅。',16,'全唐诗/poet.song.36000.json','["江漢滔滔一向東，暮江澄湛夕陽紅。"]'),
('fe138a12-1102-46ec-b989-dd65292a9c43','句  其三','吳處厚','宋','宋诗','song-poetry','','[]','雲共去時天杳杳，雁連來處水茫茫。',16,'全唐诗/poet.song.36000.json','["雲共去時天杳杳，雁連來處水茫茫。"]'),
('2e79b495-6aea-46aa-8735-535146e96b64','遊峨雜咏  其一','白約','宋','宋诗','song-poetry','','[]','祥光非實相，靈異只虛誇。',48,'全唐诗/poet.song.36000.json','["祥光非實相，靈異只虛誇。", "巖靜長留雪，山寒故放花。", "雲川千萬里，燈火兩三家。", "荷篠人何處，悠悠步落霞。"]'),
('9d7ae354-bb9d-42b7-aa55-8caf33a7c772','遊峨雜咏  其二','白約','宋','宋诗','song-poetry','','[]','樹倒因成路，林開忽見村。',48,'全唐诗/poet.song.36000.json','["樹倒因成路，林開忽見村。", "鳥音傳木杪，梵語出雲根。", "雪色連春夏，風聲接曉昏。", "徘徊幽興極，回首謝煩喧。"]'),
('27ccda8b-c27c-4c5f-9be8-69ea321f3d15','遊峨雜咏  其三','白約','宋','宋诗','song-poetry','','[]','文公太華遊，惆悵無與共。',48,'全唐诗/poet.song.36000.json','["文公太華遊，惆悵無與共。", "翁從二三子，泉石恣披弄。", "草木被芳鮮，山巖落飛動。", "朝市足紛華，不入幽人夢。"]'),
('d519ecf7-0a1c-453e-8338-9a2e2c7d0720','伏虎山房','白約','宋','宋诗','song-poetry','','[]','入眼林巒皆可意，不憚間關千里至。',64,'全唐诗/poet.song.36000.json','["入眼林巒皆可意，不憚間關千里至。", "白雲隨步入危梯，前時想像今真是。", "千巖萬壑誠瑰傑，小草微花亦精緻。", "更隨虎迹訪幽深，恐有秦人來避地。"]'),
('ad5d19d6-f9e7-4dbd-a7ee-b0ca6793be36','虎丘','蒲宗孟','宋','宋诗','song-poetry','','[]','長松繞步水灣環，寺據吳王冢墓間。',64,'全唐诗/poet.song.36000.json','["長松繞步水灣環，寺據吳王冢墓間。", "瘦石千層開碧玉，疏圍十里裹青山。", "壁從地上嶄巖起，雲出門前自在閒。", "零落生公講臺下，無人說法但空還。"]'),
('85d0b116-9e84-4f03-af8a-491630f75490','遊虎丘因書錢塘舊遊','蒲宗孟','宋','宋诗','song-poetry','','[]','失却湖山恨去舟，新年無意作春遊。',64,'全唐诗/poet.song.36000.json','["失却湖山恨去舟，新年無意作春遊。", "東風昨夜思龍井，曉雨全家入虎丘。", "望見遠峰疑石衖，誤尋歸路認花樓。", "明朝一出閶門去，清夢遥知在兩州。"]'),
('9cc9a5ed-34e0-4b96-8c41-934239669373','錦屏山','蒲宗孟','宋','宋诗','song-poetry','','[]','碧江寒浸錦屏山，寺古山靈樹石閒。',64,'全唐诗/poet.song.36000.json','["碧江寒浸錦屏山，寺古山靈樹石閒。", "水色照人清見膽，嵐光著霧翠成斑。", "自從舊句曾關念，縱有新詩總厚顔。", "今日斷絃應再續，一時傳誦在人間。"]'),
('0b15863d-e603-4c85-a4fa-945798be501a','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其一','蒲宗孟','宋','宋诗','song-poetry','','[]','歲除三十日，收得武昌書。',48,'全唐诗/poet.song.36000.json','["歲除三十日，收得武昌書。", "一紙方遠寄，數篇來起予。", "瀟湘流水闊，巫峽暮雲疏。", "不得相從去，春風正月初。"]'),
('b040fe14-e742-4122-bbee-00ebd7d3acf5','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其二','蒲宗孟','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','想到零陵日，高歌足解顔。',48,'全唐诗/poet.song.36000.json','["想到零陵日，高歌足解顔。", "鄉閭接營道，風物近廬山。", "萬石今興廢，三亭誰往還。", "不知零與永，二郡孰安閒。"]'),
('6d38bc10-610d-4816-9597-33651e997f61','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其三','蒲宗孟','宋','宋诗','song-poetry','','[]','三月春才過，君當始到官。',48,'全唐诗/poet.song.36000.json','["三月春才過，君當始到官。", "朱袍爛紅日，白髮未盈冠。", "喜靜心長在，耽詩性最歡。", "應從下車始，便起作題端。"]'),
('cd016aea-6be4-4262-80e9-d4e3befa837e','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其四','蒲宗孟','宋','宋诗','song-poetry','','[]','始彼南康責，誰知睿澤寬。',48,'全唐诗/poet.song.36000.json','["始彼南康責，誰知睿澤寬。", "還爲半刺史，不失古虞官。", "別乘今誰厚，朱轓舊最歡。", "遥憐春色好，并蓋縱游鞍。"]'),
('535a5f9f-ef2e-414c-bf6f-c380e4fc3968','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其五','蒲宗孟','宋','宋诗','song-poetry','','[]','地與江淮近，鄉人慰久暌。',48,'全唐诗/poet.song.36000.json','["地與江淮近，鄉人慰久暌。", "重看斑竹淚，還聽鷓鴣啼。", "湘水晴波遠，蒼梧霽色低。", "不知春日靜，何似在濂溪。"]'),
('c6feac01-7e21-4356-8e4b-62ce126ad1a4','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其六','蒲宗孟','宋','宋诗','song-poetry','','[]','二子君家寶，知渠神骨清。',48,'全唐诗/poet.song.36000.json','["二子君家寶，知渠神骨清。", "初生俱嶷嶷，學語便鏗鏗。", "鳳老雛方秀，珠圓蚌轉明。", "吾甥真宅相，可得不翹英。"]'),
('9922c845-50d9-41c8-b67f-e50209391806','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其七','蒲宗孟','宋','宋诗','song-poetry','','[]','山水平生好，嘗來說退居。',48,'全唐诗/poet.song.36000.json','["山水平生好，嘗來說退居。", "無家歸紱冕，有子侍籃輿。", "湓浦方營業，濂溪旋結廬。", "零陵官俸剩，應得更添書。"]'),
('e9799639-f102-4c66-a6fc-288e1719bd3d','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其八','蒲宗孟','宋','宋诗','song-poetry','','[]','八郡湖南使，稜稜盡有名。',48,'全唐诗/poet.song.36000.json','["八郡湖南使，稜稜盡有名。", "刑臺本鄉舊，漕府忝門生。", "吾戚饒風力，伊人最直清。", "預知相見日，傾蓋便投城。"]'),
('fcc4a476-d66f-4a5e-ac7b-7c88c76c4de6','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其九','蒲宗孟','宋','宋诗','song-poetry','','[]','宗邑祅災併，無如舊歲多。',48,'全唐诗/poet.song.36000.json','["宗邑祅災併，無如舊歲多。", "凶霖浸宮闕，湧水注江河。", "鬼盛天爲疫，陰强雪薦瘥。", "知君憂國甚，搔首只吟哦。"]'),
('ced27fe5-9fe0-488b-9801-e297e55b58d3','乙巳歲除日收周茂叔虞曹武昌惠書知已赴官零陵丙午正月內成十詩奉寄  其一○','蒲宗孟','宋','宋诗','song-poetry','','[]','詩社久零落，所傳毛鄭餘。',48,'全唐诗/poet.song.36000.json','["詩社久零落，所傳毛鄭餘。", "先生守章句，後輩老蟲魚。", "大義誰窺覷，微言尚闊疏。", "煩君來就索，但恨未成書。"]'),
('7b070bf0-32a6-4b13-a82f-512bf5b399be','新開湖詩 將廢西園開南湖先諭老圃','蒲宗孟','宋','宋诗','song-poetry','','[]','擬作南湖當北湖，勸教老圃罷耕鋤。',64,'全唐诗/poet.song.36000.json','["擬作南湖當北湖，勸教老圃罷耕鋤。", "此間有景待垂釣，何處無田可種蔬。", "長夏便應浮藻荇，高亭行看走龜魚。", "秋風一棹荷花裏，醉卧煙波欲自如。"]'),
('6cf9566b-7d56-4766-95ae-7dcd7e73b7c1','新開湖詩 昝司萬參軍甄盤虢略主簿何殊南湖種柳植蓮','蒲宗孟','宋','宋诗','song-poetry','','[]','繞岸便須多種柳，滿湖仍爲遍栽蓮。',32,'全唐诗/poet.song.36000.json','["繞岸便須多種柳，滿湖仍爲遍栽蓮。", "長條翠蓋成陰日，我欲移舟處處眠。"]'),
('4f74c1c6-3492-4074-aa89-d9cfb6531af7','新開湖詩 諭甄何二君於南湖諸亭築孤嶼','蒲宗孟','宋','宋诗','song-poetry','','[]','孤嶼莫教閑草占，諸亭還向四邊開。',32,'全唐诗/poet.song.36000.json','["孤嶼莫教閑草占，諸亭還向四邊開。", "凉天我欲携樽酒，同與清風白月來。"]'),
('1faa822b-ff6f-410a-98ab-919b1d6be4d3','新開湖詩 諷甄何二君南湖養魚','蒲宗孟','宋','宋诗','song-poetry','','[]','剩將鱣鮪散南湖，一細千鱗已有餘。',32,'全唐诗/poet.song.36000.json','["剩將鱣鮪散南湖，一細千鱗已有餘。", "傳舍客來須縱食，莫教彈劍嘆無魚。"]'),
('17bb6320-06ca-4269-bd06-27cce4b6fe14','新開湖詩 調甄何二君於南湖創小舟','蒲宗孟','宋','宋诗','song-poetry','','[]','細編青篾高爲蓋，密鬥朱欄大作船。',32,'全唐诗/poet.song.36000.json','["細編青篾高爲蓋，密鬥朱欄大作船。", "準擬使君清興發，銀笙玉笛醉紅蓮。"]'),
('c1b602e3-6b0c-40d3-beac-192415636dac','新開湖詩 諷甄何二君於南湖架梯橋過渚亭','蒲宗孟','宋','宋诗','song-poetry','','[]','橋須跨水三千尺，路要梯橫數百層。',32,'全唐诗/poet.song.36000.json','["橋須跨水三千尺，路要梯橫數百層。", "會有赤松來過我，待從此處共飛騰。"]'),
('96048a74-b298-4c73-b8f3-df4885ffae4d','通天巖','蒲宗孟','宋','宋诗','song-poetry','','[]','幽懷慕嶺寂，結庵在中林。',48,'全唐诗/poet.song.36000.json','["幽懷慕嶺寂，結庵在中林。", "綠竹君子操，清池故人心。", "明月弄寒影，好風摇翠陰。", "江南千里遠，何處盛朋簪。"]'),
('cb5357e0-01d4-4ea7-8ac6-757a8e1526b3','題徐沖晦處士舊隠','蒲宗孟','宋','宋诗','song-poetry','','[]','沖晦先生不肯官，布衣謁帝布衣還。',64,'全唐诗/poet.song.36000.json','["沖晦先生不肯官，布衣謁帝布衣還。", "尚嫌姓字騰人口，惟恐文章落世間。", "大隠不妨居市井，高吟何處問家山。", "平生寄意江湖上，雲自無心水自閑。"]'),
('f36bc06e-4fe4-4492-b36d-f1361353c49e','九龍巖  其一','蒲宗孟','宋','宋诗','song-poetry','','[]','虛巖蒼壁古苔斑，瀟灑清深六月寒。',32,'全唐诗/poet.song.36000.json','["虛巖蒼壁古苔斑，瀟灑清深六月寒。", "三伏流金無處避，暮天將去更盤桓。"]'),
('21d6769c-6205-407b-9ade-e69c08928b48','九龍巖  其二','蒲宗孟','宋','宋诗','song-poetry','','[]','老僧棲息亂雲顛，鑿石開山四十年。',32,'全唐诗/poet.song.36000.json','["老僧棲息亂雲顛，鑿石開山四十年。", "投得巖成身老大，更無筋力到巖前。"]'),
('37f7d305-fe46-414c-a534-9ceaad1216b9','九龍巖  其三','蒲宗孟','宋','宋诗','song-poetry','','[]','人言道士隠深山，九煉丹成去不還。',32,'全唐诗/poet.song.36000.json','["人言道士隠深山，九煉丹成去不還。", "乳溜滴成華蓋座，猶疑真相在巖間。"]'),
('c40de144-8d31-45f4-a25d-180f8d0d074e','九龍巖  其四','蒲宗孟','宋','宋诗','song-poetry','','[]','欲尋微徑到山前，聞有蛟龍洞底眠。',32,'全唐诗/poet.song.36000.json','["欲尋微徑到山前，聞有蛟龍洞底眠。", "歲旱密雲終不雨，可能無意救荒年。"]'),
('203b4221-ee2a-420d-8a0e-a0e1e3ad030b','寄蘄簟','蒲宗孟','宋','宋诗','song-poetry','','[]','公家列屋閒娥眉，珠簾不動花蔭移。',32,'全唐诗/poet.song.36000.json','["公家列屋閒娥眉，珠簾不動花蔭移。", "雲帳銀床初破睡，牙籤玉軸坐彈棋。"]'),
('6ed1fafc-1d06-4b95-974a-9e1d662da8e0','句  其一','蒲宗孟','宋','宋诗','song-poetry','','[]','收書萬卷日沈酣，鮑謝詩篇老更耽。',16,'全唐诗/poet.song.36000.json','["收書萬卷日沈酣，鮑謝詩篇老更耽。"]'),
('04843074-a3ee-445c-90de-60158aafaec1','句  其二','蒲宗孟','宋','宋诗','song-poetry','','[]','聖名不敢居，民譽日益美。',12,'全唐诗/poet.song.36000.json','["聖名不敢居，民譽日益美。"]'),
('3d85da78-b935-4e18-b34e-eb342fbf100d','句  其三','蒲宗孟','宋','宋诗','song-poetry','','[]','閬州勝絕是雲臺，十里松蘿殿閣開。',16,'全唐诗/poet.song.36000.json','["閬州勝絕是雲臺，十里松蘿殿閣開。"]'),
('fb940315-bb9b-448e-a7c7-f6d856b45490','題釣臺','魯有開','宋','宋诗','song-poetry','','[]','昔日狂奴向此來，愛垂芳餌上崔嵬。',32,'全唐诗/poet.song.36000.json','["昔日狂奴向此來，愛垂芳餌上崔嵬。", "鄉人不識釣臺意，空指山頭是釣臺。"]'),
('e90e1b65-289b-49ab-abec-b76d9d53f374','大滌洞','魯有開','宋','宋诗','song-poetry','','[]','馬蹄清曉破藍田，一出紅塵骨已仙。',64,'全唐诗/poet.song.36000.json','["馬蹄清曉破藍田，一出紅塵骨已仙。", "任鎖九重山下路，終尋五處洞中天。", "泉流碧砌長鳴玉，蹟隠蒼崖久蛻蟬。", "人世歸時知變否，樵夫曾記爛柯年。"]'),
('b24b1994-e598-41c9-9079-d73ac5b1f624','句','李誼伯','宋','宋诗','song-poetry','','[]','截開野色教天闊，斫斷浮雲放日高。',16,'全唐诗/poet.song.36000.json','["截開野色教天闊，斫斷浮雲放日高。"]'),
('24dc4234-2b70-4c40-b600-e9fa8ca46e0e','放隠齋落成寄魯直九姪','黄序','宋','宋诗','song-poetry','','[]','直木皆先伐，輪囷却歲寒。',48,'全唐诗/poet.song.36000.json','["直木皆先伐，輪囷却歲寒。", "時霑病者粟，倒著掛時冠。", "人樂觀魚尾，山齋跨馬鞍。", "朝中乞佳句，留與子孫看。"]'),
('bd5c8fc8-4303-471b-8327-7d4df6809b76','蓮華池','黄中庸','宋','宋诗','song-poetry','','[]','蓮花瓣裏可撐船，一月映成水一川。',32,'全唐诗/poet.song.36000.json','["蓮花瓣裏可撐船，一月映成水一川。", "人把水心和月浄，蓮花貯月水傾船。"]'),
('a16561eb-3866-4174-942e-0d39b14529de','謝章子厚','劉定','宋','宋诗','song-poetry','','[]','故人天上有書來，責我疏愚喚不回。',64,'全唐诗/poet.song.36000.json','["故人天上有書來，責我疏愚喚不回。", "兩處共瞻千里月，十年不寄一枝梅。", "塵泥自與雲霄隔，駑馬難追德驥才。", "莫謂無心向門下，也曾終夕望三台。"]'),
('59d991f1-4cb2-4e30-9843-ce1b4b02a08c','游齊山招提二首  其一','劉定','宋','宋诗','song-poetry','','[]','樓迥山饒翠，湖平水漫黄。',48,'全唐诗/poet.song.36000.json','["樓迥山饒翠，湖平水漫黄。", "開簾無午暑，隔洞有秋香。", "冰枕聊相慰，雲帆亦未忙。", "月明與溪色，好在紫微郎。"]'),
('daebb27d-1384-4004-b168-28d62b1619ed','游齊山招提二首  其二','劉定','宋','宋诗','song-poetry','','[]','憶上青蘿磴，流年三十三。',48,'全唐诗/poet.song.36000.json','["憶上青蘿磴，流年三十三。", "僧人頭似雪，寺坦竹如藍。", "蕭使登高石，吳公守隠巖。", "清風殊未遠，咫尺看雲嵐。"]'),
('df6a9d9f-17d4-4d04-a288-c22e57c22dd7','望江亭','陳傳','宋','宋诗','song-poetry','','[]','山藹峨峨江岸深，望餘亭影落江心。',64,'全唐诗/poet.song.36000.json','["山藹峨峨江岸深，望餘亭影落江心。", "無風萬里磨平玉，有月千波漾碎金。", "思遠解邀無己句，流清宜寫不齊琴。", "仙槎一棹驚秋曉，此去銀河尚幾尋。"]'),
('f7fab2ca-2899-4c5a-9d14-6c9bcd6d42e5','贈顔象環','陳傳','宋','宋诗','song-poetry','','[]','初與田蔬一樣平，一千年後插天青。',32,'全唐诗/poet.song.36000.json','["初與田蔬一樣平，一千年後插天青。", "行人息蔭凉風下，應說栽松道士名。"]'),
('fa9e0e89-cddf-4c06-9832-89fca47aee66','佐郎將','陳傳','宋','宋诗','song-poetry','','[]','林中生致佐郎將，名王頭顱十四五。',96,'全唐诗/poet.song.36000.json','["林中生致佐郎將，名王頭顱十四五。", "乾德可禽嗟不謀，同惡相濟能包羞。", "降書冉冉過中州，中軍傳呼笑點頭。", "蠻首算成勿藥喜，君臣稱觴弭多壘。", "元戎凱旋隔天水，夜經桄榔趨决里。", "驅將十萬人性命，換得交州數張紙。"]'),
('9f61c5cf-f6af-4497-b567-348282b3cced','衆樂亭  其一','陳汝羲','宋','宋诗','song-poetry','','[]','聞說湖亭又一新，不徒行樂樂斯民。',64,'全唐诗/poet.song.36000.json','["聞說湖亭又一新，不徒行樂樂斯民。", "水光剩占鷗鷳地，人意常同桃李春。", "試展畫圖清俗眼，况專閒席傲天真。", "使君已陟螭頭貴，應爲烟雲入夢頻。"]'),
('d342ffae-a5ed-4da9-99d6-84cada123772','衆樂亭  其二','陳汝羲','宋','宋诗','song-poetry','','[]','遥思湖上自由春，醉踏吟看屬使君。',64,'全唐诗/poet.song.36000.json','["遥思湖上自由春，醉踏吟看屬使君。", "水底天光開靜鑒，岸頭花氣遞紅雲。", "島浮虛檻橋橋接，風翼時鐘寺寺聞。", "漬墨新名人會否，不將民樂廢民勤。"]'),
('0c7a2fe5-f635-4146-ba81-c056d020fb78','句','周師厚','宋','宋诗','song-poetry','','[]','有眼不堪看鄭獬，回頭猶喜得陳傳。',16,'全唐诗/poet.song.36000.json','["有眼不堪看鄭獬，回頭猶喜得陳傳。"]'),
('13f886cd-adc9-45c3-b1c2-f793a2d290c8','五洩山','周鏞','宋','宋诗','song-poetry','','[]','路入蒼烟九過溪，細穿岩曲到招提。',64,'全唐诗/poet.song.36000.json','["路入蒼烟九過溪，細穿岩曲到招提。", "天分五溜寒傾北，地秀諸峰翠插西。", "鑿徑破崖來木杪，駕泉鳴竹落榱題。", "當年老默無消息，猶有祠堂一杖藜。"]'),
('15a688a9-d01e-4a08-be59-4f143d3923ea','建溪','鄭叔明','宋','宋诗','song-poetry','','[]','水色山光表裏清，野花溪柳意相迎。',64,'全唐诗/poet.song.36000.json','["水色山光表裏清，野花溪柳意相迎。", "狂歌驚鷺灘頭散，欹枕看雲嶺上生。", "峰曲轉帆疑路盡，潭深飛棹覺舟輕。", "歸程漸喜鄉關近，竹戶楓林雞犬聲。"]'),
('4ba8d506-16c0-4005-95d7-bc172e0c9382','送程給事知越州','何琬','宋','宋诗','song-poetry','','[]','賀老溪山久寂寥，輟從青瑣去班條。',64,'全唐诗/poet.song.36000.json','["賀老溪山久寂寥，輟從青瑣去班條。", "樓臺爽氣來蓬島，鼓角新聲壓海潮。", "千里勸耕趨壟畝，五雲吟句落漁樵。", "鑒湖想望隋河上，滿眼清風逐畫橈。"]'),
('092f9277-bdcf-464d-9b6a-13690c933fb5','送程給事知越州','呂大忠','宋','宋诗','song-poetry','','[]','飛詔平明走玉珂，夕郎持節越山阿。',64,'全唐诗/poet.song.36000.json','["飛詔平明走玉珂，夕郎持節越山阿。", "西風旗鼓催行色，南國蓴鱸助醉歌。", "鄰寇未銷謀可爾，部氓猶困政如何。", "番禺今得長城利，推此求功曲突多。"]'),
('ec6c8860-bdfa-4717-a5c5-76d2e85af96c','山門六題寄聖俞','張獻民','宋','宋诗','song-poetry','','[]','文脊佳峰巒，煙雲密帷幕。',72,'全唐诗/poet.song.36000.json','["文脊佳峰巒，煙雲密帷幕。", "窮深到幽處，無路通馬脚。", "天意忽蕪沒，神功爲開鑿。", "周環列蒼石，直上撐碧落。", "伏暑坐其下，凜凜風霜作。", "俗客頻往來，只恐却鎖鑰。"]'),
('9953a8dd-1792-46ac-94f5-006d2e3bf366','山門六題寄聖俞 山門','張獻民','宋','宋诗','song-poetry','','[]','無路可通文脊隈，山腰大闢門崔嵬。',64,'全唐诗/poet.song.36000.json','["無路可通文脊隈，山腰大闢門崔嵬。", "若非天地功破裂，定是鬼神力鑿開。", "渾渾旁撐蒼壁立，空空直貫清風來。", "祇應便徹仙源去，願躡飛雲到玉臺。"]'),
('0986eaec-ab61-4e67-9f66-14b491907372','山門六題寄聖俞 朝陽洞','張獻民','宋','宋诗','song-poetry','','[]','撇衣秉火捫石入，路硬磽确黑如漆。',32,'全唐诗/poet.song.36000.json','["撇衣秉火捫石入，路硬磽确黑如漆。", "窮深不見瞿硎生，洞中依舊石藏室。"]'),
('662feb5f-84ff-4271-977d-2efeaf0d97fe','山門六題寄聖俞 漣漪洞','張獻民','宋','宋诗','song-poetry','','[]','洞流何處窟穴斷，泉向洞中源源生。',32,'全唐诗/poet.song.36000.json','["洞流何處窟穴斷，泉向洞中源源生。", "潺潺萬古流不盡，夜夜空照山月明。"]'),
('fdc47599-4318-4b51-8f8f-fff785808e63','山門六題寄聖俞 碧雲洞','張獻民','宋','宋诗','song-poetry','','[]','一竇險若到平處，裂壁忽見天共明。',32,'全唐诗/poet.song.36000.json','["一竇險若到平處，裂壁忽見天共明。", "水深不敢投石響，潭中惟恐神龍驚。"]'),
('5b0535b9-ab54-4b7e-9be2-f9bc2ea70080','山門六題寄聖俞 紫雲巖 其一','張獻民','宋','宋诗','song-poetry','','[]','朝見紫雲生霏霏，暮見紫雲歸戢戢。',32,'全唐诗/poet.song.36000.json','["朝見紫雲生霏霏，暮見紫雲歸戢戢。", "有時飛鸞舞上下，料是仙人潛出入。"]'),
('86042726-d863-47b9-aa39-4a06939bf634','山門六題寄聖俞 紫雲巖 其二','張獻民','宋','宋诗','song-poetry','','[]','日破陰蒙照巖頂，紫雲一片拖晴影。',32,'全唐诗/poet.song.36000.json','["日破陰蒙照巖頂，紫雲一片拖晴影。", "溶溶洩洩晚不收，只疑便是壺中景。"]'),
('951e40f4-a9af-4918-8412-e7e30ef83abc','山門六題寄聖俞 夕陽巖 其一','張獻民','宋','宋诗','song-poetry','','[]','屹嵲欲到倚山脚，涵雲洩雨摩半空。',32,'全唐诗/poet.song.36000.json','["屹嵲欲到倚山脚，涵雲洩雨摩半空。", "向晚呀然射頹照，疊石爛爛參差紅。"]'),
('66f19509-efc2-4080-a8df-a0500028171e','山門六題寄聖俞 夕陽巖 其二','張獻民','宋','宋诗','song-poetry','','[]','巖下夕陽燭已然，巖腰斜照光猶射。',32,'全唐诗/poet.song.36000.json','["巖下夕陽燭已然，巖腰斜照光猶射。", "暮雲殘靄不能遮，始信仙居無晝夜。"]'),
('659d6c3a-ecd4-4474-bddc-36a7f4ec2d2a','句','樓郁','宋','宋诗','song-poetry','','[]','五經高閣倚雲開。',8,'全唐诗/poet.song.36000.json','["五經高閣倚雲開。"]'),
('806d3314-09cb-40d5-949c-38f245f9b7cd','虎丘','王紳','宋','宋诗','song-poetry','','[]','山頭古寺多陳迹，故國空餘氣象雄。',32,'全唐诗/poet.song.36000.json','["山頭古寺多陳迹，故國空餘氣象雄。", "霸業已隨流水去，闔閭墳草又西風。"]'),
('1b3d3a0a-99a4-4d54-8d87-a078c23c0b61','題干越亭送石秘校詩後','張挺卿','宋','宋诗','song-poetry','','[]','宛陵梅夫子，才名冠當世。',72,'全唐诗/poet.song.36000.json','["宛陵梅夫子，才名冠當世。", "歐蘇與並驅，時稱天下士。", "哲人去已久，手澤見英氣。", "可慕不可攀，悠悠千古意。", "行義魯臧孫，流芳垂後裔。", "今遇叔章君，箕裘元不墜。"]'),
('dce35432-3a16-4ffd-bf18-42a6c6f43aaa','集村行','王無咎','宋','宋诗','song-poetry','','[]','産業家家壞，誅求歲歲新。',48,'全唐诗/poet.song.36000.json','["産業家家壞，誅求歲歲新。", "平時不爲備，執事彼何人。", "朱戶仍奢侈，柴門轉窶貧。", "若非衢空畔，無用說悲辛。"]'),
('e70971c1-e040-46a3-b0b7-9fe9314f0586','勸巖師酒','王無咎','宋','宋诗','song-poetry','','[]','臘去東風漸破春，憑軒悵望倍凝神。',64,'全唐诗/poet.song.36000.json','["臘去東風漸破春，憑軒悵望倍凝神。", "鳥鳴曉霽聲音樂，物被陽和氣候新。", "佳景牽懷吟稍遍，芳杯到手舉宜頻。", "靈均空詫離騷好，憔悴終爲獨醒人。"]'),
('3056ebc0-c7ed-4082-8592-fe8a7447c273','麻姑山','王無咎','宋','宋诗','song-poetry','','[]','仙軿昔日此留連，氣象遼遼尚宛然。',64,'全唐诗/poet.song.36000.json','["仙軿昔日此留連，氣象遼遼尚宛然。", "溪落斷崖爲遠瀑，路從絕頂見平田。", "千年芝有靈禽戲，一洞雲留羽客眠。", "已樂勝遊塵境外，况陪清論酒尊前。"]'),
('456d7da7-3464-4ed2-ade4-4fe1367c2b45','國清寺','李元凱','宋','宋诗','song-poetry','','[]','智者高蹤接沃洲，石渠仙職我同遊。',64,'全唐诗/poet.song.36000.json','["智者高蹤接沃洲，石渠仙職我同遊。", "已無月桂籠禪室，猶有祥雲鎖寺樓。", "疊砌崚嶒封碧蘚，五峰蒼翠覆寒流。", "却緣王命相拘束，不得躋攀最上頭。"]'),
('fffaf2db-6a0b-4ade-b6f9-b53667f813d3','絕命偈','張宗旦','宋','宋诗','song-poetry','','[]','法本心生，心因法昧。',40,'全唐诗/poet.song.36000.json','["法本心生，心因法昧。", "有覺于此，是名自在。", "自在真空，頓然明徹。", "去住尋常，曉然春雪。"]'),
('1e9ba4c4-46b4-4ade-b580-df121b4d6500','賦新繁周表權如詔亭','劉孝孫','宋','宋诗','song-poetry','','[]','義方曾榜舊亭名，子已爲郎典要城。',64,'全唐诗/poet.song.36000.json','["義方曾榜舊亭名，子已爲郎典要城。", "身服上恩今日顯，詔符前語是人驚。", "正如伯起鱣堂兆，兼勝于公駟閥榮。", "試問繁江諸父老，詩書何似寶金籯。"]'),
('3d40ad2f-83f0-4dae-9362-1901eeb8c7f8','黄河','劉孝孫','宋','宋诗','song-poetry','','[]','鴻流導積石，驚浪下龍門。',24,'全唐诗/poet.song.36000.json','["鴻流導積石，驚浪下龍門。", "仙槎不辨處，沉璧想猶存。"]'),
('2e610c42-0c66-43f4-b89f-343d9c414084','句','劉孝孫','宋','宋诗','song-poetry','','[]','詩書魯國真男子，歌吹揚州是貴人。',16,'全唐诗/poet.song.36000.json','["詩書魯國真男子，歌吹揚州是貴人。"]'),
('48f3368b-56d7-4ed2-afaa-4afbad64636c','送程給事知越州','陳侗','宋','宋诗','song-poetry','','[]','夕郎鄉思滿江皋，晝錦東歸意氣豪。',96,'全唐诗/poet.song.36000.json','["夕郎鄉思滿江皋，晝錦東歸意氣豪。", "侯國臺門牙戟盛，使君樓艓隼旟高。", "瑣窗暮入曾批敕，仙殿晨趨罷染毫。", "曲水春風修禊飲，卧龍山雨望秋濤。", "番禺已有金湯惠，秦望應先衮綍褒。", "莫戀蓬萊便棲志，佇看拂拭呂虔刀。"]'),
('8ae9f409-b09a-4185-b4f0-428683e801eb','題東老庵','陳侗','宋','宋诗','song-poetry','','[]','我昔名東老，君能老此庵。',48,'全唐诗/poet.song.36000.json','["我昔名東老，君能老此庵。", "溪風開梵帙，巖月伴莊談。", "世味閒無著，人情晚更諳。", "蕭然塵外意，回首謝圖南。"]'),
('3c971a97-b6cc-4c00-8c61-01282bea2a8f','寄王微之','傅堯俞','宋','宋诗','song-poetry','','[]','當利江頭最僻州，懷人惟是數登樓。',32,'全唐诗/poet.song.36000.json','["當利江頭最僻州，懷人惟是數登樓。", "綠樽連日不成宴，飛蓋滿城無舊游。"]'),
('8623cafb-553f-497f-8cde-da4a3cd0ec02','讀書','傅堯俞','宋','宋诗','song-poetry','','[]','吾屋雖諠卑，頗不甚蕪穢。',96,'全唐诗/poet.song.36000.json','["吾屋雖諠卑，頗不甚蕪穢。", "置席屋中間，坐卧群書內。", "橫風吹急雨，入屋灑我背。", "展卷殊未知，心與古人會。", "有客自外來，笑我苦癡昧。", "且問何爲爾，我初尚不對。", "强我不得已，起答客亦退。", "聊復得此心，霑濕安足悔。"]'),
('b5334960-7e33-48c0-906a-466095a65d28','詩一首','傅堯俞','宋','宋诗','song-poetry','','[]','微官共有田園興，老罷云尋退隠廬。',32,'全唐诗/poet.song.36000.json','["微官共有田園興，老罷云尋退隠廬。", "栽種成陰十年事，倉皇求買萬金無。"]'),
('0bb77740-6309-4f73-a9ba-650fa1f9ac9b','句','傅堯俞','宋','宋诗','song-poetry','','[]','此時廊廟聯三省，它日貂蟬定兩公。',16,'全唐诗/poet.song.36000.json','["此時廊廟聯三省，它日貂蟬定兩公。"]'),
('0e8d98b2-c522-4022-b175-cc9f90369adf','偈','釋法演','宋','宋诗','song-poetry','','[]','皖伯臺前送別時，桃花如錦柳如眉。',32,'全唐诗/poet.song.36000.json','["皖伯臺前送別時，桃花如錦柳如眉。", "明年此日憑欄看，依舊青青一兩枝。"]'),
('fdb3faff-6af3-4d22-8978-6db76afc234b','投機偈呈白雲端禪師','釋法演','宋','宋诗','song-poetry','','[]','山前一片閑田地，叉手叮嚀問祖翁。',32,'全唐诗/poet.song.36000.json','["山前一片閑田地，叉手叮嚀問祖翁。", "幾度賣來還自買，爲憐松竹引清風。"]'),
('f69cc90c-4595-409a-8446-856baf1e1342','偈七首  其一','釋法演','宋','宋诗','song-poetry','','[]','幸然無一事，行脚要參禪。',24,'全唐诗/poet.song.36000.json','["幸然無一事，行脚要參禪。", "却被禪相惱，不透祖師關。"]'),
('36350589-01e4-44ea-9ab3-b4b09bc2b043','偈七首  其二','釋法演','宋','宋诗','song-poetry','','[]','難難幾何般，易易沒巴鼻。',24,'全唐诗/poet.song.36000.json','["難難幾何般，易易沒巴鼻。", "好好催人老，默默從此得。"]'),
('e974a198-c16d-4ea1-9090-5911e49db5a4','偈七首  其三','釋法演','宋','宋诗','song-poetry','','[]','此箇物，上拄天，下拄地。',60,'全唐诗/poet.song.36000.json','["此箇物，上拄天，下拄地。", "皖口作眼，皖山作鼻。", "太平退身三步，放你諸人出氣。", "太平淈髿漢，事事盡經遍。", "如是三十年，也有人讚歎。"]'),
('0d4d9e72-0f50-40b0-b4d5-751b8a512be8','偈七首  其四','釋法演','宋','宋诗','song-poetry','','[]','白雲不會說禪，三門開向兩邊。',28,'全唐诗/poet.song.36000.json','["白雲不會說禪，三門開向兩邊。", "有人動著關捩，兩片東扇西扇。"]'),
('638d410e-b28e-4cec-b8a7-484660ae245f','偈七首  其五','釋法演','宋','宋诗','song-poetry','','[]','悟了同未悟，歸家尋舊路。',48,'全唐诗/poet.song.36000.json','["悟了同未悟，歸家尋舊路。", "一字是一字，一句是一句。", "自小不脫空，兩歲學移步。", "湛水生蓮花，一年生一度。"]'),
('830aa5a7-2d86-40b7-a3b7-78f3efca8869','偈七首  其六','釋法演','宋','宋诗','song-poetry','','[]','花發鷄冠媚早秋，誰人能染紫絲頭。',32,'全唐诗/poet.song.36000.json','["花發鷄冠媚早秋，誰人能染紫絲頭。", "有時風動頻相倚，似向階前鬭不休。"]'),
('fabf74e2-aa6b-4a13-a9df-d29e3d445ec2','偈七首  其七','釋法演','宋','宋诗','song-poetry','','[]','佛祖生冤家，悟道染泥土。',24,'全唐诗/poet.song.36000.json','["佛祖生冤家，悟道染泥土。", "無爲無事人，聲色如聾瞽。"]'),
('df10aa94-0272-434e-9fd2-d3304c1045f1','偈','釋法演','宋','宋诗','song-poetry','','[]','華種有生姓，因地華生生。',24,'全唐诗/poet.song.36000.json','["華種有生姓，因地華生生。", "大緣與性合，當生生不生。"]'),
