('7d74b9f1-1ec7-428d-b4ce-0500c81bdfa9','送程給事知越州','王誨','宋','宋诗','song-poetry','','[]','清班經歲侍凝旒，寵寄稽山第一州。',64,'全唐诗/poet.song.36000.json','["清班經歲侍凝旒，寵寄稽山第一州。", "瑣闥風規丹扆側，蓬萊烟靄碧江頭。", "詩豪誰敢雷門過，鄉老爭陪晝錦遊。", "行路光華浮畫鷁，浩然佳思鑒湖秋。"]'),
('adae1359-7115-4057-8307-e2ad0dd390df','聽琴','岑宗旦','宋','宋诗','song-poetry','','[]','琴中太古意，方外無爲心。',36,'全唐诗/poet.song.36000.json','["琴中太古意，方外無爲心。", "彈之道頗散，不彈理彌深。", "所以陶元亮，何須弦上音。"]'),
('081ec12b-01e0-4f3e-ad6d-2312984b85ac','過橋遭攧有省作偈','釋守端','宋','宋诗','song-poetry','','[]','我有明珠一顆，久被塵勞關鎖。',28,'全唐诗/poet.song.36000.json','["我有明珠一顆，久被塵勞關鎖。", "今朝塵盡光生，照破山河萬朵。"]'),
('c1b78fb1-b6b9-4b2e-9e92-81cba6920aed','偈七首  其一','釋守端','宋','宋诗','song-poetry','','[]','鳥有雙翼，飛無遠近。',20,'全唐诗/poet.song.36000.json','["鳥有雙翼，飛無遠近。", "首出一隅，行無前後。"]'),
('c74138a3-5856-4df9-aec1-ee39b8463c96','偈七首  其二','釋守端','宋','宋诗','song-poetry','','[]','忌口自然諸病減，多情未免有時勞。',32,'全唐诗/poet.song.36000.json','["忌口自然諸病減，多情未免有時勞。", "貧居動便成違順，落得清閑一味高。"]'),
('0f4bf496-b512-42eb-b44e-88fb5a814cff','偈七首  其三','釋守端','宋','宋诗','song-poetry','','[]','泥佛不度水，木佛不度火。',24,'全唐诗/poet.song.36000.json','["泥佛不度水，木佛不度火。", "金佛不度爐，真佛內裏坐。"]'),
('a514cb72-ac6c-4b78-acb6-72d143c8a7b0','偈七首  其四','釋守端','宋','宋诗','song-poetry','','[]','佛身充滿於法界，普現一切群生前。',32,'全唐诗/poet.song.36000.json','["佛身充滿於法界，普現一切群生前。", "隨緣赴感靡不周，而常處此菩提座。"]'),
('57ab5ac7-b8c8-4389-af02-27955e208557','偈七首  其五','釋守端','宋','宋诗','song-poetry','','[]','他人住處我不住，他人行處我不行。',32,'全唐诗/poet.song.36000.json','["他人住處我不住，他人行處我不行。", "不是爲人難共聚，大都緇素要分明。"]'),
('a854492d-95af-4a39-94c2-6ffe692aa311','偈七首  其六','釋守端','宋','宋诗','song-poetry','','[]','諸人法眼藏，千聖莫能當。',48,'全唐诗/poet.song.36000.json','["諸人法眼藏，千聖莫能當。", "爲君通一線，光輝滿大唐。", "須彌走入海，六月降嚴霜。", "法華雖恁道，無句得商量。"]'),
('f1a9ca8b-7e79-4c40-a758-023f63fb6dcf','偈七首  其七','釋守端','宋','宋诗','song-poetry','','[]','絲毫有趣皆能進，畢竟無歸若可當。',32,'全唐诗/poet.song.36000.json','["絲毫有趣皆能進，畢竟無歸若可當。", "逐日退身行興盡，忽然得見本爺孃。"]'),
('7cc5b262-6d55-4d01-bd72-e3dea0399e59','答郭祥正居士','釋守端','宋','宋诗','song-poetry','','[]','藏身不用縮頭，歛迹何須收脚。',28,'全唐诗/poet.song.36000.json','["藏身不用縮頭，歛迹何須收脚。", "金烏半夜遼天，玉免趕他不著。"]'),
('1827461d-aa9a-4364-ade6-085c445183ee','頌','釋守端','宋','宋诗','song-poetry','','[]','一拳拳倒黄鶴樓，一趯趯翻鸚鵡洲。',32,'全唐诗/poet.song.36000.json','["一拳拳倒黄鶴樓，一趯趯翻鸚鵡洲。", "有意氣時添意氣，不風流處也風流。"]'),
('a61284e0-70f9-47f1-ad06-137cdb6cd4d1','爲郭功甫偈  其一','釋守端','宋','宋诗','song-poetry','','[]','牛來山中，水足草足。',20,'全唐诗/poet.song.36000.json','["牛來山中，水足草足。", "牛出山去，東觸西觸。"]'),
('fc6c7a63-669b-46ea-a17a-fb06decccc43','爲郭功甫偈  其二','釋守端','宋','宋诗','song-poetry','','[]','上大人，丘乙己。',16,'全唐诗/poet.song.36000.json','["上大人，丘乙己。", "化三千，可知禮。"]'),
('e0ab07a4-3730-4c63-affe-84a6b0516e58','偈','釋守端','宋','宋诗','song-poetry','','[]','一文大光錢，買得箇油糍。',24,'全唐诗/poet.song.36000.json','["一文大光錢，買得箇油糍。", "喫放肚裏了，當下便不饑。"]'),
('b2b1cb7c-3c2c-4267-85b8-a74cd43e2356','北斗藏身因緣偈','釋守端','宋','宋诗','song-poetry','','[]','九衢公子遊花慣，未第貧儒感慨多。',32,'全唐诗/poet.song.36000.json','["九衢公子遊花慣，未第貧儒感慨多。", "冷地看他人富貴，等閑無奈幞頭何。"]'),
('31b13dcd-9726-4b02-b02c-8b11e0efd489','蠅子透窗偈','釋守端','宋','宋诗','song-poetry','','[]','爲愛尋光紙上鑽，不能透處幾多般。',32,'全唐诗/poet.song.36000.json','["爲愛尋光紙上鑽，不能透處幾多般。", "忽然撞著來時路，始覺平生被眼瞞。"]'),
('0252a44a-f6ad-4329-a65d-1a0c6dcbca6d','句  其一','釋守端','宋','宋诗','song-poetry','','[]','異鄉風俗客不惡，但欲南音來耳邊。',16,'全唐诗/poet.song.36000.json','["異鄉風俗客不惡，但欲南音來耳邊。"]'),
('d2a1de92-24ff-42f3-914b-4a5e48f3ee44','句  其二','釋守端','宋','宋诗','song-poetry','','[]','不似大梅老，貪隨鼯鼠聲。',12,'全唐诗/poet.song.36000.json','["不似大梅老，貪隨鼯鼠聲。"]'),
('c2575dbe-72c4-4959-8b30-9b6f4687f191','偈八首  其一','釋仁勇','宋','宋诗','song-poetry','','[]','秋風凉，松韵長。',16,'全唐诗/poet.song.36000.json','["秋風凉，松韵長。", "未歸客，思故鄉。"]'),
('c89725d7-4227-4837-89e8-435dd6766ccb','偈八首  其二','釋仁勇','宋','宋诗','song-poetry','','[]','天上無彌勒，地下無彌勒。',24,'全唐诗/poet.song.36000.json','["天上無彌勒，地下無彌勒。", "打破太虛空，如何尋不得。"]'),
('9b995f23-2b03-4eef-bf35-09dd2eed49e7','偈八首  其三','釋仁勇','宋','宋诗','song-poetry','','[]','古人底今人用，今人底古人爲。',26,'全唐诗/poet.song.36000.json','["古人底今人用，今人底古人爲。", "古今無背面，今古幾人知。"]'),
('d325c850-e485-4870-8804-db04c13f1b14','偈八首  其四','釋仁勇','宋','宋诗','song-poetry','','[]','有手脚，無背面。',24,'全唐诗/poet.song.36000.json','["有手脚，無背面。", "明眼人，看不見。", "天左旋，地右轉。"]'),
('71badd8e-ea89-4faf-abea-7d8b4f2c0c5c','偈八首  其五','釋仁勇','宋','宋诗','song-poetry','','[]','風鳴條，雨破塊，曉來枕上鶑聲碎。',48,'全唐诗/poet.song.36000.json','["風鳴條，雨破塊，曉來枕上鶑聲碎。", "蝦𢋙蚯蚓一時鳴，妙德空生都不會。", "都不會，三箇成群，四箇作隊。", "”。"]'),
('91ee88e1-2d0b-4a47-bf8b-155c84f3e811','偈八首  其六','釋仁勇','宋','宋诗','song-poetry','','[]','有箇漢，怪復醜。',73,'全唐诗/poet.song.36000.json','["有箇漢，怪復醜。", "眼直鼻藍鑱面，南看北斗。", "解使日午金烏啼，夜斗鐵牛吼。", "天地旋，山河走。", "羽族毛群，失其所守。", "直得文殊普賢出此沒彼，七縱八橫，千生萬受。"]'),
('afdaacc0-3581-4eca-be19-6a7feb284b12','偈八首  其七','釋仁勇','宋','宋诗','song-poetry','','[]','大方無外，大圓無內。',40,'全唐诗/poet.song.36000.json','["大方無外，大圓無內。", "無內無外，聖凡普會。", "瓦礫生光，須彌粉碎。", "無量法門，百千三昧。"]'),
('ceff25c4-65ce-43db-a5a5-2605a348903a','偈八首  其八','釋仁勇','宋','宋诗','song-poetry','','[]','真相無形，示形現相。',74,'全唐诗/poet.song.36000.json','["真相無形，示形現相。", "千怪萬狀，自此而彰。", "喜則滿面光生，怒則雙眉陡豎。", "非凡非聖，或是或非。", "人不可量，天莫能測。", "直下搆得，未稱丈夫。", "喚不回頭，且莫錯怪。"]'),
('7546f9b1-d19f-4fa0-95a9-3bd316095a51','送程給事知越州','黄君俞','宋','宋诗','song-poetry','','[]','夕郎清貫籍殊材，曾寵南州刺史回。',64,'全唐诗/poet.song.36000.json','["夕郎清貫籍殊材，曾寵南州刺史回。", "通職更聯群玉府，分符仍得小蓬萊。", "民間威愛龔黄政，筆下文章李杜才。", "天子鼎新天下法，和羹方是用鹽梅。"]'),
('3bd17206-bbf9-4896-af81-f059f032e38c','句','王文淑','宋','宋诗','song-poetry','','[]','草草杯盤供語笑，昏昏燈火話平生。',16,'全唐诗/poet.song.36000.json','["草草杯盤供語笑，昏昏燈火話平生。"]'),
('f18831b6-688c-41c2-86d2-138908fa6e80','祠南海神','陳之方','宋','宋诗','song-poetry','','[]','湯湯南溟，百川所潴。',100,'全唐诗/poet.song.36000.json','["湯湯南溟，百川所潴。", "有赫其靈，有嚴其居。", "神宅于幽，誠格者應。", "其應維何，皇帝仁聖。", "幢旄鼓鐃，疇往祇祠。", "揭揭程公，神之聽之。", "祀事之既，神明歡喜。", "飈馳龍翔，一息萬里。", "衍涸濡焦，既盈既優。", "廟社億年，血食均休。"]'),
('d818f268-7e68-4869-82cd-52370d769709','送程給事知越州','陳睦','宋','宋诗','song-poetry','','[]','孔戣佳政在番禺，嚴助終年厭直廬。',64,'全唐诗/poet.song.36000.json','["孔戣佳政在番禺，嚴助終年厭直廬。", "欲解塵纓臨曲水，忽驚計吏拜高車。", "行歸天上參鵷侶，暫向江邊駐隼旟。", "正想題詩憑郡閣，秋波綠浄落芙蕖。"]'),
('3a6d05e6-2c2e-4586-bc7b-5ad22b516694','題東老庵','陳睦','宋','宋诗','song-poetry','','[]','憶昔曾來訪隠淪，瀟然雲水隔凡塵。',64,'全唐诗/poet.song.36000.json','["憶昔曾來訪隠淪，瀟然雲水隔凡塵。", "畫船祇載溪中月，白酒長添座上春。", "晝掩山扉無俗客，夜吟石鼎有高人。", "飄飄洒落青衫子，共話平生淚滿巾。"]'),
('797e3b37-5d37-47d7-b8e2-1d1b14aaa9b9','臨終偈','源禪師','宋','宋诗','song-poetry','','[]','雪鬢霜髭九九年，半肩毳衲盡諸緣。',32,'全唐诗/poet.song.36000.json','["雪鬢霜髭九九年，半肩毳衲盡諸緣。", "廓然笑指浮雲散，玉兔流光照大千。"]'),
('e04dabd4-641f-436a-a72a-6ac73c180720','偈五首  其一','釋悟真','宋','宋诗','song-poetry','','[]','師子兒哮吼，龍馬駒絙跳。',24,'全唐诗/poet.song.36000.json','["師子兒哮吼，龍馬駒絙跳。", "古佛鏡中明，三山孤月皎。"]'),
('3fe9edd9-a5d0-4572-84a2-7bb15cde3892','偈五首  其二','釋悟真','宋','宋诗','song-poetry','','[]','三面狸奴脚踏月，兩頭白牯手拏烟。',32,'全唐诗/poet.song.36000.json','["三面狸奴脚踏月，兩頭白牯手拏烟。", "戴冠碧兔立庭柏，脫殻烏龜飛上天。"]'),
('6580c836-d6df-4b04-9e1c-f2c9a4d723fb','偈五首  其三','釋悟真','宋','宋诗','song-poetry','','[]','叮嚀損君德，無言真有功。',24,'全唐诗/poet.song.36000.json','["叮嚀損君德，無言真有功。", "任從滄海變，終不爲君通。"]'),
('25bbbb8e-079c-4c81-a20f-3e950226731e','偈五首  其四','釋悟真','宋','宋诗','song-poetry','','[]','寂照常照本來照，草鞋底下常絙跳。',32,'全唐诗/poet.song.36000.json','["寂照常照本來照，草鞋底下常絙跳。", "更會針鋒上須彌，眉毛中水常渺渺。"]'),
('edf65f9a-ddff-489e-9b09-76cf69445fc4','偈五首  其五','釋悟真','宋','宋诗','song-poetry','','[]','手提巴鼻脚踏尾，仰面看天聽流水。',32,'全唐诗/poet.song.36000.json','["手提巴鼻脚踏尾，仰面看天聽流水。", "天明送出路傍邊，夜靜還歸茅屋裏。"]'),
('e17882f8-6076-4f21-98c5-03a73398500d','偈','釋真淨','宋','宋诗','song-poetry','','[]','二十餘年用意猜，幾番曾把此心灰。',32,'全唐诗/poet.song.36000.json','["二十餘年用意猜，幾番曾把此心灰。", "而今潦倒逢知己，李白元來是秀才。"]'),
('dca4d7b8-59ac-4b55-8fd4-4a9c4d878aec','送程給事知越州','曾孝寬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','承明厭直懷鄉日，適得當年嚴助州。',64,'全唐诗/poet.song.36000.json','["承明厭直懷鄉日，適得當年嚴助州。", "况是北歸持節倦，喜聞東去典城優。", "長江風月消殘暑，故國蓴鱸近早秋。", "遥想下車民訟簡，不妨乘興剡溪遊。"]'),
('7385262d-e138-4486-8d21-2f80270ce700','史院席上奉和首相吳公元韵','曾孝寬','宋','宋诗','song-poetry','','[]','御府頒醇釀，君恩錫餕餘。',48,'全唐诗/poet.song.36000.json','["御府頒醇釀，君恩錫餕餘。", "賜筵遵故事，紬史重新書。", "燕飲難偕此，風流不偉歟。", "素餐非所職，愧附相君車。"]'),
('36bc340b-33e9-45a7-be35-fefedf226e88','送程給事知越州','章衡','宋','宋诗','song-poetry','','[]','雅留威愛在南昌，又拜新恩指舊棠。',64,'全唐诗/poet.song.36000.json','["雅留威愛在南昌，又拜新恩指舊棠。", "一節帝頒嚴使旆，十州人喜擁壺漿。", "彯纓自結凝旒眷，攬轡思澄插筆鄉。", "劉晏有材將大用，豫章樓上急飛觴。"]'),
('8908eabf-ad6c-46fa-b562-fd4d3241bf3e','南禪師圓寂日偈二首  其一','釋祖心','宋','宋诗','song-poetry','','[]','去年三月十有七，一夜春風撼籌室。',58,'全唐诗/poet.song.36000.json','["去年三月十有七，一夜春風撼籌室。", "三角麒麟入海中，空餘片月波心出。", "真不掩僞，曲不藏直。", "誰人爲和雪中吟，萬古知音是今日。"]'),
('d124b8cf-0a66-4420-8dd1-e375157d56fc','南禪師圓寂日偈二首  其二','釋祖心','宋','宋诗','song-poetry','','[]','昔人去時是今日，今日依前人不來。',72,'全唐诗/poet.song.36000.json','["昔人去時是今日，今日依前人不來。", "今既不來昔不往，白雲流水空悠哉。", "誰云秤尺平，直中還有曲。", "誰云物理齊，種麻還得粟。", "可憐馳逐天下人，六六元來三十六。"]'),
('206a445b-70d9-4764-b2e9-11e886a3538e','送吳恂','釋祖心','宋','宋诗','song-poetry','','[]','海門山嶮絕行蹤，踏斷牢關信已通。',32,'全唐诗/poet.song.36000.json','["海門山嶮絕行蹤，踏斷牢關信已通。", "自有太平基業在，不論南北與西東。"]'),
('ca3caf85-4b2a-4044-9c84-3743237fb980','初退黄龍院作','釋祖心','宋','宋诗','song-poetry','','[]','不住唐朝寺，閑爲宋地僧。',48,'全唐诗/poet.song.36000.json','["不住唐朝寺，閑爲宋地僧。", "生涯三事衲，故舊一枝藤。", "乞食隨緣過，逢山任意登。", "相逢莫相笑，不是嶺南能。"]'),
('9bcc136d-ac54-43d4-ade9-dcd34aa8d650','偈三首  其一','釋克文','宋','宋诗','song-poetry','','[]','雲門抽顧，自有來由。',20,'全唐诗/poet.song.36000.json','["雲門抽顧，自有來由。", "一點不到，休休休休。"]'),
('a21620a7-c3a1-4567-826c-08a4f5f7fa87','偈三首  其二','釋克文','宋','宋诗','song-poetry','','[]','先師昔住金輪日，有偈君家結凈緣。',32,'全唐诗/poet.song.36000.json','["先師昔住金輪日，有偈君家結凈緣。", "我住金輪還有偈，却應留與子孫傳。"]'),
('eb9c89c2-0621-4789-b4d3-043634ba77e5','偈三首  其三','釋克文','宋','宋诗','song-poetry','','[]','佛性天真事，誰云別有師。',48,'全唐诗/poet.song.36000.json','["佛性天真事，誰云別有師。", "罔明彈指處，女子出禪時。", "不費纖毫力，何曾動所思。", "衆生總平等，日用自多疑。"]'),
('8dc15c0d-6e56-4b6f-a227-aa5b1e811879','遺偈','釋克文','宋','宋诗','song-poetry','','[]','今年七十八，四大相離別。',24,'全唐诗/poet.song.36000.json','["今年七十八，四大相離別。", "火風既分散，臨行休更說。"]'),
('34d8d015-eabb-476c-8423-f43c901d7bae','偈','釋克文','宋','宋诗','song-poetry','','[]','諸佛出身處，東山水上行。',48,'全唐诗/poet.song.36000.json','["諸佛出身處，東山水上行。", "目前一彈指，變現自分明。", "日面月面過，佛手馿脚呈。", "皆承此恩力，言外度迷情。"]'),
('019b0742-f49a-41fa-855d-554994c03ea4','弔黄龍和尚塔','釋克文','宋','宋诗','song-poetry','','[]','示滅師何速，空遺塔此中。',48,'全唐诗/poet.song.36000.json','["示滅師何速，空遺塔此中。", "僧閑四海錫，誰復九年風。", "鳥外千峰遶，人間一徑通。", "寥寥朝與暮，唯有白雲同。"]'),
('1d768bc8-1cef-4495-a543-28843240accd','雲鶴','釋克文','宋','宋诗','song-poetry','','[]','旦過晚應宿，山堂任去留。',48,'全唐诗/poet.song.36000.json','["旦過晚應宿，山堂任去留。", "孤雲能自在，隻鶴更優游。", "楖栗開青眼，袈裟伴白頭。", "未明西祖意，萍迹謾悠悠。"]'),
('230a94a4-b8d7-4f83-87ba-6ec0b90e03f9','偈四首  其一','釋守智','宋','宋诗','song-poetry','','[]','緊峭離水靴，踏破湖湘月。',48,'全唐诗/poet.song.36000.json','["緊峭離水靴，踏破湖湘月。", "手把鐵蒺藜，打碎龍虎穴。", "翻身倒上樹，始見無生滅。", "却笑老瞿曇，彈指超彌勒。"]'),
('bfd10e09-f88b-44d5-8dbe-013dff063992','偈四首  其二','釋守智','宋','宋诗','song-poetry','','[]','昨日高山看釣魚，步行騎馬失却馿。',32,'全唐诗/poet.song.36000.json','["昨日高山看釣魚，步行騎馬失却馿。", "有人拾得駱駝去，重賞千金一也無。"]'),
('8d87110c-0069-45c5-a0cf-8674dde25831','偈四首  其三','釋守智','宋','宋诗','song-poetry','','[]','不離當處常湛然，覓即知君不可見。',32,'全唐诗/poet.song.36000.json','["不離當處常湛然，覓即知君不可見。", "雖然先聖恁麽道，且作箇模子搭却。"]'),
('9dd0a969-7a33-4f68-9901-364913e22573','偈四首  其四','釋守智','宋','宋诗','song-poetry','','[]','法門不幸法幢摧，五藴山中化作灰。',32,'全唐诗/poet.song.36000.json','["法門不幸法幢摧，五藴山中化作灰。", "昨夜泥牛通一線，黄龍從此入輪迴。"]'),
('19f36568-84a7-4901-a92d-a9cc0cf70cee','題清輝堂','劉宗孟','宋','宋诗','song-poetry','','[]','曙光倫紫翠，秋氣莫爭青。',48,'全唐诗/poet.song.36000.json','["曙光倫紫翠，秋氣莫爭青。", "山近嵐同潤，堂虛日共生。", "斷霞雲去接，夕照月來迎。", "翻想鮫人室，珠盤亦讓明。"]'),
('e623febf-bdd9-4003-a80d-2353583a939e','句  其一','劉宗孟','宋','宋诗','song-poetry','','[]','萬山攢地窄，四氣得春偏。',24,'全唐诗/poet.song.36000.json','["萬山攢地窄，四氣得春偏。", "分野侵秦壤，星河共楚天。"]'),
('403ce0bb-1c4f-4a08-8bde-3b5522b9e7f8','句  其二','劉宗孟','宋','宋诗','song-poetry','','[]','氣潤梅蒸雨，陰濃柳鬰煙。',24,'全唐诗/poet.song.36000.json','["氣潤梅蒸雨，陰濃柳鬰煙。", "夏深盧橘熟，花盡海棠妍。"]'),
('db0b64d2-19af-4d04-8064-6b459306bcd0','句','俞仲昌','宋','宋诗','song-poetry','','[]','白雲來去本無蹤，占定仙山四六峰。',16,'全唐诗/poet.song.36000.json','["白雲來去本無蹤，占定仙山四六峰。"]'),
('3aca64c0-7be7-478f-9318-fd829d2087aa','贈俞仲昌','李某','宋','宋诗','song-poetry','','[]','家對南山第一峰，誰知大隠隠松蓬。',64,'全唐诗/poet.song.36000.json','["家對南山第一峰，誰知大隠隠松蓬。", "閒身悟道持心得，俗事隨緣見性通。", "門外高居無俗客，篋中靈藥是陰功。", "年來更喜兒孫盛，俊筆香名紹素風。"]'),
('13e63c79-c620-4541-a950-49504fde6fa8','澹山巖','尹瞻','宋','宋诗','song-poetry','','[]','岌嶪元化精，嶄巖大塊坼。',48,'全唐诗/poet.song.36000.json','["岌嶪元化精，嶄巖大塊坼。", "駭若盤古時，呀然巨靈擘。", "狀怪嘔風雷，勢邈吞山澤。", "寒暑中外分，居僧甘窟宅。"]'),
('7ce4fc42-5bef-4773-983d-9edf7a975db3','火星巖','尹瞻','宋','宋诗','song-poetry','','[]','郡古時和諍訟銷，使君乘興忽相招。',64,'全唐诗/poet.song.36000.json','["郡古時和諍訟銷，使君乘興忽相招。", "畫船載妓游巖寺，紅旆摇風過野橋。", "就石開樽偎樹脚，撥雲策杖上山腰。", "鳴騶未許歸城去，更望寒林隔□遥。"]'),
('e57050fb-9924-4b1e-ab96-e09a22697635','火星巖聯句','尹瞻','宋','宋诗','song-poetry','','[]','千里熙醇政，靈巖嘉訪尋。',108,'全唐诗/poet.song.36000.json','["千里熙醇政，靈巖嘉訪尋。", "登亭雲擁坐，穿徑筍成林。", "樂逐天風遠，塵隨宿霧沉。", "綺羅紅作錦，冠蓋綠交陰。", "下顧關河小，寒知洞壑深。", "松枯存舊節，花老見初心。", "旌棨嵐光潤，樽罍野氣侵。", "自愧翁歸拙，難攀子厚吟。", "城樓傳暮角，南陌騎駸駸。"]'),
('17cb168f-e631-4c8b-9539-7e8b1670ccdb','句','邱與權','宋','宋诗','song-poetry','','[]','念往曾高枕。',6,'全唐诗/poet.song.36000.json','["念往曾高枕。"]'),
('05fa1e17-c36f-42bd-97cc-f397ec48ebff','夜宿垂虹亭舟中有感而作','龐元英','宋','宋诗','song-poetry','','[]','離家無數里，客思便侵凌。',48,'全唐诗/poet.song.36000.json','["離家無數里，客思便侵凌。", "久撥爐無力，頻翻被有稜。", "孤蟾如得伴，哀雁擬傷矰。", "怪底寒清冽，推篷露氣凝。"]'),
('8658257a-6083-4a4e-a223-8527434cbbe2','集句  其一','胡歸仁','宋','宋诗','song-poetry','','[]','一第知何日，無端意不移。',48,'全唐诗/poet.song.36000.json','["一第知何日，無端意不移。", "欲爲青桂主，誰與白雲期。", "傍架齊書帙，翻瓢作酒巵。", "文明終有托，休把運行推。"]'),
('0543bded-014b-4de1-b7b6-3b01a3bea7ce','集句  其二','胡歸仁','宋','宋诗','song-poetry','','[]','白沙溪繞白雲堆，但有何人把酒杯。',64,'全唐诗/poet.song.36000.json','["白沙溪繞白雲堆，但有何人把酒杯。", "專慕聖賢知志氣，可憐談笑出塵埃。", "碧山終日思無盡，清世難群好自猜。", "風滿老松門晝掩，可憐高尚仰天才。"]'),
('4150a4ec-c98a-4f78-b759-edb871e4197e','題傳舍','張唐英','宋','宋诗','song-poetry','','[]','先帝昭陵土未乾，又聞永厚葬衣冠。',32,'全唐诗/poet.song.36000.json','["先帝昭陵土未乾，又聞永厚葬衣冠。", "小臣有淚皆成血，忍向東風看牡丹。"]'),
('cb41d988-deb4-4550-869e-182c9a7deb0e','偈一首','張唐英','宋','宋诗','song-poetry','','[]','言生本不生，言滅本不滅。',24,'全唐诗/poet.song.36000.json','["言生本不生，言滅本不滅。", "覺路自分明，勿與迷者說。"]'),
('c1e0373b-cd74-4c68-be04-d8cf946f8b72','句','張唐英','宋','宋诗','song-poetry','','[]','西掖詞臣舊處游，南隆隠客敞廬幽。',16,'全唐诗/poet.song.36000.json','["西掖詞臣舊處游，南隆隠客敞廬幽。"]'),
('813b2c24-f27a-40fa-b0e7-2f7a11b28a2a','南澗月夕','俞紫芝','宋','宋诗','song-poetry','','[]','華髮念秋晚，青燈憐夜長。',48,'全唐诗/poet.song.36000.json','["華髮念秋晚，青燈憐夜長。", "香團菊花露，寒著橘林霜。", "月在北窗底，人行南澗傍。", "婆娑不知去，身世兩相忘。"]'),
('d9005a9f-44e8-45bb-96ea-d76deff361dd','旅中諭懷','俞紫芝','宋','宋诗','song-poetry','','[]','白浪紅塵二十春，就中奔走費光陰。',64,'全唐诗/poet.song.36000.json','["白浪紅塵二十春，就中奔走費光陰。", "有時俗事不稱意，無限好山都上心。", "一面琴爲方外友，數篇詩當橐中金。", "會須將爾同歸去，家在碧溪煙樹深。"]'),
('8863c7b2-b9a1-46ba-99d7-60562bbf6aee','歲杪山中','俞紫芝','宋','宋诗','song-poetry','','[]','石亂雲深客到稀，鶴和殘雪在高枝。',32,'全唐诗/poet.song.36000.json','["石亂雲深客到稀，鶴和殘雪在高枝。", "小軒日午貪濃睡，門外春風過不知。"]'),
('446f7025-1b0d-4fa0-b32b-8c7fb54a6aa2','咏草','俞紫芝','宋','宋诗','song-poetry','','["\u548f\u7269", "\u6292\u60c5", "\u690d\u7269", "\u548f\u7269\u8bd7"]','滿目芊芊野渡頭，不知若箇解忘憂。',64,'全唐诗/poet.song.36000.json','["滿目芊芊野渡頭，不知若箇解忘憂。", "細隨綠水侵離館，遠带斜陽過別洲。", "金谷園中荒映月，石頭城下碧連秋。", "行人悵望王孫去，買斷金釵十二愁。"]'),
('4794f9ee-b5f6-4809-8cb6-9949eb2d660c','宿蔣山棲霞寺','俞紫芝','宋','宋诗','song-poetry','','[]','獨坐清談久亦勞，碧松燃火暖衾袍。',32,'全唐诗/poet.song.36000.json','["獨坐清談久亦勞，碧松燃火暖衾袍。", "夜深童子喚不起，猛虎一聲山月高。"]'),
('a3a626c4-cfd7-42d8-ad1e-4cfa35ccd3d8','山中琴興','俞紫芝','宋','宋诗','song-poetry','','[]','野客調琴玉一枝，薰風滋味自家知。',32,'全唐诗/poet.song.36000.json','["野客調琴玉一枝，薰風滋味自家知。", "夜深斷送鶴先睡，彈到山空月落時。"]'),
('abf50079-3c4e-4d76-bd3d-f8981482ef78','無題','俞紫芝','宋','宋诗','song-poetry','','[]','深深盡陌倚朱門，腮粉輕紅濕淚痕。',32,'全唐诗/poet.song.36000.json','["深深盡陌倚朱門，腮粉輕紅濕淚痕。", "寂寞繡屏人未見，杏花疏雨立黄昏。"]'),
('ab63afec-9337-41cf-b40e-cc2089dea5cc','口占','俞紫芝','宋','宋诗','song-poetry','','[]','相君高卧朝天闕，立損階前白玉麟。',32,'全唐诗/poet.song.36000.json','["相君高卧朝天闕，立損階前白玉麟。", "此去定生獅子國，却來重載法王身。"]'),
('c70a277e-92bb-437e-bc06-64cd019cc461','松風','俞紫芝','宋','宋诗','song-poetry','','[]','萬壑摇蒼煙，百灘度流水。',24,'全唐诗/poet.song.36000.json','["萬壑摇蒼煙，百灘度流水。", "下有騎馿人，蕭蕭吹凍耳。"]'),
('21cf2dfd-c878-4e8f-bc2f-3e821855f685','戲作','俞紫芝','宋','宋诗','song-poetry','','[]','鬰鬰襟懷怨別離，鳳樓西角正斜暉。',32,'全唐诗/poet.song.36000.json','["鬰鬰襟懷怨別離，鳳樓西角正斜暉。", "洞房風細春華暖，落盡碧桃人未歸。"]'),
('719d6ec0-7722-4f69-b756-d2af589c4cae','寄杜宣卿長官','俞紫芝','宋','宋诗','song-poetry','','[]','長憶逢君歷水隅，坐中談笑見醇儒。',64,'全唐诗/poet.song.36000.json','["長憶逢君歷水隅，坐中談笑見醇儒。", "當年許我入詩社，別後有誰爲酒徒。", "頭想白如潘騎省，家應貧似范萊蕪。", "相思不可能相得，蟬老西風海樹枯。"]'),
('36fe9ca3-3042-442a-8db4-01b78edc70ae','水村','俞紫芝','宋','宋诗','song-poetry','','[]','畫橈兩兩枕汀沙，隔岸煙蕪一望賒。',64,'全唐诗/poet.song.36000.json','["畫橈兩兩枕汀沙，隔岸煙蕪一望賒。", "悲翠閒居眠藕葉，鷺鷥別業在蘆花。", "溪雲漠漠迷漁屋，野旆翻翻露酒家。", "一幅江南真水墨，無人寫得寄京華。"]'),
('432570e2-4f0f-4d63-b662-8fb6c07a2de3','秋閣晨興','俞紫芝','宋','宋诗','song-poetry','','[]','遠寺一聲鐘，簷楹驚宿鳥。',24,'全唐诗/poet.song.36000.json','["遠寺一聲鐘，簷楹驚宿鳥。", "拂衣風露清，月落千山曉。"]'),
('423cd415-1258-4a0c-8618-0eacd61c7e51','冬日','俞紫芝','宋','宋诗','song-poetry','','[]','茆舍竹籬短，梅花吐未齊。',24,'全唐诗/poet.song.36000.json','["茆舍竹籬短，梅花吐未齊。", "晚來溪徑側，雪壓小橋低。"]'),
('5cf48fba-60db-464e-a280-271d8ec393bd','吳興','俞紫芝','宋','宋诗','song-poetry','','[]','沽酒店穿斜巷出，採蓮船傍後門歸。',32,'全唐诗/poet.song.36000.json','["沽酒店穿斜巷出，採蓮船傍後門歸。", "翠霑城郭山千點，清蘸樓臺水一圍。"]'),
('a8e3845a-ecc0-4dd8-a3c9-fe7495233a4e','鍾山僧舍酬辟疆祕授','俞紫芝','宋','宋诗','song-poetry','','[]','同謁臨川丞相時，不期顔色偶然披。',64,'全唐诗/poet.song.36000.json','["同謁臨川丞相時，不期顔色偶然披。", "綠葵自得山人味，絳帳難求俗士知。", "午磬喚回幽枕夢，夕陽催就小窗詩。", "松毛桂葉山中路，肯顧非公復是誰。"]'),
('ecffb9a2-bdb9-4c53-802e-f24893cca489','句  其一','俞紫芝','宋','宋诗','song-poetry','','[]','莫怪野人經宿住，白蘋露落蟹螯肥。',16,'全唐诗/poet.song.36000.json','["莫怪野人經宿住，白蘋露落蟹螯肥。"]'),
('56a9be41-db1a-422a-ab05-80ea3efb934d','句  其二','俞紫芝','宋','宋诗','song-poetry','','[]','滿地榆錢逐曉風。',8,'全唐诗/poet.song.36000.json','["滿地榆錢逐曉風。"]'),
('7b614561-fa57-4f3a-a530-25719108ea14','句  其三','俞紫芝','宋','宋诗','song-poetry','','[]','月中疏影暗中香。',8,'全唐诗/poet.song.36000.json','["月中疏影暗中香。"]'),
('6370f438-e26e-4f1c-851e-f7d66ddeb0c6','瓊花','俞澹','宋','宋诗','song-poetry','','[]','因此瓊花發，維陽勝洛陽。',24,'全唐诗/poet.song.36000.json','["因此瓊花發，維陽勝洛陽。", "若無三月雨，占斷一春香。"]'),
('dfdde54b-bc02-46b9-9574-802fe26c5d8e','越山四見亭','劉瑾','宋','宋诗','song-poetry','','[]','山山能作雨，面面盡來峰。',24,'全唐诗/poet.song.36000.json','["山山能作雨，面面盡來峰。", "倚遍欄干曲，歸心曲曲同。"]'),
('d8e66f6f-0880-4a3a-a51f-0b7dce43558b','送程給事知越州','熊本','宋','宋诗','song-poetry','','[]','龍節頒新命，鸞臺輟侍臣。',108,'全唐诗/poet.song.36000.json','["龍節頒新命，鸞臺輟侍臣。", "詔開都督府，寄重老成人。", "四紀文章伯，三朝富貴身。", "指麾清劇部，談笑動殊鄰。", "麗正裁書久，承明厭直頻。", "銀黄鄉路晝，襦袴屬城春。", "冠蓋傾吳會，旌旗照海瀕。", "溪藤閒得句，雪舫夜留賓。", "夢想依青瑣，風流喜紫蓴。"]'),
('84fb9904-ff6c-4da3-9f5f-6acbec53212d','休休亭','樂沆','宋','宋诗','song-poetry','','[]','貽溪澄澈玉峰寒，居士當年此考槃。',64,'全唐诗/poet.song.36000.json','["貽溪澄澈玉峰寒，居士當年此考槃。", "訪得遺基青華下，構成危棟白雲端。", "人間日月雙輪轉，世外襟懷九鼎安。", "醉魄吟魂如未泯，也應謝我數盤桓。"]'),
('1db6420b-ed4b-4199-948c-c04aa8066484','送程給事知越州','王汾','宋','宋诗','song-poetry','','[]','名藩從古任惟良，况復深嚴瑣闥郎。',64,'全唐诗/poet.song.36000.json','["名藩從古任惟良，况復深嚴瑣闥郎。", "夕拜更持仙殿筆，晝歸仍綰會稽章。", "詩編豈愧微之富，杯酒應嗤賀監狂。", "惠政相承今邵杜，越人歌頌繼南陽。"]'),
('529fa9fe-56b1-4f7f-a04a-721dd4c9e072','題陸子泉','王汾','宋','宋诗','song-poetry','','[]','泉品舊知名，澄源石甃盈。',96,'全唐诗/poet.song.36000.json','["泉品舊知名，澄源石甃盈。", "甘滋飽僧飯，潤澤濟農耕。", "漱玉人誰聽，囊茶客自烹。", "久供鴻漸啜，曾奉贊皇羹。", "昨忝此邦守，令無諸縣行。", "煩酲想巖壑，一日慰幽情。", "慚怍方堆面，塵埃正滿纓。", "臨流聊洗濯，心已識蒙亨。"]'),
('ae70c1bc-c606-43a9-b027-1901f5147b89','詩一首','王汾','宋','宋诗','song-poetry','','[]','暫到靈巖頃刻間，籃輿還促度前山。',32,'全唐诗/poet.song.36000.json','["暫到靈巖頃刻間，籃輿還促度前山。", "我今吏役羞前輩，勝地逢僧不得閑。"]'),
('3abfd531-de9a-46dd-84b1-62c85abc224c','東臺山','王汾','宋','宋诗','song-poetry','','[]','誰謂前人不可攀，金杯泛菊且開顔。',32,'全唐诗/poet.song.36000.json','["誰謂前人不可攀，金杯泛菊且開顔。", "但知落帽臨風醉，未必龍山勝鳳山。"]'),
('53ec84de-45fd-4f0d-8d15-a0c72d61b372','松石峰','彭次雲','宋','宋诗','song-poetry','','[]','同登雲級上危巔，松石嶔崟掛晚烟。',32,'全唐诗/poet.song.36000.json','["同登雲級上危巔，松石嶔崟掛晚烟。", "好是回頭遥望處，海波如带石如拳。"]'),
('c8a8d9a9-4867-4ac7-8ece-834684ef7419','曾公巖和曾子宣安撫','彭次雲','宋','宋诗','song-poetry','','[]','目擊煙霞晝卷舒，披榛敲石得蓬壺。',64,'全唐诗/poet.song.36000.json','["目擊煙霞晝卷舒，披榛敲石得蓬壺。", "洞天日月千年久，人世塵埃一點無。", "靈藥難尋雲縹緲，落花不見水縈紆。", "使君鳳閣翱翔近，謾與東山作畫圖。"]'),
('ea364ae9-d40e-4cc7-87e0-542a1b2a9934','老君巖次劉誼韵  其一','彭次雲','宋','宋诗','song-poetry','','[]','仙馭凌雲去幾年，九流空苦道家言。',32,'全唐诗/poet.song.36000.json','["仙馭凌雲去幾年，九流空苦道家言。", "何人懷古求遺像，巖穴長蒙雨露恩。"]'),
('b00f6684-dea1-41ce-803a-3e295db7a951','老君巖次劉誼韵  其二','彭次雲','宋','宋诗','song-poetry','','[]','儼然鶴髮與龍顔，誰道乘風不復還。',32,'全唐诗/poet.song.36000.json','["儼然鶴髮與龍顔，誰道乘風不復還。", "渾俗何須窮變化，或來塵世或雲間。"]'),
('d3b56f97-2860-4aa7-a30d-43a4c9edb752','國清寺','蘇澥','宋','宋诗','song-poetry','','[]','自嗟靈骨久埋淪，惆悵當年舊事存。',32,'全唐诗/poet.song.36000.json','["自嗟靈骨久埋淪，惆悵當年舊事存。", "青眼重開蕭寺路，無人隔夜掃松門。"]'),
('824e933c-3a90-4cf4-b759-c5e04bd48ec0','大慈寺','蘇澥','宋','宋诗','song-poetry','','[]','身去寥寥無朕迹，此時誰會真消息。',32,'全唐诗/poet.song.36000.json','["身去寥寥無朕迹，此時誰會真消息。", "黄金靈骨今尚存，指示世人人不識。"]'),
('0033cda5-59cd-42be-9f09-91bab6115812','題石橋','蘇澥','宋','宋诗','song-poetry','','[]','連雲靄翠疊重重，直下雙溪擁霽虹。',64,'全唐诗/poet.song.36000.json','["連雲靄翠疊重重，直下雙溪擁霽虹。", "榮辱自分山色外，利名不到水聲中。", "清凉世界隨心現，方廣樓臺遂感通。", "願侍千僧共談麈，撥開陳障出樊籠。"]'),
('5beb4cee-f253-4179-9a05-b55fb62726f5','和簽判殿丞書仙臺觀壁','費琦','宋','宋诗','song-poetry','','[]','先生舊隠寄煙岑，丹竈仙臺暫訪尋。',32,'全唐诗/poet.song.36000.json','["先生舊隠寄煙岑，丹竈仙臺暫訪尋。", "自歎不如雞犬幸，偶霑靈藥換凡心。"]'),
('29e768aa-8cbe-4953-9a6f-7909ba8ed8f0','和簽判殿丞游山上一道觀三佛寺','費琦','宋','宋诗','song-poetry','','[]','巖扉相望路紆盤，杉檜風高夏亦寒。',32,'全唐诗/poet.song.36000.json','["巖扉相望路紆盤，杉檜風高夏亦寒。", "游遍陡忘名宦意，恨無生計可休官。"]'),
('e4a0c242-f45f-4d32-ae95-c6f402d58d39','和簽判殿丞寵示游山之作','費琦','宋','宋诗','song-poetry','','[]','平生癖愛林泉趣，名利縈人未許閒。',32,'全唐诗/poet.song.36000.json','["平生癖愛林泉趣，名利縈人未許閒。", "不是儒流霽風采，登山游騎恐難攀。"]'),
('10918873-6ea1-40d4-91b5-c76e3ddc0d3f','呈謝簽判殿丞寵示游山之作','費琦','宋','宋诗','song-poetry','','[]','夫君落筆盡珠璣，不比相如意思遲。',32,'全唐诗/poet.song.36000.json','["夫君落筆盡珠璣，不比相如意思遲。", "從此洛陽須紙貴，夜來新有愛山詩。"]'),
('d155fce7-2ad7-436e-991f-fe68e4267adc','送程給事知越州','程嗣弼','宋','宋诗','song-poetry','','[]','華宗晚貴派雖殊，別圃留詩敘舊娛。',64,'全唐诗/poet.song.36000.json','["華宗晚貴派雖殊，別圃留詩敘舊娛。", "導水决謀摧宦者，尊君抗禮屈單于。", "日疏賓閤容談麈，秋過家山好鱠鱸。", "宸眷許來應暮召，不須久計戀東吳。"]'),
('7f6ebe63-627c-42b8-8220-55ef9eab6478','送程給事知越州','沈季長','宋','宋诗','song-poetry','','[]','給事才名不記春，又麾雙旆越江濱。',64,'全唐诗/poet.song.36000.json','["給事才名不記春，又麾雙旆越江濱。", "厭看圖牒評句踐，慣把珪符笑買臣。", "身到遊舊心更喜，詩逢絕境語爭新。", "暫虛紫府雲間直，去與蓬萊作主人。"]'),
('d713c804-649f-4f28-893e-8d1995340e69','登驪山閣留詩','吳雍','宋','宋诗','song-poetry','','[]','山頭羯鼓奏霓裳，斷送君王入醉鄉。',32,'全唐诗/poet.song.36000.json','["山頭羯鼓奏霓裳，斷送君王入醉鄉。", "憑閣無言念興廢，孤煙猶起泰陵傍。"]'),
('a6ac6207-e700-4d40-8afd-95c4e2d40add','題司空表聖王官谷','王臨','宋','宋诗','song-poetry','','[]','夫君久逐夜舟移，依舊巖扃鎖翠微。',64,'全唐诗/poet.song.36000.json','["夫君久逐夜舟移，依舊巖扃鎖翠微。", "位至文昌還避世，身甘幽谷是知機。", "清風未泯隨流水，遺像空存伴落暉。", "百有餘年同俯仰，白雲猶繞故亭飛。"]'),
('34be64f7-6382-4ae0-b3a6-739a463c3d91','靈巖','王臨','宋','宋诗','song-poetry','','[]','瓶鉢飄然別帝鄉，法音從此振東方。',64,'全唐诗/poet.song.36000.json','["瓶鉢飄然別帝鄉，法音從此振東方。", "黄龍山下傳心印，白鶴泉邊起道場。", "甘露無時皆一味，旃檀何處不清香。", "煩師更唱宗門曲，兔脚龜毛任展張。"]'),
('55e0fedf-b3db-49a5-bfb2-2962b51310c0','遊春','楊繪','宋','宋诗','song-poetry','','[]','傾城追逐艷陽天，上巳清明節序連。',64,'全唐诗/poet.song.36000.json','["傾城追逐艷陽天，上巳清明節序連。", "桃李光陰足駘蕩，湖山風月更鮮妍。", "谷中答響飄新曲，波底妝光颺綵船。", "遲日未西人已醉，綠楊柔弱舞秋千。"]'),
('8e7b7bd5-56f4-4578-9410-5485477c0e69','劫權','楊繪','宋','宋诗','song-poetry','','[]','對敵常觀勢，臨機便得先。',48,'全唐诗/poet.song.36000.json','["對敵常觀勢，臨機便得先。", "安危心不動，殺活手能專。", "勿以欺爲行，須知劫是權。", "旁人爛柯看，當局是神仙。"]'),
('a69de026-fcf2-4916-a5e0-11f1367d0756','落花','楊繪','宋','宋诗','song-poetry','','[]','夜來經雨學啼妝，今日摧紅怨夕陽。',64,'全唐诗/poet.song.36000.json','["夜來經雨學啼妝，今日摧紅怨夕陽。", "已落旋隨春水急，强留還怯晚風狂。", "應將別恨憑鶑語，更把歸期趁蝶忙。", "誰謂多情消不得，夢魂猶惜滿欄香。"]'),
('3a3ce79d-2d6b-4895-ae81-32b91ecf006f','荷花借字詩','楊繪','宋','宋诗','song-poetry','','[]','香艷憐渠好，無端雜芰窠。',48,'全唐诗/poet.song.36000.json','["香艷憐渠好，無端雜芰窠。", "向來因藕斷，特地見絲多。", "實有終成的，露摇爭奈何。", "深房蓮底味，心裏苦相和。"]'),
('96d59a4e-5a68-47c1-8e92-5cd94350acd7','詩寄東坡','楊繪','宋','宋诗','song-poetry','','[]','仙舟游漾霅溪風，三奏琵琶一艦紅。',64,'全唐诗/poet.song.36000.json','["仙舟游漾霅溪風，三奏琵琶一艦紅。", "聞望喜傳新政異，夢魂猶憶舊歡同。", "二南籍裏知誰在，六客堂中已半空。", "細問人間爲宰相，爭如願住水晶宮。"]'),
('4c50ac9a-9255-4cde-90fa-c913655d8e1a','中秋月','楊繪','宋','宋诗','song-poetry','','[]','素月玉寒空，乾坤灝氣通。',48,'全唐诗/poet.song.36000.json','["素月玉寒空，乾坤灝氣通。", "光華一夕滿，節候九秋中。", "萬里天衢峻，四方人望同。", "妖邪無處匿，方顯照臨功。"]'),
('d4ad43a2-d5f7-47a7-b07d-225bfe1f7ea1','凌霄花','楊繪','宋','宋诗','song-poetry','','[]','直饒枝幹凌霄去，猶有根原與地平。',32,'全唐诗/poet.song.36000.json','["直饒枝幹凌霄去，猶有根原與地平。", "不道花依他樹發，强攀紅日鬭鮮明。"]'),
('281a29f7-9b26-4372-99ae-76148a7c07c3','柳花','楊繪','宋','宋诗','song-poetry','','[]','春光未老楊花飛，游子此情傷別離。',32,'全唐诗/poet.song.36000.json','["春光未老楊花飛，游子此情傷別離。", "扳折楊柳贈離別，駸駸匹馬歸何時。"]'),
('7fe04aaf-f697-4f01-a7c1-5502eb563e31','送淳用長老歸邛州','楊繪','宋','宋诗','song-poetry','','[]','曾扣禪扉喜接陪，師將境物諭輪迴。',64,'全唐诗/poet.song.36000.json','["曾扣禪扉喜接陪，師將境物諭輪迴。", "燈籠不滅心中火，香印空殘死後灰。", "綿邑難留真錫駐，臨邛還慶法堂開。", "臨邛綿邑何分別，無去無來無去來。"]'),
('64c3b479-5e49-43c9-b8c1-a272b562191c','壽山','楊繪','宋','宋诗','song-poetry','','[]','壽山北聳侵隋碧，溳水南流接漢清。',32,'全唐诗/poet.song.36000.json','["壽山北聳侵隋碧，溳水南流接漢清。", "宋玉陽臺猶暮雨，子虛夢澤半春耕。"]'),
('84193f5e-8cf7-461c-80b3-282d2acfa044','句  其一','楊繪','宋','宋诗','song-poetry','','[]','高驂黄鶴望天飛，千載誰能繼費禕。',16,'全唐诗/poet.song.36000.json','["高驂黄鶴望天飛，千載誰能繼費禕。"]'),
('ac4291fd-f981-4b60-b7e9-46dea116c7af','句  其二','楊繪','宋','宋诗','song-poetry','','[]','源有雌雄分碧白。',8,'全唐诗/poet.song.36000.json','["源有雌雄分碧白。"]'),
('206054f7-f5d7-4c2d-8ad9-bff0eaecbba6','句  其三','楊繪','宋','宋诗','song-poetry','','[]','清香舊已親陶令，紅艷新能惑阮郎。',16,'全唐诗/poet.song.36000.json','["清香舊已親陶令，紅艷新能惑阮郎。"]'),
('e09b1c97-f147-4e62-b0c6-59c69001c7df','句  其四','楊繪','宋','宋诗','song-poetry','','[]','何必口辭山簡醉，但教心似屈原醒。',16,'全唐诗/poet.song.36000.json','["何必口辭山簡醉，但教心似屈原醒。"]'),
('cde349d7-8aeb-4a66-98be-351561fc0350','句  其五','楊繪','宋','宋诗','song-poetry','','[]','爛紫妖紅色盡卑。',8,'全唐诗/poet.song.36000.json','["爛紫妖紅色盡卑。"]'),
('2a7a60bd-92c7-4555-b224-911834c8dc04','句  其六','楊繪','宋','宋诗','song-poetry','','[]','高唐神女蘭供澤，姑射仙人雪瑩肌。',16,'全唐诗/poet.song.36000.json','["高唐神女蘭供澤，姑射仙人雪瑩肌。"]'),
('757ca0e5-fe2b-4fae-9fde-ec10818c2a6d','句  其七','楊繪','宋','宋诗','song-poetry','','[]','朱欄明綠水，古柳照斜陽。',12,'全唐诗/poet.song.36000.json','["朱欄明綠水，古柳照斜陽。"]'),
('8bcdaa99-e3dd-4411-8f9f-747dee2032bb','解雨送神曲  其一','李常','宋','宋诗','song-poetry','','[]','怒風兮揚塵，日爍石兮將焚。',59,'全唐诗/poet.song.36000.json','["怒風兮揚塵，日爍石兮將焚。", "水泉竭兮厚地裂，嘉穀槁兮孰耨且耘。", "神龍兮靈壑，挹清波兮幽濆。", "鳴鼉鼓兮舞神覡，庶下鑒兮霈祥氛。"]'),
('437ca7ae-6e92-453b-889f-96ab287746d2','解雨送神曲  其二','李常','宋','宋诗','song-poetry','','[]','觸石兮山巔，倏四騖兮天邊。',59,'全唐诗/poet.song.36000.json','["觸石兮山巔，倏四騖兮天邊。", "驚霆怒兮電熾，翻河漢兮繩懸。", "黍離離兮發嘉，穗壠高下兮水潺湲。", "讙吾人兮拜貺，請奉事兮無有窮年。"]'),
('142608c8-434b-4cad-a72f-621de5342353','解雨送神曲  其三','李常','宋','宋诗','song-poetry','','[]','肅旂旆兮先驅，咽簫笳兮擁歸輿。',62,'全唐诗/poet.song.36000.json','["肅旂旆兮先驅，咽簫笳兮擁歸輿。", "椒醑甘兮牲幣潔，如肸蠁兮爲之躊躕。", "瞻前山兮嵯峨，指去路兮縈紆。", "神德大兮報無以稱，徒感涕兮長吁。"]'),
('a7f67a88-79f8-41c4-9ef8-a0481c55370d','醉眠亭','李常','宋','宋诗','song-poetry','','[]','陶公醉眠野中石，君醉輒眠舍後亭。',128,'全唐诗/poet.song.36000.json','["陶公醉眠野中石，君醉輒眠舍後亭。", "人知醉眠盡以酒，不知身醉心常醒。", "衆人清晨未嘗飲，已若醉夢心冥冥。", "淫名嗜利到窮老，有耳亦不聞雷霆。", "醉石雖頑委山側，苔昏日剝誰與扃。", "牧童樵叟亦能指，卒以陶令垂千齡。", "危簷弱棟倚荒渚，海霧江雨穿疏櫺。", "勿謂幽亭易摧折，勉事偉節同明星。"]'),
('058fc0eb-4586-49c6-b071-cd7dfe5f051b','題招提院靜照堂','李常','宋','宋诗','song-poetry','','[]','藻戶面通漕，飛甍出重城。',120,'全唐诗/poet.song.36000.json','["藻戶面通漕，飛甍出重城。", "堂成未遑息，復作千里行。", "塵埃袖短褐，蒙暑踏寒冰。", "其求異求食，志欲詩編盈。", "寧辭閽吏慢，聊爲一堂榮。", "都城競名利，日出車馬聲。", "誰云方外士，奔走亦有營。", "惟靜制衆動，自照中乃明。", "胡爲撓山水，風急帆更輕。", "歲闌去勿緩，恐負新堂名。"]'),
('5b1845c0-477f-4dd7-9414-ce795dbc857f','句','李常','宋','宋诗','song-poetry','','[]','皖公山下開軒處，坐聽龍吟十里長。',16,'全唐诗/poet.song.36000.json','["皖公山下開軒處，坐聽龍吟十里長。"]'),
('dac8172d-8f42-41ed-8760-b1d001b7258a','題有美堂','賈收','宋','宋诗','song-poetry','','[]','自刊宸畫入雲端，神物應須護翠巒。',64,'全唐诗/poet.song.36000.json','["自刊宸畫入雲端，神物應須護翠巒。", "吳越不藏千里色，斗牛常占一天寒。", "四簷望盡回頭嬾，萬象搜來下筆難。", "誰信靜中疏拙意，略無蹤跡到波瀾。"]'),
('dc10f00e-7c2d-4337-916e-e8220714513c','送友人赴天台幕','賈收','宋','宋诗','song-poetry','','[]','天台仙籍上，又見姓劉人。',48,'全唐诗/poet.song.36000.json','["天台仙籍上，又見姓劉人。", "入幕紅蓮曉，趨庭彩服春。", "魚多知海熟，藥少覺山貧。", "太守鄉儒丈，何妨婉畫頻。"]'),
('598935f2-364c-46c4-a00d-565fcaf1e95c','和沈君與送蟹','賈收','宋','宋诗','song-poetry','','[]','彭越孫多伏下風，蝤蛑奴視敢稱雄。',64,'全唐诗/poet.song.36000.json','["彭越孫多伏下風，蝤蛑奴視敢稱雄。", "江湖縱養膏腴紫，鼎鑊終烹爪眼紅。", "嗍稱吳兒牙似鍍，劈慚湖女手如葱。", "獨憐盤內秋臍實，不比溪邊夏殻空。"]'),
('5d48a967-05cf-42c8-925d-975d0870862e','具區閣','賈收','宋','宋诗','song-poetry','','[]','軒窗塵不點，更在水雲邊。',48,'全唐诗/poet.song.36000.json','["軒窗塵不點，更在水雲邊。", "夜月鳴榔地，秋風斫鱠天。", "達人多傲世，清景易忘年。", "往往憑欄者，空高張翰賢。"]'),
('3e41d3ac-aae4-463d-a5db-01c692c94dce','句','賈收','宋','宋诗','song-poetry','','[]','洄洄流水抱橫塘，蘭芷無風也自香。',16,'全唐诗/poet.song.36000.json','["洄洄流水抱橫塘，蘭芷無風也自香。"]'),
('aa1ccb04-f082-4824-869d-1703455ed944','頌','釋法秀','宋','宋诗','song-poetry','','[]','誰能一日三梳頭，撮得根牢髻便休。',32,'全唐诗/poet.song.36000.json','["誰能一日三梳頭，撮得根牢髻便休。", "大抵是他肌骨好，不施紅粉也風流。"]'),
('ddf5f0f6-7a1b-4965-b95f-9971b89d2e52','偈四首  其一','釋法秀','宋','宋诗','song-poetry','','[]','山僧不會巧說，大都應箇時節。',44,'全唐诗/poet.song.36000.json','["山僧不會巧說，大都應箇時節。", "相喚喫椀茶湯，亦無祖師妙訣。", "禪人若也未相諳，踏著秤鎚硬似鐵。"]'),
('fe24cfcb-9b84-4862-862e-5f2829103cfc','偈四首  其二','釋法秀','宋','宋诗','song-poetry','','[]','秋雲秋水，看山滿目。',20,'全唐诗/poet.song.36000.json','["秋雲秋水，看山滿目。", "這裏明得，千足萬足。"]'),
('a6af3d92-f3bd-4d3f-9b61-4da3b36fe457','偈四首  其三','釋法秀','宋','宋诗','song-poetry','','[]','寒雨細，朔風高。',18,'全唐诗/poet.song.36000.json','["寒雨細，朔風高。", "吹沙走石，拔木鳴條。"]'),
('210e082c-1d3f-4c21-8fcd-dfaa60f623da','偈四首  其四','釋法秀','宋','宋诗','song-poetry','','[]','少林九年冷坐，却被神光覷破。',28,'全唐诗/poet.song.36000.json','["少林九年冷坐，却被神光覷破。", "如今玉石難分，祇得麻纏紙裹。"]'),
('53c46bb0-8295-4198-8e8e-e69633f53d86','送僧遊嘉禾','釋法秀','宋','宋诗','song-poetry','','[]','楚天西首路，槜李記曾遊。',48,'全唐诗/poet.song.36000.json','["楚天西首路，槜李記曾遊。", "店宿燈懸夢，隄行草喚愁。", "玉澄湖水曉，畫展囿亭秋。", "小艇枯楊趾，重來爲繫留。"]'),
('8966aaf2-f928-40b6-96a9-762262eabfcc','春帖子','鄧潤甫','宋','宋诗','song-poetry','','[]','晨曦瀲灧上簾櫳，金屋熙熙歌吹中。',32,'全唐诗/poet.song.36000.json','["晨曦瀲灧上簾櫳，金屋熙熙歌吹中。", "桃臉似知宮宴早，百花頭上放輕紅。"]'),
('4a8fe255-cd52-4cbd-8305-c2f6663c2083','送黄守解印','鄧潤甫','宋','宋诗','song-poetry','','[]','文雅登臨謝守才，愛山今作別山來。',32,'全唐诗/poet.song.36000.json','["文雅登臨謝守才，愛山今作別山來。", "知公未厭真仙境，早擁江南使節來。"]'),
('eb527e24-f27a-461e-b5cc-83883a0381b3','詩一首','鄧潤甫','宋','宋诗','song-poetry','','[]','聞說東南第一州，區區來訪小蓬丘。',32,'全唐诗/poet.song.36000.json','["聞說東南第一州，區區來訪小蓬丘。", "湖光带日黄金擁，山色凝烟碧玉浮。"]'),
('a9973642-19b4-41d9-ba70-d3bf8f91f94e','道中詠懷奉寄利州馮允南使君','鄧潤甫','宋','宋诗','song-poetry','','[]','交印夔人國，分襟汴水隄。',288,'全唐诗/poet.song.36000.json','["交印夔人國，分襟汴水隄。", "十年難會合，一夢頓乖暌。", "官序潘生拙，詩文庾信齊。", "諸公多汲引，憲府屢提携。", "不肯乘驄馬，那能出寶雞。", "安恬輕世味，灑落見天倪。", "照物聰明决，爲邦聞望躋。", "笑談清岸獄，暇豫勸耕犁。", "不忍爲鉤距，何嘗設町畦。", "燕堂傳夜燭，遊轂碾春泥。", "衆服題鸚鵡，疇將食駃騠。", "草黄思隼擊，梧碧值鸞棲。", "欲問無來使，開編有舊題。", "君方安玉壘，予亦遠金閨。", "地隔江波闊，書傳鳥翼稽。", "豈知雙鬢白，相見兩當西。", "內顧微他技，殊私牧遠黎。", "辭親愁不斷，叱馭意空迷。", "吳苑飛雲杳，春城北斗低。", "南山千里雪，劍閣萬盤溪。", "夜宿星邊驛，朝行石上谿。", "深疑窺地軸，高駭躡天梯。", "看岫時欹帽，聽泉或杖藜。", "蕭蕭黄葉下，裊裊冷猿啼。"]'),
('b2f93043-18d6-48f0-a191-b419f227610d','句  其一','鄧潤甫','宋','宋诗','song-poetry','','[]','武昌山水誠佳哉，當年五柳親栽培。',32,'全唐诗/poet.song.36000.json','["武昌山水誠佳哉，當年五柳親栽培。", "家家開門枕江水，春風照耀桃與梅。"]'),
('7a003e70-5571-48a7-af6f-7e2946dde29a','句  其二','鄧潤甫','宋','宋诗','song-poetry','','[]','妙論出六合，微言破九流。',12,'全唐诗/poet.song.36000.json','["妙論出六合，微言破九流。"]'),
('ba419473-7acd-492e-aa82-e4a29dfea595','句  其三','鄧潤甫','宋','宋诗','song-poetry','','[]','自有嫣然態，風前欲笑人。',24,'全唐诗/poet.song.36000.json','["自有嫣然態，風前欲笑人。", "涓涓朝泣露，盎盎夜生香。"]'),
('e68dabea-5310-4165-9157-2de9d9646e18','江瀆泛舟次吳中復韵','韓宗道','宋','宋诗','song-poetry','','[]','綠錦池塘藻荇芳，拏舟清泛水風凉。',64,'全唐诗/poet.song.36000.json','["綠錦池塘藻荇芳，拏舟清泛水風凉。", "千珠翠颭圓荷雨，百和交銷寶篆香。", "暫駐旌麾開燕豆，只憑談笑樂杯觴。", "留連晚景殊多適，無奈黄昏送夕陽。"]'),
('942b7b7b-ad3c-45c6-b355-298499bb7258','又和謝景初韵','韓宗道','宋','宋诗','song-poetry','','[]','萧洒叢祠古道旁，偶來乘興興何長。',64,'全唐诗/poet.song.36000.json','["萧洒叢祠古道旁，偶來乘興興何長。", "珊珊翠竹寒成韵，苒苒紅蕖細度香。", "雲暗塵頭雲雨急，風來水面葛衣凉。", "天涯一笑良難得，預借驪歌送別觴。"]'),
('41686f25-4a5c-4708-84cb-783a51b0c2f2','和吳中復游海雲寺','韓宗道','宋','宋诗','song-poetry','','[]','茂林修竹翠煙收，寺枕清江江上頭。',64,'全唐诗/poet.song.36000.json','["茂林修竹翠煙收，寺枕清江江上頭。", "好馬啼春知客恨，落花浮水近人流。", "政閒不廢登臨賞，意適真成汗漫遊。", "紫陌紅塵歸路遠，夕陽回首重遲留。"]'),
('facbc808-0d0d-496d-98b6-bb9d6538f4c6','和母同州丁巳吟','呂大防','宋','宋诗','song-poetry','','[]','行高名並美，命否數皆殂。',72,'全唐诗/poet.song.36000.json','["行高名並美，命否數皆殂。", "嗟爾百君子，賢哉二丈夫。", "世方敦薄俗，誰復距虛無。", "望道咸瞠若，脩梁遽壞乎。", "密章燔漢綬，環絰泣秦儒。", "頼有諸良友，能令紹不孤。"]'),
('2d9aba52-a975-4bcf-95a5-bc0553b22933','飛赴山','呂大防','宋','宋诗','song-poetry','','[]','最勝西峰下，林梢四望亭。',24,'全唐诗/poet.song.36000.json','["最勝西峰下，林梢四望亭。", "江山觀掌握，梁益布丹青。"]'),
('0a5f16c6-6710-4297-a479-9eec2047a086','西園辨蘭亭','呂大防','宋','宋诗','song-poetry','','[]','手種叢蘭對小亭，辛勤爲訪正嘉名。',64,'全唐诗/poet.song.36000.json','["手種叢蘭對小亭，辛勤爲訪正嘉名。", "終身佩服騷人宅，舉國傳香楚子城。", "削玉紫芽凌臘雪，貫珠紅露綴春英。", "若非郢客相開示，幾被方言誤一生。"]'),
('8061644b-6688-49fd-bb23-747cabecefc5','萬里橋','呂大防','宋','宋诗','song-poetry','','[]','萬里橋西萬里亭，錦江春漲與隄平。',32,'全唐诗/poet.song.36000.json','["萬里橋西萬里亭，錦江春漲與隄平。", "拏舟直入修篁裏，坐聽風湍澈骨清。"]'),
('592e69c0-dc4c-4109-bedb-681e6c72a102','送朱壽昌迎母東歸','呂大防','宋','宋诗','song-poetry','','[]','去年謫守豫章南，楚岸方舟鷁首銜。',64,'全唐诗/poet.song.36000.json','["去年謫守豫章南，楚岸方舟鷁首銜。", "君便得親誇綵服，我方違養苦征帆。", "春來重到青山郭，膝下同榮□綺衫。", "尤愛中條更相類，板輿時可到西巖。"]'),
('1041f746-2138-41e5-9a96-5f214bcdb324','幸太學倡和','呂大防','宋','宋诗','song-poetry','','[]','清曉金輿出建章，祠宮轉仗指虞庠。',64,'全唐诗/poet.song.36000.json','["清曉金輿出建章，祠宮轉仗指虞庠。", "三千逢掖裾如雪，十萬勾陳錦作行。", "再拜新儀瞻魯聖，一篇古訓贊周王。", "崇儒盛世無云補，扈蹕空慚集論堂。"]'),
('91d227f2-125b-482f-80ca-053d285704b2','句  其一','呂大防','宋','宋诗','song-poetry','','[]','天倉三十六，寒擁翠微宮。',12,'全唐诗/poet.song.36000.json','["天倉三十六，寒擁翠微宮。"]'),
('b6d075b3-ef5b-4fc1-a8bf-2b01469b9425','句  其二','呂大防','宋','宋诗','song-poetry','','[]','巖暉萬古照，泉漏六時飛。',12,'全唐诗/poet.song.36000.json','["巖暉萬古照，泉漏六時飛。"]'),
('48261bd6-84fb-444b-8ae6-344de8cfea60','句  其三','呂大防','宋','宋诗','song-poetry','','[]','樹向仙山老，枝經漢水燔。',12,'全唐诗/poet.song.36000.json','["樹向仙山老，枝經漢水燔。"]'),
('37149959-6800-4d2a-9f5b-1795b290b3ed','夜過吳江憶華終之','呂寅伯','宋','宋诗','song-poetry','','[]','更深既盡燭，清氣滿山川。',48,'全唐诗/poet.song.36000.json','["更深既盡燭，清氣滿山川。", "沙上風鷗聚，烟中霜草鮮。", "故人別何處，新月照孤眠。", "欲寄相思意，征鴻未可傳。"]'),
('96b3ae2f-47ed-4cdd-9173-8a2f887283e5','北遊寄崔象之','范純仁','宋','宋诗','song-poetry','','[]','塵埃都門路，羸馬復北首。',168,'全唐诗/poet.song.36000.json','["塵埃都門路，羸馬復北首。", "徘徊孤客心，厭此行役久。", "秋雲結層陰，風葉下高柳。", "解鞍止孤館，斜雨入戶牖。", "愁懷寫長川，時運付杯酒。", "回念宇宙間，無一真我有。", "功名聖賢事，世味俗自厚。", "行心弗愧天，安俟傳不朽。", "偶爲細故牽，還成浪奔走。", "矧庇吾族繁，折腰仰五斗。", "營營百年內，此累難遽否。", "田廬儻其完，尚可歸老醜。", "人事固莫定，此志誠不苟。", "誦言成短章，聊以告吾友。"]'),
('c1741083-260d-4b4e-95de-6a95e8af0e98','寄謝師直','范純仁','宋','宋诗','song-poetry','','[]','去夏謁君時，踏雨溵川路。',108,'全唐诗/poet.song.36000.json','["去夏謁君時，踏雨溵川路。", "癯然泣相弔，心苦別亦遽。", "窮愁但急急，崢嶸歲還暮。", "羈旅念友朋，天寒感霜露。", "孤懷雜離憂，紛亂疇可訴。", "計我之官期，迨君祥琴御。", "邑館臨通途，車馬當迎遻。", "言笑釋所願，此喜良可預。", "欲致情抱勤，音書豈能敘。"]'),
('71b48df9-2758-459d-851d-b757afd2486c','陳東父示及新文','范純仁','宋','宋诗','song-poetry','','[]','世德鍾良士，爽氣橫清秋。',120,'全唐诗/poet.song.36000.json','["世德鍾良士，爽氣橫清秋。", "公才輔經術，文價伏時流。", "近從計廷召，斬爲梁苑遊。", "京都利名地，趨謁先公侯。", "高情遠俗尚，壯麗資冥搜。", "清尊破旅顔，黄菊迎歸舟。", "佳藻盈大軸，遺我蠲窮愁。", "正聲和群心，明珠炫雙眸。", "詞高不可繼，惠重終可酬。", "愧君樂善懷，行義愚當脩。"]'),
('474e685b-a71c-4347-9394-7e5543a89a07','休心亭','范純仁','宋','宋诗','song-poetry','','[]','吾友明知士，結廬汝水邊。',168,'全唐诗/poet.song.36000.json','["吾友明知士，結廬汝水邊。", "名亭號休心，休心師昔賢。", "將期一寸誠，悠久如青天。", "我聞人最靈，至性初純全。", "吉凶以情變，善惡緣習遷。", "湍水决其防，放蕩無由還。", "所以古聖師，三絕窮韋編。", "曾子善守約，孟軻養浩然。", "皆能保誠明，千載光華傳。", "夫君真其徒，墳史尤精研。", "恬然安粹靈，外慮何由牽。", "進退固有道，用舍豈必專。", "丘疾不俟禱，顔樂無窮年。", "寧同避俗者，身迹空拘攣。"]'),
('cd8322ef-e2c8-41bd-a68a-7a93b9d269bd','累約舍弟純禮以職事未至','范純仁','宋','宋诗','song-poetry','','[]','落葉猶同飛，寒鳥猶竝枝。',204,'全唐诗/poet.song.36000.json','["落葉猶同飛，寒鳥猶竝枝。", "我汝獨何負，不得長相隨。", "偶爲細累拘，跬步成天涯。", "後日更遠適，會合信難期。", "尚願家國寧，且作千日離。", "悠悠百年間，幾別顔即衰。", "從宦非我志，功名徒自欺。", "誰言干寸祿，坐使手足違。", "逐末背本心，得一萬已遺。", "我汝粗有識，此事良同悲。", "安得長洲田，清水稻百畦。", "將汝入故廬，親戚坐成圍。", "幼弟就文史，長兄近砭醫。", "孝謹奉諸宗，祭祀潔四時。", "此外逐風月，對酌白酒巵。", "畢世爲善人，不負生育慈。", "斯志儻未遂，終爲路人嗤。"]'),
('feb0deea-517c-45a7-b99f-52e2461587f1','會師宰','范純仁','宋','宋诗','song-poetry','','[]','憶昨相逢際，風喧洛城春。',252,'全唐诗/poet.song.36000.json','["憶昨相逢際，風喧洛城春。", "芳菲供愁眼，衣袂偕京塵。", "艱難各之適，會合寧逡巡。", "君歸來何時，我約赴無因。", "自此還相望，渴臆生埃塵。", "晚歲留故丘，山村寂無鄰。", "落日送樵牧，蒼烟起荆榛。", "季弟自城至，開顔慰天倫。", "遽言長者車，相過止來晨。", "茲遇出意表，俟迎屢冠巾。", "寒途馬歷歷，幽扉犬狺狺。", "野夫競走報，似能喜佳賓。", "空堂揖顔色，和氣相氤氳。", "開尊共燈燭，笑語何諄諄。", "朝遊禹門寺，暮歷清伊濱。", "危龕儼金像，遠波舒翠鱗。", "石樓最清絕，就宿同禂茵。", "灘聲夜逾急，天然謝韶鈞。", "閒淡盡物理，至樂還天真。", "人生足羈束，此會尤難頻。", "所期道義心，白首長相親。"]'),
('9b7f77e9-498a-4639-94c7-aa78da39c7ea','久雨','范純仁','宋','宋诗','song-poetry','','[]','季夏德陽盛，炎赫恢洪鑪。',252,'全唐诗/poet.song.36000.json','["季夏德陽盛，炎赫恢洪鑪。", "俄然積陰來，直掩造化樞。", "蒸雲滿乾坤，澍雨傾江湖。", "晝夜不停灑，動植寧得蘇。", "深虞墊地軸，遂恐沈日車。", "火官弛權綱，朱鳥憂沾濡。", "薰風阜民物，反逢怒飈驅。", "川盈浩無津，龍卧埋深淤。", "晦霧擁城門，驚瀾起康衢。", "雖經禹力勤，尚畏赤子魚。", "叢蘭委泥滓，祥木掩蒿蕪。", "罅漏生廣厦，浸淫矧吾廬。", "澀蘚上明鏡，蠹腐盈縑書。", "牆茨漸衣繡，網蟲競纓珠。", "螺蚓恣緣繞，蛙黽爭讙呼。", "幽人志自苦，陰處情難舒。", "憂頹詎安席，避溺思乘桴。", "安得赤帝悟，却使政令敷。", "盡屏沴祲昏，大明升震隅。", "六合仰清光，九州免淪胥。", "四序各有主，一物長歡娛。"]'),
('d6d34f60-c45b-4973-88c4-1ac158b12e70','道旁柵','范純仁','宋','宋诗','song-poetry','','[]','鱗鱗田邊柵，意欲全嘉禾。',72,'全唐诗/poet.song.36000.json','["鱗鱗田邊柵，意欲全嘉禾。", "不念大道隳，輪蹄苦難過。", "還來踐旁畝，害稼良愈多。", "願以樹柵心，治道夷險坡。", "行子得坦途，羈旅遠詆訶。", "芃芃滿隴翠，誰冒蹊田科。"]'),
('6fe030c6-cd2d-44f0-a434-3143b699da62','游渶川石橋','范純仁','宋','宋诗','song-poetry','','[]','英山富泉石，翠巖映清漣。',288,'全唐诗/poet.song.36000.json','["英山富泉石，翠巖映清漣。", "近可杖屨及，寂無市井喧。", "良辰惜虛過，幽尋忍空還。", "幸接鴻雁序，愧在驊騮前。", "一徑入嵐靄，遍野皆蘭荃。", "洗耳慕潁曲，散髮非伊川。", "芳意動宿楚，暖脈通幽泉。", "遥源發何所，積流浩成淵。", "斷岸矗蒼壁，澄瀛印晴天。", "人稀石有彴，村遠魚無筌。", "初開臘甕酒，乍減春衣綿。", "風光入雩詠，暄和臨禁煙。", "柔莎當茵席，輕漪泛觥船。", "天日正清潤，水雲共澄鮮。", "靈苗恣采擷，古跡皆窮研。", "高會屏紛雜，野具無葷羶。", "繁英落如糝，幽禽語如絃。", "嫩香小杏肥，深碧新荷圓。", "游鯈忽上下，戲蝶時翩翾。", "芳樹蔭坐釣，平石醒醉眠。", "共得真隠趣，勿爲豪華傳。", "滿目是圖畫，在處皆潺湲。", "春風拂歸袂，暮景生吟鞭。", "恨不見山月，月曉山南邊。"]'),
('e8af7222-f700-4459-8e76-ea342ce7971a','暑雨','范純仁','宋','宋诗','song-poetry','','[]','暑候積隆暵，驕陽變重陰。',239,'全唐诗/poet.song.36000.json','["暑候積隆暵，驕陽變重陰。", "朱靈弛綱權，蒸鬰資霖淫。", "驚聲遞洶洶，密脚羅森森。", "階除垂玉霤，朝暮無停音。", "脩虹掛明带，奔雲仆危岑。", "雷電收震耀，曦光久潛沈。", "老火不復炎，飈迓柔金。", "大道瀉溪壑，窮巷多汙涔。", "朝泥涴羸屐，夜氣凌疏衾。", "腐耳帖朱檻，美實墮青林。", "蛙黽生意氣，螻蚓相謳吟。", "嘉穀失耘耨，坐忍萊莠侵。", "白屋生罅漏，工女停機紝。", "庭圃亦蕪蔓，誰能辨藁芩。", "長夏方長養，漸漬所不禁。", "伊予抱最靈，咨戚何由愔。", "安得排九閽，感激露至忱。", "訴帝求陽明，咄嗟破凝膁。", "薰風阜萬物，復將歌舜琴。", "天高不可達，耿耿徒此心。"]'),
('9d298f41-5cac-4fe5-9e7b-ff28158682f6','寄友人','范純仁','宋','宋诗','song-poetry','','[]','時君養多士，本欲康生民。',96,'全唐诗/poet.song.36000.json','["時君養多士，本欲康生民。", "服章與奉祿，豈但榮其身。", "士昔志於學，寧曰利欲親。", "得位以行道，脩己將安人。", "夫君青雲姿，文行尤彬彬。", "明主親選士，往作諸侯賓。", "茲義雅所尚，有懷竝松筠。", "當令千載間，炯炯尊儒紳。"]'),
('7467a88c-4769-4893-8814-ffcac668ec4b','謁辛化光','范純仁','宋','宋诗','song-poetry','','[]','濃陰結秋意，疏林嘯松聲。',144,'全唐诗/poet.song.36000.json','["濃陰結秋意，疏林嘯松聲。", "時節感壯懷，挈酒慰友生。", "友生冰玉士，節行映古清。", "十五簪儒冠，四十無華纓。", "家貧道彌富，身困譽益榮。", "殷勤數賓侶，足趨顔巷輕。", "高齋面幽圃，脩筠擁軒楹。", "班班寒露叢，竟吐籬下英。", "食具簡且潔，盤蔬亦晶明。", "飲適言笑和，至樂不亂情。", "郁然蘭芷芬，薰灼通心誠。", "因嗟朝市間，利欲空自兵。"]'),
('fed1f25f-4348-4149-af8f-3e94c159570f','留別洛中諸友','范純仁','宋','宋诗','song-poetry','','[]','少孤多旅遊，解驂幸吾里。',48,'全唐诗/poet.song.36000.json','["少孤多旅遊，解驂幸吾里。", "親友皆賢豪，相逢有餘喜。", "世事如浮雲，離合寧暫止。", "酒罷予其東，幽蹤逐伊水。"]'),
('e7ec1a2c-dbc4-46d8-b425-a71a145aedac','同成都尹吳仲庶運判韓持正會飲','范純仁','宋','宋诗','song-poetry','','[]','宦遊鮮寧居，未定即奔走。',168,'全唐诗/poet.song.36000.json','["宦遊鮮寧居，未定即奔走。", "踰年官岷峨，較昔已云久。", "所喜風物繁，聯職多舊友。", "平生道義心，相期各白首。", "公餘事招尋，談笑共尊酒。", "時方積雨歇，凉氣生戶牖。", "紅蘂照平池，蒼烟羃高柳。", "清歡正蕭散，離思已紛糾。", "後遇復何鄉，此樂能再不。", "念初撫遐氓，力薄顔亦厚。", "飽歷風波危，僅脫虎狼口。", "何當掛塵冠，杖屨醉林藪。", "俯仰適所願，榮利亦何有。", "世故浩難必，逍遥慕莊叟。"]'),
('2f138ff2-9441-40ec-b090-309310a40f82','寄趙大觀度支','范純仁','宋','宋诗','song-poetry','','[]','上天生賢傑，有意康斯民。',264,'全唐诗/poet.song.36000.json','["上天生賢傑，有意康斯民。", "六十不大用，徒勞何足云。", "堂堂趙夫子，德與往哲鄰。", "嘗冠獬豸冠，血面嬰龍鱗。", "身輕秋葉危，大典虞湮淪。", "予時忝同僚，附驥願亦伸。", "自爾均出處，荏苒十四春。", "不肖罷蜀使，迂謬衆所髕。", "君獨憐其心，撫勞意益親。", "特枉廉按車，再宿驂行塵。", "愧無管氏才，蒙此鮑叔仁。", "蒼皇摻袂去，分老江湖濱。", "前年易邊麾，揖君東都門。", "君方領部使，迎遇謂可頻。", "不作旬浹別，各走西征輪。", "後前數舍間，音旨徒相聞。", "到官但引領，莫覿綦與巾。", "道大果難合，稅冕寧逡巡。", "投劾勇自丐，就養歸丘樊。", "君志固爲得，我懷誰與論。", "命駕適千里，茲義古所敦。", "有守念繫匏，空望南山雲。"]'),
('8d143e79-c4fa-4375-8a5e-96d4afcc1e63','秋意','范純仁','宋','宋诗','song-poetry','','[]','日躔回南陸，炎氣徹厚地。',72,'全唐诗/poet.song.36000.json','["日躔回南陸，炎氣徹厚地。", "鬰蒸堆火雲，飄雨良快意。", "闇穴蟪蛄鳴，濕翼玄蟬墜。", "潛陰生早凉，熇暑不得熾。", "羈懷感時節，撫事增愁思。", "倦遊老將至，歸興勞夢寐。"]'),
('49b5c008-3141-4cd2-9422-173e9a1d7914','題楊希元朝議南軒','范純仁','宋','宋诗','song-poetry','','[]','卜居俯澗瀍，開軒面嵩洛。',156,'全唐诗/poet.song.36000.json','["卜居俯澗瀍，開軒面嵩洛。", "迥占西都勝，高據北邙脚。", "千門凝紫烟，群峰參碧落。", "神臯勢回抱，天闕誰開鑿。", "朝陽麗金碧，半空橫殿閣。", "灘聲夜潺湲，雲氣暮慘錯。", "春花敷爛錦，夏木成翠幄。", "三川披畫圖，八極開綷幕。", "曾無登涉勤，坐享仁智樂。", "主人富才識，大隠當城郭。", "早解郡印還，勇脫官檢縛。", "清心對萬景，真趣絕外鑠。", "可笑學神僊，妄意向寥廓。"]'),
('b8055538-1507-4910-b906-34f9cf6ca638','和子駿','范純仁','宋','宋诗','song-poetry','','[]','夏木擁高陰，微風蕩輕靄。',60,'全唐诗/poet.song.36000.json','["夏木擁高陰，微風蕩輕靄。", "開軒延衆賓，置榻臨爽塏。", "清談析妙理，塵臆滌煩痗。", "至樂從中來，外物亦何待。", "頻登君子堂，道義庶無餒。"]'),
('b36f5db2-b7ff-46ff-9b41-6e11d20f0dc4','王安之朝議蛙樂軒','范純仁','宋','宋诗','song-poetry','','[]','群響本無異，悲歡由感懷。',48,'全唐诗/poet.song.36000.json','["群響本無異，悲歡由感懷。", "蛙鳴得其所，人樂與之偕。", "既泯物我念，寧煩絲竹諧。", "誰能同此適，應亦少朋儕。"]'),
('58b687c2-2a0d-4245-93a6-b7172c310a2a','和君實病中子駿招不至','范純仁','宋','宋诗','song-poetry','','[]','君子固無患，雖有亦何病。',84,'全唐诗/poet.song.36000.json','["君子固無患，雖有亦何病。", "公偶無妄疾，居養仁者靜。", "懷賢本心服，非由譽望盛。", "庶以德義風，化此愚蒙性。", "欣陪杖屨遊，晨夕不爲併。", "暫阻如三秋，斯言猶未稱。", "屢詗期勿藥，敢怠走門徑。"]'),
('f70a0ab6-49e7-4a07-a04f-3b9ce1366ef8','君實南園飲罷留宿二首  其一','范純仁','宋','宋诗','song-poetry','','[]','間從長者車，名園宴初闋。',48,'全唐诗/poet.song.36000.json','["間從長者車，名園宴初闋。", "佳賓薄暮散，歸鞍带明月。", "珠玉良有德，芝蘭香不絕。", "夜久卧北窗，魂夢亦清潔。"]'),
('aca5ea78-ea6a-40a5-b7fc-0e9b1df55578','君實南園飲罷留宿二首  其二','范純仁','宋','宋诗','song-poetry','','[]','繁花錦鬭鮮，好鳥歌無闋。',48,'全唐诗/poet.song.36000.json','["繁花錦鬭鮮，好鳥歌無闋。", "逍遥涉其間，豈獨娛歲月。", "脩竹色常佳，清渠流不絕。", "客散掩幽扉，圓蟾正明潔。"]'),
('bca2d6fa-7451-4c3e-8adb-681a0065fd51','次韵景仁寄君實决樂議之作','范純仁','宋','宋诗','song-poetry','','[]','餘生苦多難，所向招詆讕。',288,'全唐诗/poet.song.36000.json','["餘生苦多難，所向招詆讕。", "前年失二子，悲腸劇刳剜。", "悸魂念職守，憂患何瀰漫。", "叫閽輒自陳，聞者爲辛酸。", "朝恩俯從欲，幸忝留司官。", "薄廩霑甑釜，尚愧遠祖丹。", "西都多巨公，賢哲羅衣冠。", "親炙挹高義，朝夕陪清歡。", "蒹葭倚白玉，蟻蛭對層巒。", "肴羞屢陳列，桃梨煩雕鑽。", "翰林壺冰潔，祕殿朱繩端。", "遠識固莫測，確論宜不刊。", "立行皆表的，析埋亡髀髖。", "從容及議樂，辯論生酒闌。", "相圃衆如堵，楚戰惴旁觀。", "辭鋒奮銛利，學海翻波瀾。", "解带拒班輸，登壇劫齊桓。", "焚舟却魏武，火牛快田單。", "守義若據險，持說侔執干。", "當仁不相讓，食馬幾及肝。", "聽者如餒人，得味皆珍餐。", "折衷無聖師，簡編闕且殘。", "誰能置輕重，愈見制作難。", "兩家難未解，宜僚徒弄丸。"]'),
('8019ad6e-f5b6-4130-b554-dcc49a759965','歷陽彭衛字明微棄官養母築堂名曰壽燕取壽老燕安之義得古人養志之道作詩以紀實','范純仁','宋','宋诗','song-poetry','','[]','養親不擇祿，昔有仕爲貧。',192,'全唐诗/poet.song.36000.json','["養親不擇祿，昔有仕爲貧。", "唯有席先疇，足以供昏晨。", "超然舍祿位，一志親耕耘。", "既無王事盬，亦免賈用勤。", "雞豚畜以時，粱稻盈倉囷。", "處身但清約，甘旨極鮮珍。", "堂上垂素髮，含飴弄兒孫。", "綵服不離膝，終日常欣欣。", "園中復構室，花竹圍四鄰。", "窗戶儼羅列，開闔隨寒溫。", "慈顔縱遊適，日涉不爲頻。", "雅當壽燕名，安康保靈椿。", "門多長者車，間可延嘉賓。", "講道資朋友，德譽日以新。", "孝誠動金石，豈獨化鄉枌。", "顯揚久益大，聖世求忠臣。"]'),
('9376b7aa-15bb-47ba-9fee-cf074d7e3655','自警','范純仁','宋','宋诗','song-poetry','','[]','憶昔爲小官，位卑職易營。',276,'全唐诗/poet.song.36000.json','["憶昔爲小官，位卑職易營。", "朋知喜其勤，民口亦見稱。", "中間忝臺諫，已覺言難行。", "然頼識者恕，尚謂無欹傾。", "數年忽遭遇，用大過其能。", "名虛稱不實，任重力難勝。", "具瞻不可欺，舉動招譏評。", "士論固不與，自知亦甚明。", "祿厚難報答，徒滋驕侈萌。", "子孫忘艱難，服用饒夸矜。", "清白素風減，冗長浮費增。", "親舊多責望，厚薄貽怨憎。", "貧賤勝富貴，古語信可憑。", "請病蒙罷免，方幸憂責輕。", "俄復統一道，撫民帥邊兵。", "寇狂適偃蹇，民疲未蘇醒。", "勝負繫司命，休戚及群民。", "細務委將佐，大事稟朝廷。", "所稟有違從，委擇有不精。", "差失雖毫釐，致敗或丘陵。", "殞身何足道，誤國玷家聲。", "可不常惕懼，臨淵履春冰。", "庶幾免危溢，書此爲心銘。"]'),
('91eda0e9-8f44-434c-8c49-0a82fac796bf','自砭','范純仁','宋','宋诗','song-poetry','','[]','人有好勝心，當以善勝惡。',120,'全唐诗/poet.song.36000.json','["人有好勝心，當以善勝惡。", "豈宜執人我，與彼較彊弱。", "所得無毫釐，所失已山嶽。", "事過徒自悔，駟馬追不却。", "况臨衰暮年，事尤資審度。", "如人行遠道，日暮將憩泊。", "遵途益須慎，勿使趣向錯。", "逆境是吾師，苦口多良藥。", "豈止人難欺，將爲鬼所噱。", "有病在速治，姑以自砭灼。"]'),
('b383ce82-74a6-4a12-b098-c903cc9bc173','次韵曼叔見寄','范純仁','宋','宋诗','song-poetry','','[]','予生三十愚且惷，樂善自許人難雙。',272,'全唐诗/poet.song.36000.json','["予生三十愚且惷，樂善自許人難雙。", "前年杞城拜夫子，似處幽蔀逢明釭。", "交情期與道義久，第愧蟻蛭臨崆㟅。", "兵厨得酒不自飲，携挈過我盈尊缸。", "追遊頗縱山水樂，凉風皓月臨溪矼。", "長歌高嘯助清景，徹曙未肯回艂艭。", "別來節物皆一換，秋風憀慄陵疏窗。", "韓庵幽蓮墮紅粉，崔榭密竹森雲幢。", "過從往往臻靜默，兀坐終日如枯憙。", "得君新詩成杼軸，目未窮紙心先降。", "指摘萬象無不到，發慮百中如甘逄。", "搜情引思勉欲和，畎溜豈合追湍瀧。", "念君懷道滯山邑，誰者肉食居高龐。", "方今明聖締堂搆，采拔材榦恢鴻厖。", "長松偃蹇卧澗谷，梓匠誰與來扶扛。", "入登明堂柱九室，氣象凜凜尊家邦。", "復使天下貴儒術，頌聲千載長錚淙。"]'),
('5f940be8-de3c-4c71-b834-2cc4a08f10ec','同王弱翁宿廣化寺','范純仁','宋','宋诗','song-poetry','','[]','能知真樂唯吾曹，聲利外物誠無僥。',256,'全唐诗/poet.song.36000.json','["能知真樂唯吾曹，聲利外物誠無僥。", "深山窮谷苟遂性，膚體不厭常枯焦。", "况如佳景擅天巧，會與仁友相追邀。", "龍門伊洛古今勝，蒼巖翠壁雙岧嶢。", "疏鑿宛見神禹迹，懷襄既乂熙堯朝。", "千龕萬宇變佛室，鐘磬梵唄何喧囂。", "唐僧無畏號神雋，當時聲勢尤翹翹。", "開山撥壤盡奇秀，樓殿勢若風中飄。", "高甍垂空插雲翼，連閣跨路馳星橋。", "深沈神物潛擁護，顯敞燕雀如矜驕。", "搜奇選勝幸遲日，禪堂解榻眠清宵。", "灘聲蕭蕭雜群籟，天真不啻聞咸韶。", "陵晨携策度翠巘，竹溪深處從僧招。", "融融朝暉射巖谷，雜花爛熳紅欲燒。", "令人即欲置萬累，百年盡向遊中消。", "乃知神僊有窟室，我意已欲陵煙霄。"]'),
('e55903af-ec3e-4500-826a-60d87cae60c9','龍門行','范純仁','宋','宋诗','song-poetry','','[]','皇圖經野臨中天，北有大河南陸渾。',336,'全唐诗/poet.song.36000.json','["皇圖經野臨中天，北有大河南陸渾。", "陸渾之下伊之源，直走關塞侵山根。", "此山不斷亙坤軸，逆爲汝海波濤翻。", "忽焉天意有不測，疈開峽口流如吞。", "長波萬練卷空過，貫都會洛風霆奔。", "崖岸相嶔竦天闕，此號鑿龍爲禹門。", "石道盤紆入幽邃，杉松隠映皆祇園。", "下窺朝市但塵土，不與人世同囂喧。", "天章閣老真相嗣，詔委北陲嚴國藩。", "前騶驅弩聊盤桓，憑高置酒臨巖軒。", "是月嘉平臘將盡，春風料峭煙霾昏。", "圭陰表日景漸正，玉沙透水波先溫。", "杳杳端闈照宸極，壯以崤函周轘轅。", "超然宴覽動咨歎，坐預國論慚冥煩。", "乃知公旦卜洛意，根本繫時亡與存。", "法宮在今宜有制，上憲太微尊至尊。", "乘杓布政朝萬玉，莫如洛宅當乾坤。", "三陵氣象貫星野，慶雲祚百雲來孫。", "豈唯設險御諸夏，亦以捍患安元元。", "爲於可爲事乃濟，器大重遷咸有言。", "賤臣幽退冒及此，願對上前圖籍論。"]'),
('c7539a14-727e-4507-82a6-a9ff14221eb2','梁貺之惠酒分餉張伯常朝議','范純仁','宋','宋诗','song-poetry','','[]','黄衣健卒肩乘壺，口傳好語無緘書。',176,'全唐诗/poet.song.36000.json','["黄衣健卒肩乘壺，口傳好語無緘書。", "爲言八使致新釀，赤泥翠籠來兵厨。", "軫予官冷乏斟酌，補助不足均贏餘。", "殷勤拜貺興不淺，對月開縢露華滿。", "金波瀉出紫玉瓶，珠光飛入琉璃醆。", "獨酌雖甘少遺味，懷友思賢動深意。", "走送城西詩酒家，珠玉琅琅發清思。", "李白一斗詩百篇，劉伶一石高七賢。", "吏部興來卧甕邊，賀公眼花井底眠。", "乃知醉鄉路安穩，華胥有國無圻畛。", "願君愷樂游其間，千秋萬歲歡難泯。"]'),
('99a9a4b6-2f6a-4648-a2a8-a0130db7fd96','和君實同年會作','范純仁','宋','宋诗','song-poetry','','[]','詩酒相娛誠得策，洛社當年有牛白。',80,'全唐诗/poet.song.36000.json','["詩酒相娛誠得策，洛社當年有牛白。", "况公同榜三四君，從宦天涯久相隔。", "一朝把酒對春風，餘花紅白猶堪摘。", "不鄙賤生年輩晚，招延亦預尊前客。", "清歡盡日信忘形，醉舞狂歌不知拍。"]'),
('44f99434-34d7-439c-9827-847a3102ee37','和王微之赴韓持國燕集','范純仁','宋','宋诗','song-poetry','','[]','潁川太守無羈束，爲政課卑纔第六。',224,'全唐诗/poet.song.36000.json','["潁川太守無羈束，爲政課卑纔第六。", "里中耆舊六七翁，漸閒勇退皆高躅。", "獨愧衰疲掌民社，謾擁熊軒駕丹轂。", "身病何由安百姓，才薄豈當尸厚祿。", "巧匠居旁只坐觀，老手真能袖間縮。", "唯有過從相愛心，青松不肯更寒燠。", "韓公開宴坐高堂，帳帟垂紅窗綺綠。", "簾深不散玉爐香，夜長屢剪銅盤燭。", "從容談笑雜笙歌，爛熳肴烝兼海陸。", "翩翩舞態學驚鴻，嘹喨龍吟出橫竹。", "與公進退晚相同，曾共憂勤參大麓。", "酒量從茲減壯年，豈復長鯨吞百谷。", "興來猶勉奉公歡，金尊未釂先頹玉。", "且同萬物樂時康，况慕諸君知止足。"]'),
('1786cd65-7902-46c0-8043-b126e15b02be','早行','范純仁','宋','宋诗','song-poetry','','[]','夙駕冒輕寒，身勞意自閒。',48,'全唐诗/poet.song.36000.json','["夙駕冒輕寒，身勞意自閒。", "鳴雞起遥墅，殘月滿空山。", "水落灘沙白，林稀落葉殷。", "東方上朝旭，始免畏途難。"]'),
('65f56c06-3c03-4318-9df2-4f59443f9c17','遊嵩山與王弱翁聯句','范純仁','宋','宋诗','song-poetry','','[]','靈境中天秀，雄名古到今。',288,'全唐诗/poet.song.36000.json','["靈境中天秀，雄名古到今。", "位尊朝列嶽，勢重壓千岑。", "靜鎖神僊宅，高盤宇宙心。", "孤棱標日月，絕仞倚戈鐔。", "彩棟靈祠邃，層壇凈剎深。", "民祈傳覡語，國祀致君忱。", "碑古苔生字，堂虛畫蠹金。", "山呼曾薦壽，神降即爲霖。", "事怪塗山石，形端玉女砧。", "峰巒排翠玉，灘瀨潄鳴琴。", "蕙帳人誰繼，金泥迹可尋。", "唐經藏寶妙，魏殿想鑾音。", "雲作他方雨，松連別院陰。", "谷泉長浸斗，頂路欲捫參。", "探穴魂潛動，捫蘿力不禁。", "箕熊分蟻垤，伊洛認蹄涔。", "鳥道樵夫去，龍潭驛使臨。", "衆僊停羽駕，昔帝儼宸襟。", "選勝先看記，乘危可作箴。", "天門開四極，樹品冠雙林。", "靈藥看苗劚，香醪挈榼斟。", "道宮庭不掃，學館突無黔。", "壠麥風摇浪，溪淙石聳簪。", "雜花春爛熳，老木夜蕭森。"]'),
('13bdd223-39e0-4522-b09b-569e237bdfb9','賈文元生日','范純仁','宋','宋诗','song-poetry','','[]','寶運興王國，真賢降帝庭。',216,'全唐诗/poet.song.36000.json','["寶運興王國，真賢降帝庭。", "乾坤深毓粹，河嶽共儲靈。", "慶澤貽謀遠，光華變世丁。", "精心該古學，夷步涉僊扃。", "虎變騰彪蔚，鵬飛絕窈冥。", "畋占渭濱兆，夢肖傅巖形。", "姬旦興周典，桓榮授漢經。", "四聰延啟沃，百辟仰儀刑。", "金節臨全魏，天聲震北溟。", "仁恩宣雨露，威令肅風霆。", "玉壘兼前好，黄樞冠舊廳。", "出封仍衮職，開國直龍廷。", "樂育先儒學，憂勤察訟囹。", "談賓延白屋，衛劍匣青萍。", "體貌師臣貴，功名史筆青。", "朝廷方倚重，民物傒圖寧。", "大厦容棲翼，洪鍾謝寸莛。", "徒能繼輿頌，傾意祝遐齡。"]'),
('30c88dc0-85a4-4236-87b1-a10775034196','清輝閣','范純仁','宋','宋诗','song-poetry','','[]','使寄東南重，提封舊國雄。',72,'全唐诗/poet.song.36000.json','["使寄東南重，提封舊國雄。", "江山歸漢節，棟宇壓吳宮。", "隠几群峰近，穿梧一徑通。", "竹陰摇檻翠，橋影落溪紅。", "響迸荷心雨，凉生水面風。", "澄清多暇日，尊酒喜時同。"]'),
('6c2dc4b4-63e3-4715-8486-bb3fe9de2060','寒食日泛舟','范純仁','宋','宋诗','song-poetry','','[]','合友逢佳節，携尊泛碧流。',48,'全唐诗/poet.song.36000.json','["合友逢佳節，携尊泛碧流。", "溪風銷酒力，煙樹入春愁。", "群鴨開波練，疏雲透月鈎。", "平生懷古意，最羨五湖游。"]'),
('a2a6c18b-1110-414c-91dd-d6e24581f381','贈師宰','范純仁','宋','宋诗','song-poetry','','[]','君來寧素約，我至自殊因。',48,'全唐诗/poet.song.36000.json','["君來寧素約，我至自殊因。", "義重緣應合，心親見亦頻。", "十年無齟齬，一遇有逡巡。", "他日林丘去，須爲白首親。"]'),
('2145a66e-9d7b-4eb1-a5e1-e69157f74f86','送別','范純仁','宋','宋诗','song-poetry','','[]','小雨郊原淨，輕風生早凉。',48,'全唐诗/poet.song.36000.json','["小雨郊原淨，輕風生早凉。", "歌聲激離思，酒力壯悲腸。", "默計去程遠，預知宵夢長。", "鄉關足清賞，一一寄詩章。"]'),
('ad475d1a-3e54-4209-a23a-870cc77fe5ac','和韓侍中上巳日會興慶池二首  其一','范純仁','宋','宋诗','song-poetry','','[]','波漲朱闌外，山明綺席前。',48,'全唐诗/poet.song.36000.json','["波漲朱闌外，山明綺席前。", "畫橈飛彩鷁，紅旆照清漣。", "東閣隨開府，佳賓盡謫僊。", "夕陽歸騎外，芳草綠綿綿。"]'),
('fda1ac0d-3328-4b24-b75b-7a3bcb0b32ee','和韓侍中上巳日會興慶池二首  其二','范純仁','宋','宋诗','song-poetry','','[]','故隄高柳綠毿毿，花萼遺基映柳南。',64,'全唐诗/poet.song.36000.json','["故隄高柳綠毿毿，花萼遺基映柳南。", "啼鳥解招遊客醉，落花時有戲魚銜。", "舟移羅綺添春色，山破雲烟出曉嵐。", "後會陪公應更樂，行看廟勝掃祅欃。"]'),
('0260ed87-aca0-4780-958c-b8a5b69c8216','觀終南採冰','范純仁','宋','宋诗','song-poetry','','[]','凝結自太古，蒼崖潛閟深。',48,'全唐诗/poet.song.36000.json','["凝結自太古，蒼崖潛閟深。", "炎蒸當六月，皎潔正千尋。", "金盌通珠液，青蠅避玉碪。", "焦勞方旰昃，聊可沃君心。"]'),
('8dab982b-97ff-4ecd-9a10-4ac4f3f96c89','和江東運使韓子文見寄','范純仁','宋','宋诗','song-poetry','','[]','歲寒君子意，窮達見情均。',48,'全唐诗/poet.song.36000.json','["歲寒君子意，窮達見情均。", "多謝江南信，偏憐澤畔人。", "明珠驚照夜，寒谷頓生春。", "白首論交地，須看管鮑親。"]'),
('03ba22fe-e99e-44ee-b487-1afa109bac72','和韓子文題王摩詰畫寒林','范純仁','宋','宋诗','song-poetry','','[]','摩詰傳遺跡，家藏久自奇。',48,'全唐诗/poet.song.36000.json','["摩詰傳遺跡，家藏久自奇。", "高人不復見，絕藝更誰師。", "水石生寒早，煙雲結雨遲。", "筆端窮造化，聊可敵君詩。"]'),
('6f7d422e-1801-4165-9bbd-321dafa8f76e','和毛維瞻郎中見寄','范純仁','宋','宋诗','song-poetry','','[]','高賢煩出使，妙柬蓋從中。',96,'全唐诗/poet.song.36000.json','["高賢煩出使，妙柬蓋從中。", "紅旆臨江浦，牙檣列岸楓。", "頒條蘇舊俗，弔古訪遺宮。", "令信遺文簡，刑平獄戶空。", "九重天眷異，千里物情通。", "識面烟波際，論心氣類同。", "斷金捐畛域，倚玉愧蒿蓬。", "別思知何似，秋雲日夜東。"]'),
('3cefbac8-c3fe-4b59-b860-913397921652','晚菊','范純仁','宋','宋诗','song-poetry','','[]','幽叢有佳色，不必趁時開。',48,'全唐诗/poet.song.36000.json','["幽叢有佳色，不必趁時開。", "冷艷霜仍借，清香蝶自來。", "晚芳情愈重，醉賞目先回。", "且伴芝蘭秀，休嗟暮景頹。"]'),
('70b31737-d0aa-4f8d-ad69-5c64175c407b','和謝師厚見寄','范純仁','宋','宋诗','song-poetry','','[]','拙宦身何補，謀生術不高。',264,'全唐诗/poet.song.36000.json','["拙宦身何補，謀生術不高。", "履霜慚踐屐，察俗念同袍。", "獨鶴寒先警，哀猿夜更號。", "淒風獵蘭蕙，濃露濕蓬蒿。", "故國荒三徑，南冠歎二毛。", "使軺違右蜀，賢里隔西豪。", "吾友真時傑，斯文敵楚騷。", "一官曾共守，多難適聯遭。", "諷詠餐忘味，賡酬夜費膏。", "倦禽慵擇木，涸鮒羨游濠。", "交分窮彌篤，相思夢亦勞。", "未能拋假綬，何計理行篙。", "老去情難展，憂來首獨搔。", "書勤空繫雁，河廣詎容舠。", "郡僻稀民政，科繁屬吏曹。", "飯粳吹玉粒，嘗蟹擘金螯。", "治性親黄卷，蠲愁仰白醪。", "任真傾肺俯，共醉沃醨糟。", "夕惕持新禁，年凶減衆遨。", "光陰徒汩汩，懷抱慎忉忉。", "歸隠輸陶令，參禪學李翱。", "因君破蒙滯，遣興彊含毫。"]'),
('fa570d70-623d-4eda-9b83-2a664b130985','和徐億郎中喜雪','范純仁','宋','宋诗','song-poetry','','[]','君恩消祲沴，喜雪驗時和。',120,'全唐诗/poet.song.36000.json','["君恩消祲沴，喜雪驗時和。", "山峙崑兼閬，江迷汜與沱。", "圃妝花鬭巧，林亞玉相摩。", "丘壑平無異，蕭蘭惠不頗。", "野催農務急，客醉酒家多。", "裂素思團扇，吹毛想太阿。", "流風疑漢舞，黄竹詠周歌。", "煙冷漁村遠，裘厖獵騎過。", "穀登期歲稔，人樂免夭瘥。", "會待晴宵賞，寒光混月波。"]'),
('49c4bc4f-c8aa-4bc7-b925-f6fcfd6d22d4','謝師厚寄同黄婿魯直唱和','范純仁','宋','宋诗','song-poetry','','[]','忽得穰郊信，翛然病魄醒。',72,'全唐诗/poet.song.36000.json','["忽得穰郊信，翛然病魄醒。", "懷賢心獨在，感舊涕偏零。", "南斗占神劍，西豪聚德星。", "卧龍看復起，失馬顧曾經。", "冰玉清相照，芝蘭遠更馨。", "麤官應念我，白首候戎亭。"]'),
('d6c97577-163f-4383-8b51-6c65a1f968a4','和閻灝中秋賞月四首  其一','范純仁','宋','宋诗','song-poetry','','[]','中秋氣清肅，况復在邊庭。',48,'全唐诗/poet.song.36000.json','["中秋氣清肅，况復在邊庭。", "月吐孤輪迥，天開六幕青。", "輝盈疑白晝，明極掩常星。", "此夕鄉關思，胡笳莫細聽。"]'),
('74c95bf1-bea4-4fee-a81e-1eddca68b772','和閻灝中秋賞月四首  其二','范純仁','宋','宋诗','song-poetry','','[]','張筵賞秋月，簫鼓沸公庭。',48,'全唐诗/poet.song.36000.json','["張筵賞秋月，簫鼓沸公庭。", "光泛露逾白，輪高天更青。", "遮藏三讓客，牢落庶民星。", "節去人隨老，杯行我但聽。"]'),
('29361cac-947a-4e0d-9caf-b8def48f792e','和閻灝中秋賞月四首  其三','范純仁','宋','宋诗','song-poetry','','[]','萬里邊城月，清輝徹北庭。',48,'全唐诗/poet.song.36000.json','["萬里邊城月，清輝徹北庭。", "沙侔霜霰白，圃失蕙蘭青。", "影亂林篩玉，光長隙透星。", "南飛有歸雁，羨爾故先聽。"]'),
('7b16713e-b1b2-422d-a290-c8e7dd4ffb81','和閻灝中秋賞月四首  其四','范純仁','宋','宋诗','song-poetry','','[]','浮雲收絕塞，金鑒躍天庭。',48,'全唐诗/poet.song.36000.json','["浮雲收絕塞，金鑒躍天庭。", "但願冰輪瑩，何煩桂影青。", "溪心如瀉練，杯面若涵星。", "曩昔開元曲，何人可復聽。"]'),
('9be19bc6-8330-4254-a66e-5d275989aba9','和聖美翟家原道中之作','范純仁','宋','宋诗','song-poetry','','[]','曉烟浮水白，晴日透霞紅。',48,'全唐诗/poet.song.36000.json','["曉烟浮水白，晴日透霞紅。", "屈曲嶺頭路，蕭條旗脚風。", "主恩覃塞外，賢業滿胸中。", "始信人聲遠，歡迎到處同。"]'),
('e9d10043-e346-46aa-bec7-bc019d04c56c','騎射','范純仁','宋','宋诗','song-poetry','','[]','雄兒矜絕藝，勇氣厭天驕。',48,'全唐诗/poet.song.36000.json','["雄兒矜絕藝，勇氣厭天驕。", "振臂聯驅馬，翻身仰射雕。", "回旋驚電雹，奔突出塵囂。", "武備并文教，均脩是我朝。"]'),
('59830cfd-4cd9-41be-93ad-2c52b6e69806','病起聞走馬宴同僚走筆戲呈席上','范純仁','宋','宋诗','song-poetry','','[]','平日倦仍衰，那堪更病羸。',48,'全唐诗/poet.song.36000.json','["平日倦仍衰，那堪更病羸。", "賓僚聞燕集，冠蓋阻追隨。", "歌筦宜嘉賞，觥觴莫苦辭。", "酒深緣意厚，但看樂天詩。"]'),
('4c9ac3a4-d27d-4e9e-ac8c-8a9903bf9c17','仲春寄二弟','范純仁','宋','宋诗','song-poetry','','[]','春雁來時節，飛鳴各有行。',48,'全唐诗/poet.song.36000.json','["春雁來時節，飛鳴各有行。", "弟兄俱遠宦，秦楚久相望。", "尊席唯他士，鶑花似故鄉。", "何時遂歸計，共醉潩湖旁。"]'),
('d6655703-5430-4399-941d-846791cdbb22','酬羅道濟黄任道見寄','范純仁','宋','宋诗','song-poetry','','[]','明時頻得罪，出處愧朝行。',48,'全唐诗/poet.song.36000.json','["明時頻得罪，出處愧朝行。", "音問通猶懶，賡酬况敢望。", "諸公憐舊物，遷客慣他鄉。", "懷抱隨新月，遥依紫塞旁。"]'),
('c40098dc-b3a2-406f-a7c3-7236716be091','簽判李太博靜勝軒二首  其一','范純仁','宋','宋诗','song-poetry','','[]','開軒納清景，爲吏似閒居。',48,'全唐诗/poet.song.36000.json','["開軒納清景，爲吏似閒居。", "佳客迹頻到，主人心自虛。", "琴尊良有助，時命固無如。", "喧靜何能必，中恬樂有餘。"]'),
('7529e805-fdf2-49e1-97e6-4cc01a713b5d','簽判李太博靜勝軒二首  其二','范純仁','宋','宋诗','song-poetry','','[]','題軒名靜勝，靜勝理何深。',48,'全唐诗/poet.song.36000.json','["題軒名靜勝，靜勝理何深。", "自得歸根趣，寧存較物心。", "雜花隨節候，疊嶂互晴陰。", "終日對圖畫，應無塵慮侵。"]'),
('26271fc7-9112-4783-b0a1-585d0bb72bf9','和君實微雨書懷韵','范純仁','宋','宋诗','song-poetry','','[]','老畏風光速，閒知日晷添。',288,'全唐诗/poet.song.36000.json','["老畏風光速，閒知日晷添。", "惜春逢雨急，病酒與愁兼。", "採蘂蜂須涇，銜泥燕觜黏。", "水聲淙曲沼，花氣遞疏簾。", "墜絮柔鋪徑，高梧翠倚簷。", "清伊照窗碧，少室插雲尖。", "老蔓蛇難蟄，殘紅火不炎。", "邀朋擬白社，取友盡蒼髯。", "饌具雖真率，賓儀去謹嚴。", "主公紆繡衮，詞伯玩書籤。", "陶冶恩唯舊，葭莩契偶霑。", "尊崇儲峻嶽，高潔仰孤蟾。", "社稷勳無敵，軻雄學不厭。", "威聲傳異域，名姓到窮閻。", "賓主均歡愛，鄉閭化靜恬。", "應憐孤客志，粗守小官廉。", "饑頼監河粟，貧無遺盜縑。", "清朝慚祿薄，豐歲喜魚占。", "識暗妨時用，心愚以古潛。", "狂歌忘皓首，醉眼怯青帘。", "東閣容疏放，西都慰佇瞻。", "酬詩常愧拙，負弈固非謙。", "久玷題評末，深蒙道義漸。", "虛舟不復繫，所向可無嫌。"]'),
('3df6e6de-ca28-4ab9-98f6-030e09a56033','寄伯康君實','范純仁','宋','宋诗','song-poetry','','[]','平生親友分，偏向二難深。',48,'全唐诗/poet.song.36000.json','["平生親友分，偏向二難深。", "但念相從樂，應知別後心。", "西窗棋罷弈，南圃逕慵尋。", "不奈懷賢意，香醪獨滿斟。"]'),
('5e849043-8872-4537-9396-45ad9267b0fe','寄伯康君實','范純仁','宋','宋诗','song-poetry','','[]','明月照分袂，離魂增黯然。',48,'全唐诗/poet.song.36000.json','["明月照分袂，離魂增黯然。", "禪公歸故里，詞伯約新年。", "松竹荒三徑，金蘭憶二賢。", "向風無限意，書札豈能宣。"]'),
('37d4f51e-d24a-4336-bde5-e98b3c3bf3f8','酬安之罷赴真率會','范純仁','宋','宋诗','song-poetry','','[]','席上多佳客，非君衆不怡。',48,'全唐诗/poet.song.36000.json','["席上多佳客，非君衆不怡。", "詩詞雖有激，誠意在相思。", "朋舊難疏間，年齡合養頤。", "何如兩俱便，忺出莫推辭。"]'),
('fee830d4-dfda-4284-b665-f5114bdd2363','和安之謝伯康君實見訪','范純仁','宋','宋诗','song-poetry','','[]','眉壽當安逸，炎蒸倦往還。',48,'全唐诗/poet.song.36000.json','["眉壽當安逸，炎蒸倦往還。", "二難俱命駕，三逕始開關。", "清論應更僕，新詩特解顔。", "冥冥雙雁序，爲叟下雲間。"]'),
('57a30823-06fe-47ea-95f3-4a69133586c3','和文潞公席上','范純仁','宋','宋诗','song-poetry','','[]','夏木清陰合，公當雅燕開。',72,'全唐诗/poet.song.36000.json','["夏木清陰合，公當雅燕開。", "前軒鳴脆管，密席列英才。", "坐久風逾快，歡多日易頹。", "膺門榮一顧，孫閤愧常陪。", "繞客燒銀燭，垂蓮釂玉杯。", "醉歸應倒載，遠勝習家回。"]'),
('bb245f83-d0c0-4006-9570-67425df1c970','和安之喜雨','范純仁','宋','宋诗','song-poetry','','[]','驕陽逢密雨，歲事可遥占。',72,'全唐诗/poet.song.36000.json','["驕陽逢密雨，歲事可遥占。", "灑砌凉堪喜，通宵滴未嫌。", "渠淙鳴玉佩，簷逗水精簾。", "草木神俱王，倉箱望已添。", "炎蒸俄盡滌，秋意忽相兼。", "稍霽循幽圃，重尋晚筍尖。"]'),
('d637dac4-766b-48cf-9509-d78f6a66a04b','和范景仁蜀中寄牡丹圖','范純仁','宋','宋诗','song-poetry','','[]','牡丹開蜀圃，盈尺莫如今。',48,'全唐诗/poet.song.36000.json','["牡丹開蜀圃，盈尺莫如今。", "妍麗色殊衆，栽培功信深。", "矜夸傳萬里，圖寫費千金。", "難就朱欄賞，徒摇遠客心。"]'),
('76192733-da81-4995-85d5-235b5f720f4c','同張伯常會君實南園','范純仁','宋','宋诗','song-poetry','','[]','幽圃多清致，人賢樂有餘。',120,'全唐诗/poet.song.36000.json','["幽圃多清致，人賢樂有餘。", "游心同藝苑，歸興若田廬。", "畦廣容栽藥，門扃爲著書。", "築臺占嶽頂，鑿沼灑伊渠。", "庵倣盧仝屋，坊鄰白傅居。", "拂床留倦客，種竹蔭游魚。", "弄水衣襟濕，遵流酒醆徐。", "園翁名草木，山鳥戲階除。", "密席延商皓，高風邁漢疏。", "城西老詩伯，獨免醉登車。"]'),
('9e51ad5d-2ff5-4971-830b-30019c85c49f','子駿君實約遊園遇雨而止','范純仁','宋','宋诗','song-poetry','','[]','不盡陪從樂，端居若絆羈。',48,'全唐诗/poet.song.36000.json','["不盡陪從樂，端居若絆羈。", "雨方添草色，寒更展花期。", "舉目紅芳阻，搔頭素髮垂。", "清尊難獨酌，終日起相思。"]'),
('6e7f2dc7-85de-4980-9619-7be61fa76815','子華相公同遊趙令公園','范純仁','宋','宋诗','song-poetry','','[]','相君行樂處，繁盛故王家。',48,'全唐诗/poet.song.36000.json','["相君行樂處，繁盛故王家。", "聲遠歌喧閣，香濃酒泛花。", "瑰材扶廣厦，美植列甘柤。", "彊飲頻中聖，回頭畏麯車。"]'),
('eb15fd19-1a82-4286-93b8-caad56edfbba','和王端太中牡丹','范純仁','宋','宋诗','song-poetry','','[]','盈尺吐紅房，春叢占上陽。',72,'全唐诗/poet.song.36000.json','["盈尺吐紅房，春叢占上陽。", "佳名過百品，絕艷冠群芳。", "嫩玉舒韶臉，鮮霞避曉光。", "楚妃殊衆色，洛浦謝濃粧。", "露重珠如綴，風回麝不香。", "倦游稀愛賞，得此浣愁腸。"]'),
('7dc86346-e9e1-4c11-bc5f-1320c49dcb2a','和王太中游洛述懷','范純仁','宋','宋诗','song-poetry','','[]','乘春尋洛社，不憚路岐長。',48,'全唐诗/poet.song.36000.json','["乘春尋洛社，不憚路岐長。", "盈畹花如笑，傾都客若狂。", "山林多寂寞，朝市太奔忙。", "不似安車老，優游適四方。"]'),
('38b1717f-a55d-49f9-baca-1467ca3c2a9f','和君實陪潞公子華景仁宴集各一首  其一','范純仁','宋','宋诗','song-poetry','','[]','始終全盛美，今古莫如公。',48,'全唐诗/poet.song.36000.json','["始終全盛美，今古莫如公。", "華衮加朱紱，安車撤畫熊。", "建儲宗社計，破賊廟堂功。", "身退謀猷壯，宜哉帝眷隆。"]'),
('fe033b81-3eeb-414c-a872-5a583343ad15','和君實陪潞公子華景仁宴集各一首  其二','范純仁','宋','宋诗','song-poetry','','[]','再擁平陽節，麟符守洛宮。',48,'全唐诗/poet.song.36000.json','["再擁平陽節，麟符守洛宮。", "禮賢多孺子，交政得裴公。", "寬簡宜民化，歡游與俗同。", "行看歸宰席，致主詠南風。"]'),
('906d689b-c38b-4493-b82e-289d611c5410','和君實陪潞公子華景仁宴集各一首  其三','范純仁','宋','宋诗','song-poetry','','[]','莎輾安車穩，花簪醉帽紅。',48,'全唐诗/poet.song.36000.json','["莎輾安車穩，花簪醉帽紅。", "還鄉慰多士，入洛訪諸公。", "覽德如威鳳，歸鞍若去鴻。", "清規傳後學，信道不談空。"]'),
('cfcfb33d-9158-450f-85ab-87beff7c42db','和君實陪潞公子華景仁宴集各一首  其四','范純仁','宋','宋诗','song-poetry','','[]','種竹盈軒翠，栽花滿圃紅。',48,'全唐诗/poet.song.36000.json','["種竹盈軒翠，栽花滿圃紅。", "著書評百代，守節避三公。", "皎潔升壇玉，孤高漸陸鴻。", "清名若嵩少，萬仞亙長空。"]'),
('7624ad97-dda4-4ce6-ace4-df3273f8911b','寄君實','范純仁','宋','宋诗','song-poetry','','[]','西臺無吏責，道義得親依。',48,'全唐诗/poet.song.36000.json','["西臺無吏責，道義得親依。", "過宿暌談益，中懷已恨稀。", "何情堪久別，無翼不能飛。", "愚直相知少，非公誰與歸。"]'),
('421886a5-28e9-4f7d-a484-ec4c80137e79','寄王不疑朝議','范純仁','宋','宋诗','song-poetry','','[]','松筠宜歲晚，冰雪照人清。',48,'全唐诗/poet.song.36000.json','["松筠宜歲晚，冰雪照人清。", "無限相從樂，空添別後情。", "官期何日滿，歸計未能成。", "不起思予念，輸君道眼明。"]'),
('a2c8d111-fa9e-4518-a317-ba9f71605a50','喜雪','范純仁','宋','宋诗','song-poetry','','[]','久暘逢臘雪，酌酒動歡誠。',48,'全唐诗/poet.song.36000.json','["久暘逢臘雪，酌酒動歡誠。", "密勢迷城郭，餘霏冒棟楹。", "河光平曳練，嶽色遠堆瓊。", "已報豐年瑞，三登賀太平。"]'),
('d2a434e8-5979-498e-8e6d-6e63b39ce7ee','和張坊州','范純仁','宋','宋诗','song-poetry','','[]','詞場同際遇，郡政接循良。',96,'全唐诗/poet.song.36000.json','["詞場同際遇，郡政接循良。", "珠玉篇章妙，芝蘭氣味長。", "褒言如衮繡，雅意戒鵜梁。", "老格松千尺，清文水一塘。", "賡酬停筆久，降歎舉幡忙。", "當宁神兼武，開邊洮與湟。", "再叨藩寄重，難報主恩滂。", "憂職思承教，何由到訟棠。"]'),
('a30a1c0a-736b-4bca-8057-d40ec9a97864','和微之湖亭席上見贈','范純仁','宋','宋诗','song-poetry','','[]','曾陪湖上醉，一別十秋風。',72,'全唐诗/poet.song.36000.json','["曾陪湖上醉，一別十秋風。", "向老相知少，追歡舊德同。", "花香來席上，歌韵徹雲中。", "美酒盈尊綠，新粧映燭紅。", "清時宜共樂，白雪和難工。", "便合歸休去，荒田附郭東。"]'),
('7543ba97-5613-4546-a196-6c2b3b4d5d79','酬慶州五弟','范純仁','宋','宋诗','song-poetry','','[]','仲氏居青瑣，予而各大州。',48,'全唐诗/poet.song.36000.json','["仲氏居青瑣，予而各大州。", "報君當盡節，省己合回頭。", "繼述將何有，榮華過即休。", "相期知止足，里社早同遊。"]'),
('ba1aa1f8-74ab-4856-915d-ec8bbef59d8c','寄二弟','范純仁','宋','宋诗','song-poetry','','[]','一日如三歲，離懷不可忘。',48,'全唐诗/poet.song.36000.json','["一日如三歲，離懷不可忘。", "宦遊難會合，衰老易悲傷。", "原上鴒飛急，天邊雁序長。", "如何名利役，白首遠相望。"]'),
('40bde01c-490d-42f1-bdf8-3783f24e2ec8','目盲','范純仁','宋','宋诗','song-poetry','','[]','肝膽輸將竭，因鍾兩目盲。',48,'全唐诗/poet.song.36000.json','["肝膽輸將竭，因鍾兩目盲。", "小冠希子夏，令色恥丘明。", "青白何曾變，紛華舊不爭。", "幸回觀物志，都作反身誠。"]'),
('0d0c955c-02e6-4c9d-b983-df083a12d2f5','謫居零陵','范純仁','宋','宋诗','song-poetry','','[]','過盡瀟湘景，冥行固不分。',48,'全唐诗/poet.song.36000.json','["過盡瀟湘景，冥行固不分。", "烏羊飧可飫，白酒飲能醺。", "自息登臨興，因無出入勤。", "靈妃曾鼓瑟，信有尚堪聞。"]'),
('347c8264-3895-4420-81ce-13e4f7a8dee0','無書','范純仁','宋','宋诗','song-poetry','','[]','患難人皆恤，誰能絕信音。',48,'全唐诗/poet.song.36000.json','["患難人皆恤，誰能絕信音。", "寧忘問生死，可是盡浮沉。", "信子情無矯，知予咎自深。", "嚴冬見松柏，爲有歲寒心。"]'),
('f908d053-a735-4345-9039-70ea5fa17e5d','覆舟','范純仁','宋','宋诗','song-poetry','','[]','始駭舟衝簸，顛風振厚坤。',48,'全唐诗/poet.song.36000.json','["始駭舟衝簸，顛風振厚坤。", "濤聲如壞屋，雨勢若翻盆。", "力援煩舟子，驚號閔稚孫。", "全家脫魚腹，應有未招魂。"]'),
('f045637f-3a03-4b48-ac4b-cc8993166cb4','零陵重陽','范純仁','宋','宋诗','song-poetry','','[]','衰年逢素節，盲卧桂江東。',48,'全唐诗/poet.song.36000.json','["衰年逢素節，盲卧桂江東。", "應有登高會，其如摘埴翁。", "捫杯難舉酒，嗅菊不知叢。", "白首跧僧室，無煩落帽風。"]'),
('cf5085b1-a7cd-4dd1-86dc-364edafbe884','零陵移居','范純仁','宋','宋诗','song-poetry','','[]','不起移居念，全因廢兩眸。',48,'全唐诗/poet.song.36000.json','["不起移居念，全因廢兩眸。", "門閭俱莫辨，隘陋亦何憂。", "瞑鳥離巢遠，盲龜待木浮。", "平生安穩少，蓋乏措身謀。"]'),
('23064e97-a6db-4643-8a3e-d83ee43e21b1','零陵憶弟妹','范純仁','宋','宋诗','song-poetry','','[]','感秋懷弟妹，憔悴客瀟湘。',48,'全唐诗/poet.song.36000.json','["感秋懷弟妹，憔悴客瀟湘。", "他日常星聚，衰年隔雁行。", "既盲難引望，垂老易悲傷。", "安得騎鴻鵠，高飛向汝傍。"]'),
('c5bdf803-81d9-4f09-bdb9-3a9626879a3a','零陵寄三弟五弟二首  其一','范純仁','宋','宋诗','song-poetry','','[]','勿起還鄉念，囊空不易居。',48,'全唐诗/poet.song.36000.json','["勿起還鄉念，囊空不易居。", "田租收素薄，官俸奪無餘。", "顔困嘗求米，丘貧樂飯蔬。", "朱門啟新第，懸罄是吾廬。"]'),
('3d4a1562-359e-4e37-bd31-88a6abd7bd58','零陵寄三弟五弟二首  其二','范純仁','宋','宋诗','song-poetry','','[]','勿起還鄉念，人多故與親。',48,'全唐诗/poet.song.36000.json','["勿起還鄉念，人多故與親。", "舊通鄉里意，皆仰俸餘緡。", "望縱諸家息，情須一飯伸。", "誰能悠久坐，白眼絕朋賓。"]'),
('b90fca50-6b09-485a-be48-307dc5c0ffa5','送貫之兄被召爲御史三首  其一','范純仁','宋','宋诗','song-poetry','','[]','御史得言天下事，吾兄清直副明揚。',64,'全唐诗/poet.song.36000.json','["御史得言天下事，吾兄清直副明揚。", "方當旒扆勤開納，肯使江湖勇退藏。", "賢者慮時心欲破，仁人致主策須長。", "朝廷寬大生靈急，只在忠臣振紀綱。"]'),
('04a18e4b-03df-4154-9306-eaff6e971143','送貫之兄被召爲御史三首  其二','范純仁','宋','宋诗','song-poetry','','[]','憶昔先門陟諫垣，正人風采動朝端。',64,'全唐诗/poet.song.36000.json','["憶昔先門陟諫垣，正人風采動朝端。", "家聲宜有琳琅器，兄職今峨獬豸冠。", "臺閣繼登時所貴，忠賢得用古來難。", "浮榮未必吾儒志，會把功名竹帛看。"]'),
('e0d393db-8fcb-4602-b046-a793ab70778b','送貫之兄被召爲御史三首  其三','范純仁','宋','宋诗','song-poetry','','[]','艱禍龍鍾百指存，共全餘齒頼依仁。',64,'全唐诗/poet.song.36000.json','["艱禍龍鍾百指存，共全餘齒頼依仁。", "鴒原方顧飛鳴急，烏府俄聞拔擢新。", "此別宦遊須異地，從今教撫更何人。", "他年莫負鄉關約，明月扁舟白酒醇。"]'),
('a58f79e0-b802-4302-b3a3-1117978b9488','孔寧極先生拜官二首  其一','范純仁','宋','宋诗','song-poetry','','[]','聖朝旌德向丘園，紫詔頒恩到蓽門。',32,'全唐诗/poet.song.36000.json','["聖朝旌德向丘園，紫詔頒恩到蓽門。", "鄉老始知爲善貴，競相廉讓教兒孫。"]'),
('0e1128ad-0d7f-47f8-90fa-f0cf20e4f0de','孔寧極先生拜官二首  其二','范純仁','宋','宋诗','song-poetry','','[]','先生操術本真儒，進退恬然與道俱。',32,'全唐诗/poet.song.36000.json','["先生操術本真儒，進退恬然與道俱。", "寵至不驚高節在，豈顓虛譽激凡愚。"]'),
('eaa09916-7bf5-4119-8d08-28445d9bf296','龍門山二首  其一','范純仁','宋','宋诗','song-poetry','','[]','雲擁樓臺雪擁川，親朋行望舉吟鞭。',32,'全唐诗/poet.song.36000.json','["雲擁樓臺雪擁川，親朋行望舉吟鞭。", "煙龕萬疊凌花霰，坐見金人變玉僊。"]'),
('3c68da71-8606-4330-82fa-7fa798760522','龍門山二首  其二','范純仁','宋','宋诗','song-poetry','','[]','松筠深處訪潛溪，唐相當年卜隠棲。',32,'全唐诗/poet.song.36000.json','["松筠深處訪潛溪，唐相當年卜隠棲。", "必竟主人歸不得，只教游客駐輪蹄。"]'),
('d3bbecb8-bfe3-4530-a8ca-5ec3ec80c94e','獨游石巖寄諸友','范純仁','宋','宋诗','song-poetry','','[]','亂石巉空聳翠稜，攀蘿尋勝逐溪聲。',32,'全唐诗/poet.song.36000.json','["亂石巉空聳翠稜，攀蘿尋勝逐溪聲。", "愛山懷友情無限，日暮巖邊獨記名。"]'),
('dc9e8076-129d-4cf0-ae8b-7fa809ca699b','寄香嚴海僊上人','范純仁','宋','宋诗','song-poetry','','[]','穰鄧相逢已十年，想懷風格鎮依然。',64,'全唐诗/poet.song.36000.json','["穰鄧相逢已十年，想懷風格鎮依然。", "身同幻境融都寂，心得玄珠照自圓。", "倚錫靜眠松下石，煮茶閒試竹間泉。", "利名識盡情猶熟，終羨吾師絕世緣。"]'),
('971a382a-3ee5-4523-8103-b6ef08d80f33','陳和叔游龍門先歸','范純仁','宋','宋诗','song-poetry','','[]','玉峰環照碧伊寒，樓閣參差四望間。',64,'全唐诗/poet.song.36000.json','["玉峰環照碧伊寒，樓閣參差四望間。", "散騎從游皆故友，一川清景徹南山。", "笑言迥出塵埃外，心意都如物象閒。", "夫子官居慣追賞，故饒諸客獨先還。"]'),
('3e7a629a-ee4e-4bdd-a74b-40286c66ab1e','和王弱翁白沙道中','范純仁','宋','宋诗','song-poetry','','[]','共驅羸馬躡寒蕪，景色鮮明近洛都。',64,'全唐诗/poet.song.36000.json','["共驅羸馬躡寒蕪，景色鮮明近洛都。", "出谷流泉春更綠，隔林幽鳥暮相呼。", "伊川舊賞疑朝夢，少室重看勝畫圖。", "從此便窮山水樂，相從應不厭崎嶇。"]'),
('034a5528-6873-4122-95f6-76383a372413','龍門馬上望雪','范純仁','宋','宋诗','song-poetry','','[]','山開曉色千峰玉，草映寒光萬點瓊。',32,'全唐诗/poet.song.36000.json','["山開曉色千峰玉，草映寒光萬點瓊。", "爲我春游添景物，不教桃李獨鮮明。"]'),
('a58c1749-a3fc-4b31-a3e5-181e0dc9c1a3','臨汝溫泉','范純仁','宋','宋诗','song-poetry','','[]','山前陰火煮靈源，昔日曾臨萬乘尊。',32,'全唐诗/poet.song.36000.json','["山前陰火煮靈源，昔日曾臨萬乘尊。", "歷盡興亡只如此，不隨時俗變寒溫。"]'),
('1eed1182-da7a-4688-85c2-5ddf8d2108be','與王弱翁游龍門','范純仁','宋','宋诗','song-poetry','','[]','誰知造化擘巍峨，千古伊流向此過。',64,'全唐诗/poet.song.36000.json','["誰知造化擘巍峨，千古伊流向此過。", "四面寒松擁香剎，兩崖蒼石束寒波。", "身閒愈覺良朋貴，詩拙翻羞好景多。", "宜向諸方縱蕭散，明朝望洛下長坡。"]'),
('c8cd5162-c0ef-4db5-9b25-5afd4b48bbe0','許真君天誥','范純仁','宋','宋诗','song-poetry','','[]','至人脩練久能成，此誥嘗聞降帝庭。',64,'全唐诗/poet.song.36000.json','["至人脩練久能成，此誥嘗聞降帝庭。", "寶墨森森聳鸞鳳，訓詞一一在生靈。", "既將道行蒙幽顯，奚必僊蹤到杳冥。", "鶴駕雲軿非我覿，祇期操履學真經。"]'),
('91e09010-3835-48ce-a15b-eba7f61335a2','讀逸民傳寄孔寧極先生','范純仁','宋','宋诗','song-poetry','','[]','漢法忠賢有不容，遂持名節隠蒿蓬。',64,'全唐诗/poet.song.36000.json','["漢法忠賢有不容，遂持名節隠蒿蓬。", "生靈莫見真儒效，爵祿多酬戰士功。", "燕市終難沽美璞，魚羅安得挂飛鴻。", "聖朝高士優游甚，自有行藏繼祖風。"]'),
('670605b9-15a4-49fc-bb3d-330e35c7b34d','和曼叔閒書','范純仁','宋','宋诗','song-poetry','','[]','夫子天資過我曹，兩兼才德屬人豪。',64,'全唐诗/poet.song.36000.json','["夫子天資過我曹，兩兼才德屬人豪。", "不求近譽聲逾遠，能處卑官道益高。", "豈止一同裁美錦，直須萬俗被重袍。", "由來康濟吾儒事，撫遍瘡痍莫厭勞。"]'),
('9a7141d3-6328-4d88-9157-72f99a39355e','又和早行','范純仁','宋','宋诗','song-poetry','','[]','拂曙征人各向方，乍明林野更青蒼。',64,'全唐诗/poet.song.36000.json','["拂曙征人各向方，乍明林野更青蒼。", "雲頭漏日開秋色，馬足翻沙破曉霜。", "時事罕聞心愈靜，故人不見恨空長。", "憐君素愛還鄉樂，行役雖勞肯暫忘。"]'),
('03a504e1-da53-471e-84a3-500c7681c219','循吏','范純仁','宋','宋诗','song-poetry','','[]','王化由來起一同，盡由守宰致平隆。',64,'全唐诗/poet.song.36000.json','["王化由來起一同，盡由守宰致平隆。", "坐移風俗爲能政，勤撫生靈是至忠。", "四境肅清民害去，一方和樂主恩通。", "吾皇有德真堯舜，唯待諸君共理功。"]'),
('4452be9a-9b96-4e17-9337-839581e268d2','酷吏','范純仁','宋','宋诗','song-poetry','','[]','虐吏天資害物深，斯民無恥歎刑淫。',64,'全唐诗/poet.song.36000.json','["虐吏天資害物深，斯民無恥歎刑淫。", "只憑豺虎貪殘意，肯順乾坤長養心。", "骨肉盡將成怨府，君親何以致薰琴。", "終逢族滅令人快，智者爲謀豈待箴。"]'),
('ed3eb4d7-915e-4588-808f-67d847dba61e','聞鍛','范純仁','宋','宋诗','song-poetry','','[]','萬籟蕭然送夕曛，鍛聲相應互成文。',64,'全唐诗/poet.song.36000.json','["萬籟蕭然送夕曛，鍛聲相應互成文。", "高隨晚吹驚愁耳，清入霜空透暮雲。", "始訝僧魚敲曉石，靜如山木響秋斤。", "五兵若可爲農器，此韵千家不厭聞。"]'),
('fb013e1f-5fb9-4fa0-83a3-914c14db7bb8','和象之石磬','范純仁','宋','宋诗','song-poetry','','[]','誰向西山選翠琳，中含太古自然音。',64,'全唐诗/poet.song.36000.json','["誰向西山選翠琳，中含太古自然音。", "昔逢虞帝來祥鳳，今與陶家伴素琴。", "清越乍敲脩竹裏，堅方真合哲人心。", "一鎸名姓將難朽，千載知君道德深。"]'),
('6f7a20ca-79d0-4cb4-a1a0-0e31e1baa661','送賈春卿宰尉氏','范純仁','宋','宋诗','song-poetry','','[]','相君勳業冠朝端，愛子猶居字俗官。',64,'全唐诗/poet.song.36000.json','["相君勳業冠朝端，愛子猶居字俗官。", "道德相傳家有法，功名善繼古爲難。", "清平足使群情化，談笑能令萬室安。", "千里遠途今日見，願當仁政勿盤桓。"]'),
('a6fde377-3e2d-45a0-b7c3-ebcd794819f0','赴鄭郎中宴集','范純仁','宋','宋诗','song-poetry','','[]','卧錦仙郎久卜居，滿床書史日康娛。',32,'全唐诗/poet.song.36000.json','["卧錦仙郎久卜居，滿床書史日康娛。", "邀朋欲走趨齋閣，不厭塵埃俗客無。"]'),
('4e59565b-6b8c-41ec-a9cc-a180cf53a2d1','寄辛化光','范純仁','宋','宋诗','song-poetry','','[]','疏閒心蹟久相親，一別江城兩見春。',64,'全唐诗/poet.song.36000.json','["疏閒心蹟久相親，一別江城兩見春。", "身若孤鴻長慕侶，道非尺蠖敢求伸。", "優游歲月空尸祿，明潤溪山不染塵。", "尊酒從容皆勝景，欠君來作席中賓。"]'),
('badf15fe-986d-40d7-a7e7-b60984bf82b0','和吳君平游蔣山兼呈王安國二首  其一','范純仁','宋','宋诗','song-poetry','','[]','十年游宦阻朋從，尊酒俄欣二友同。',64,'全唐诗/poet.song.36000.json','["十年游宦阻朋從，尊酒俄欣二友同。", "單父能名推子賤，襄陽高節愛龐公。", "六朝山色空陳迹，十里松聲正晚風。", "聯騎追攀不知暮，却嫌歸路入塵中。"]'),
('3657dd2d-c1f4-43ef-8b98-11d7c6e57d24','和吳君平游蔣山兼呈王安國二首  其二','范純仁','宋','宋诗','song-poetry','','[]','錢塘山色飽相從，復此登臨景物同。',64,'全唐诗/poet.song.36000.json','["錢塘山色飽相從，復此登臨景物同。", "舊國池臺餘草碧，夕陽樓閣半山紅。", "當時言笑如朝夢，今日心顔盡老翁。", "終愛巖間坐禪客，能將萬事付虛空。"]'),
('550d23be-c23c-4688-b150-a0431bab1cae','和呂獻可江口見贈','范純仁','宋','宋诗','song-poetry','','[]','世閥俱承父祖風，又叨宦契十年中。',64,'全唐诗/poet.song.36000.json','["世閥俱承父祖風，又叨宦契十年中。", "棠陰代領諸侯印，棣萼更聯御史驄。", "白首相期唯信道，清朝連貶爲輸忠。", "駑駘詎合參騏驥，應合心能報主同。"]'),
('c7736950-844a-4d97-8a18-d83d931cfc45','和呂獻可牡丹','范純仁','宋','宋诗','song-poetry','','[]','去年仁政與春來，真賞曾蒙醉目回。',32,'全唐诗/poet.song.36000.json','["去年仁政與春來，真賞曾蒙醉目回。", "紅旆已隨芝檢去，滿欄芳意爲誰開。"]'),
('e5f992fd-47dd-4fcd-bccd-449ab2164af9','和獻可龍峰寺見寄三首  其一','范純仁','宋','宋诗','song-poetry','','[]','驅車日日望行舟，目斷風帆不可留。',32,'全唐诗/poet.song.36000.json','["驅車日日望行舟，目斷風帆不可留。", "獨有召公遺愛地，蒼山重疊滿晴樓。"]'),
('4585604f-c25e-4f6c-98c0-24b9d12042e2','和獻可龍峰寺見寄三首  其二','范純仁','宋','宋诗','song-poetry','','[]','丹心自許酬明主，百謫那能避貴權。',32,'全唐诗/poet.song.36000.json','["丹心自許酬明主，百謫那能避貴權。", "此道方今誰復問，望公須向古人前。"]'),
('c4a26d97-0734-4e5f-aadd-1599ce5539ea','和獻可龍峰寺見寄三首  其三','范純仁','宋','宋诗','song-poetry','','[]','忠臣多快姦臣憤，天意人情可奈何。',32,'全唐诗/poet.song.36000.json','["忠臣多快姦臣憤，天意人情可奈何。", "安得臯夔能致主，早聞堯舜復賡歌。"]'),
('4c4df746-6f57-41b4-b9a6-d263731f3a50','和獻可丙午二月六日別臺中僚友','范純仁','宋','宋诗','song-poetry','','[]','感時情緒已難禁，况復懷賢恨愈深。',64,'全唐诗/poet.song.36000.json','["感時情緒已難禁，况復懷賢恨愈深。", "鴉噪晚林催遠客，雲藏夕照弄輕陰。", "松筠自信凌霜操，葵藿長傾向日心。", "同志飄零山館寂，欲沽芳酒與誰斟。"]'),
('aec931df-663d-40dd-af1e-c69cf9bc38dc','荆甘','范純仁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','品珍方重寄來難，長憶東吳把酒看。',64,'全唐诗/poet.song.36000.json','["品珍方重寄來難，長憶東吳把酒看。", "笠澤煙閑排錦樹，洞庭霜老摘金丸。", "清香先透筠籠細，甘液俄通玉齒寒。", "不學荔枝遺國恨，曾煩驛使到長安。"]'),
('1f3f3202-a14d-4001-bea7-7c6843a113e2','兖墨','范純仁','宋','宋诗','song-poetry','','[]','誰爇長松製作勤，輕煤勻膩雜蘭薰。',64,'全唐诗/poet.song.36000.json','["誰爇長松製作勤，輕煤勻膩雜蘭薰。", "中疑玄石無纖翳，外若靈犀有密紋。", "溪石乍研浮紫翠，蜀牋試寫落烟雲。", "會將點畫傳青簡，千古忠邪爲爾分。"]'),
('0efbab4c-51fa-4d24-a751-cd584d405435','寄曼叔','范純仁','宋','宋诗','song-poetry','','[]','他年嘗苦見君難，每一相逢百倍歡。',64,'全唐诗/poet.song.36000.json','["他年嘗苦見君難，每一相逢百倍歡。", "正值風煙遥化邑，敢期塵土共麤官。", "夜談往往驚晨鼓，樂飲時時解醉鞍。", "遊遍洛陽佳勝地，須將歸興暫盤桓。"]'),
('ca0fccaf-9a6a-4712-b0ab-ee17404941ad','和張統貫之同年','范純仁','宋','宋诗','song-poetry','','[]','同榜同僚是別緣，所存相近復相便。',64,'全唐诗/poet.song.36000.json','["同榜同僚是別緣，所存相近復相便。", "性情疏懶忘官檢，襟抱平夷學古賢。", "仁者才謀當濟物，吾曹名利久推天。", "須知白首相逢日，不失初心始自全。"]'),
('a4d5d283-6a88-4756-89d5-50485c970a49','和韓侍中遊興慶池席上','范純仁','宋','宋诗','song-poetry','','[]','出郊尤喜雨初晴，洗出川原物象明。',64,'全唐诗/poet.song.36000.json','["出郊尤喜雨初晴，洗出川原物象明。", "樓影半藏高柳外，池光遥與綠萍平。", "鷗馴長近朱闌戲，民樂爭隨畫隼行。", "主禮自忘台鼎貴，芳尊盡日許同傾。"]'),
('690bd2d5-0da1-4f37-965a-1a5dc23d6c85','和韓侍中垂蘿洞','范純仁','宋','宋诗','song-poetry','','[]','勝遊今屬相君家，臺榭高開碧水涯。',64,'全唐诗/poet.song.36000.json','["勝遊今屬相君家，臺榭高開碧水涯。", "森聳綠梧常映日，縈紆寒溜曲穿花。", "藤牽柔蔓垂長带，竹引新萌走蟄蛇。", "下吏不辭峨醉弁，却愁歸污繡茵車。"]'),
('bb59a795-46ee-4aba-90ad-b73f9f1e74e2','和韓侍中上巳晚遊九曲池','范純仁','宋','宋诗','song-poetry','','[]','前朝池閣盡塵埃，登覽慚無弔古才。',64,'全唐诗/poet.song.36000.json','["前朝池閣盡塵埃，登覽慚無弔古才。", "舊物祇餘蒼石在，斷牆曾識翠輿來。", "回環竹徑穿幽鳥，寂寞茅簷覆故臺。", "游客靜觀興廢迹，利名心息若寒灰。"]'),
('d87929f1-6127-4d7f-822b-b7993b00d035','和韓侍中春陰馬上','范純仁','宋','宋诗','song-poetry','','[]','三月芳菲欲暮天，可堪零雨晝連綿。',64,'全唐诗/poet.song.36000.json','["三月芳菲欲暮天，可堪零雨晝連綿。", "潤催隴麥將籠節，寒阻春蠶趁早眠。", "疏柳拂牆難結絮，嫩苔鋪砌已成錢。", "牡丹只待晴陽照，看吐新花一尺圓。"]'),
('27ac87ee-8ae5-4d64-8c9b-0dcf1f76f290','次韵韓侍中遊興慶池','范純仁','宋','宋诗','song-poetry','','[]','兩奉清歡到碧塘，再遊無奈惜春光。',64,'全唐诗/poet.song.36000.json','["兩奉清歡到碧塘，再遊無奈惜春光。", "莎勻古岸添新綠，蝶遶殘花採舊香。", "佳木引陰交翡翠，疏林迸筍補篔簹。", "從容賞遍西園景，化國偏知日月長。"]'),
('32b726bc-eda0-4cc1-a675-401222517269','和韓侍中登廣教院閣','范純仁','宋','宋诗','song-poetry','','[]','兩陪千騎叩禪關，每聽高吟解客顔。',64,'全唐诗/poet.song.36000.json','["兩陪千騎叩禪關，每聽高吟解客顔。", "吉甫壯猷方北伐，謝公高興在東山。", "僧軒深閉芳菲靜，春晝初長鳥雀閒。", "游覽不知歸逕晚，火城看逐隼旟還。"]'),
('a5ab3c3c-ffc5-40ee-b42c-a8469e38ab13','和韓侍中同賞牡丹','范純仁','宋','宋诗','song-poetry','','[]','秦地春光似洛陽，牡丹名擅百花場。',64,'全唐诗/poet.song.36000.json','["秦地春光似洛陽，牡丹名擅百花場。", "巧鍾絕艷群芳後，高翦紅雲萬葉彊。", "露滿金盤看國色，風回綺席識天香。", "酒酣只欲盈簪戴，聊伴衰顔照玉觴。"]'),
('31ca7fed-6117-4220-8956-dca8908890ab','和孫曼叔北禪牡丹一蒂三花','范純仁','宋','宋诗','song-poetry','','[]','三花駢蒂吐芳叢，曲盡東皇造化功。',32,'全唐诗/poet.song.36000.json','["三花駢蒂吐芳叢，曲盡東皇造化功。", "疑是神山仙子會，霞衣鼎立馭輕風。"]'),
('f38b0d3b-6951-4c5b-9430-59e0786007ae','和韓侍中西禪牡丹','范純仁','宋','宋诗','song-poetry','','[]','秦川花品似伊川，真賞應同上苑看。',64,'全唐诗/poet.song.36000.json','["秦川花品似伊川，真賞應同上苑看。", "衆卉先收推國艷，五雲高吐學僊冠。", "烟苞添色資吟筆，露蘂霑香滿酒盤。", "勻壓春叢千萬朵，欲歸猶復遶朱欄。"]'),
('05403be5-0615-44d7-a859-14f2154323c2','和韓侍中初夏游興慶池','范純仁','宋','宋诗','song-poetry','','[]','池邊喜逐綵旗行，初夏亭臺照水明。',64,'全唐诗/poet.song.36000.json','["池邊喜逐綵旗行，初夏亭臺照水明。", "筠籜乍開春後綠，林稍長带雨來聲。", "新荷獵獵香風遠，深洞沈沈晝景清。", "珍重相君憂國意，宴游終亦念農耕。"]'),
('4e120b17-302e-4810-9e07-0a2573abba9c','與張靖學士游華清宮雍帥錢子飛端明以詩見寄次韵和','范純仁','宋','宋诗','song-poetry','','[]','金節煌煌柅使輈，華清勝絕許陪遊。',64,'全唐诗/poet.song.36000.json','["金節煌煌柅使輈，華清勝絕許陪遊。", "東來渭水晴光動，西望長安翠靄浮。", "休羨青山供秀句，好歸黄閤告嘉猷。", "憶公何處偏回首，身在朝元最上頭。"]'),
('54e1f55e-e0c2-4950-95c2-9742ef839dfb','和吳仲庶龍圖西園海棠','范純仁','宋','宋诗','song-poetry','','[]','丹葩翠葉競夭濃，蜂蝶翩翻弄暖風。',64,'全唐诗/poet.song.36000.json','["丹葩翠葉競夭濃，蜂蝶翩翻弄暖風。", "濯雨正疑宮錦爛，媚晴先奪曉霞紅。", "芳菲劍外從來勝，歡賞天涯爲爾同。", "却想鄉關足塵土，只應能見畫圖中。"]'),
('7cfecc25-0d52-4127-9ba4-bcecb0f3b655','贈眉陽致政程濬少卿','范純仁','宋','宋诗','song-poetry','','[]','清節高風世所推，秋毫名宦肯徘徊。',64,'全唐诗/poet.song.36000.json','["清節高風世所推，秋毫名宦肯徘徊。", "勇拋朝市無窮事，笑指林泉獨自來。", "吟榻未移溪月上，醉巾長拂野雲回。", "塵衣欲作登門客，几杖何妨許暫陪。"]'),
('1f626ad1-5f21-48d3-b281-170a1ae5b194','和吳仲庶遊碑樓大慈二寺','范純仁','宋','宋诗','song-poetry','','[]','錦城寒食最繁華，游騎翩翩雜鈿車。',64,'全唐诗/poet.song.36000.json','["錦城寒食最繁華，游騎翩翩雜鈿車。", "烟染翠行環郭柳，波摇紅影隔江花。", "長年已覺春如夢，遠客唯應醉是家。", "回首鄉關行樂地，風光正好路岐賒。"]'),
('ec82fa62-9afd-4258-a1b0-4e2542bdf474','和吳仲庶上巳遊學射山','范純仁','宋','宋诗','song-poetry','','[]','天涯春色蜀川多，勝賞相從到薜蘿。',64,'全唐诗/poet.song.36000.json','["天涯春色蜀川多，勝賞相從到薜蘿。", "遶郭烟蕪深似染，隔林山鳥靜能歌。", "花邊密擁青絲蓋，陌上輕馳白玉珂。", "察俗自知無遠術，祇於民樂驗時和。"]'),
('c6f29a39-821e-47d4-91bd-a619d82f6715','和吳仲庶晚春遊海雲','范純仁','宋','宋诗','song-poetry','','[]','東郊行樂冠西州，古寺岧嶢翠嶺頭。',64,'全唐诗/poet.song.36000.json','["東郊行樂冠西州，古寺岧嶢翠嶺頭。", "化俗文翁傳豈弟，尋山謝傅繼風流。", "天涯尊酒欣相遇，劍外三春得共遊。", "雅興直須窮勝賞，年光難使隙駒留。"]'),
('d3666f62-5346-4b0e-9334-52da8ebb11da','又和暮春蠶市','范純仁','宋','宋诗','song-poetry','','[]','古祠幽邃錦城隈，千騎懽游宴席開。',64,'全唐诗/poet.song.36000.json','["古祠幽邃錦城隈，千騎懽游宴席開。", "盡日風光隨綵旆，一方民樂在春臺。", "江頭佛寺藏深竹，郊外人家蔭綠槐。", "已奉更書催別緒，肯辭清賞屢追陪。"]'),
('0a717807-e902-4e14-95dc-f899dbe2f72a','寄臨邛致政常郎中','范純仁','宋','宋诗','song-poetry','','[]','東海拋官勇退時，邦人留止任牽衣。',64,'全唐诗/poet.song.36000.json','["東海拋官勇退時，邦人留止任牽衣。", "三朝報國丹心盡，萬里還鄉一棹歸。", "身向清閒添壽考，德因潛隠更光輝。", "常思把酒親高議，何日單車遂扣扉。"]'),
('468bb397-5c00-46a2-9ea0-5c5a2e3e0526','寄持正都官按部嘉眉','范純仁','宋','宋诗','song-poetry','','[]','使者觀風過晚春，逢山應暫柅征輪。',64,'全唐诗/poet.song.36000.json','["使者觀風過晚春，逢山應暫柅征輪。", "雲埋雪嶺鋪銀界，日射金仙照碧津。", "千里謳謠民足食，萬家水竹地無塵。", "未能結駟相從去，簿領空嗟絆此身。"]'),
('f0108494-97b9-4ac6-87c9-378106f6be33','以眉州綠荔枝寄吳仲庶有詩次韵','范純仁','宋','宋诗','song-poetry','','[]','嘉川荔子著芳名，携從歸鞍到錦城。',64,'全唐诗/poet.song.36000.json','["嘉川荔子著芳名，携從歸鞍到錦城。", "馳驛幸無唐日貢，甘芹聊致野人情。", "丹砂結顆藏膏露，赭縠爲囊貯嫩瓊。", "京洛不須圖畫去，得公佳句自分明。"]'),
('81b10a5c-b3ca-4914-9083-781a7bf0ab3b','和仲庶江瀆避暑','范純仁','宋','宋诗','song-poetry','','[]','古祠清燕敞虛堂，喬木森森晝景長。',64,'全唐诗/poet.song.36000.json','["古祠清燕敞虛堂，喬木森森晝景長。", "池面雨來荷助響，席間風細篆生香。", "烏紗傾側朋簪樂，翠縠翩翻舞袖長。", "牽俗自嗟行役去，阻陪千騎醉瑶觴。"]'),
('a7edfead-67c3-4dfe-9ace-1e8e557ef6cc','將出蜀次仲庶送行詩韵敘別','范純仁','宋','宋诗','song-poetry','','[]','遠客親仁豈素期，况陪文酒復經時。',64,'全唐诗/poet.song.36000.json','["遠客親仁豈素期，况陪文酒復經時。", "自慚拙宦多遷逐，每歎良朋易別離。", "白首馮唐空已老，清秋宋玉不勝悲。", "仰公早展經綸志，百辟方今待允釐。"]'),
('48d5e20a-9ab7-40c2-aec2-6d815c1d725b','寄李審言龍圖','范純仁','宋','宋诗','song-poetry','','[]','英風一別幾經年，尊酒相逢意灑然。',64,'全唐诗/poet.song.36000.json','["英風一別幾經年，尊酒相逢意灑然。", "欲報重知慚國士，喜同清議屬真賢。", "武侯方屈南陽卧，蕭相曾封漢水邊。", "好及新春頒惠化，行藏吾道合推天。"]'),
('db7b9de1-0b6e-4ca3-8fb7-7f77bbf09bb3','酬張杲卿相公見招','范純仁','宋','宋诗','song-poetry','','[]','先君同榜更何人，教育偏蒙契義親。',64,'全唐诗/poet.song.36000.json','["先君同榜更何人，教育偏蒙契義親。", "孔氏繫匏暫滯迹，遼陽歸鶴羨閒身。", "四朝盛事渾經眼，千日濃醪好入脣。", "箕潁更無高放客，只應梅柳爲公春。"]'),
('88a759cb-e8eb-427d-961c-28c5fa4d8126','和閻五秀才折海棠見贈','范純仁','宋','宋诗','song-poetry','','[]','蜀國海棠春最妍，萬枝紅錦憶曾觀。',32,'全唐诗/poet.song.36000.json','["蜀國海棠春最妍，萬枝紅錦憶曾觀。", "鄉人折贈情尤重，肯與群花一等看。"]'),
('c9055a19-b203-450b-93f6-ca7fba5e3047','宿州元太守北樓席上','范純仁','宋','宋诗','song-poetry','','[]','七月高樓暑氣回，荷香細逐水風來。',64,'全唐诗/poet.song.36000.json','["七月高樓暑氣回，荷香細逐水風來。", "翠蛾細袖歌聲遠，綠野蒼山醉眼開。", "羈客秋懷追屈宋，主人交義繼陳雷。", "他年林下相逢去，詩酒何妨許重陪。"]'),
('13ef7ac1-32ce-4304-a11b-23dcd059213f','和吳伯脩洞霄宮','范純仁','宋','宋诗','song-poetry','','[]','三朝勤瘁不謀身，今日官閒與道親。',64,'全唐诗/poet.song.36000.json','["三朝勤瘁不謀身，今日官閒與道親。", "紆組還鄉宜最樂，居山得祿未全貧。", "性情有暇窮真理，門館無權少俗賓。", "會待收蹤歸畎畝，就君同醉洞天春。"]'),
('095d26f4-1a9f-4dc3-8211-85c865f76714','和滕中舍見寄','范純仁','宋','宋诗','song-poetry','','[]','蘄水分携自昔時，六年奔走困長岐。',64,'全唐诗/poet.song.36000.json','["蘄水分携自昔時，六年奔走困長岐。", "人憐家世三朝舊，身在風波一葉危。", "白髮星星驚歲月，丹心皎皎仗朋知。", "林泉早晚歸休去，廩祿無厭愧漏巵。"]'),
('781f379a-dde0-452b-8c0e-b0a455e4e2c7','和李敷察推即席感舊二首  其一','范純仁','宋','宋诗','song-poetry','','[]','相逢同榜盛當年，喜復君來對此筵。',64,'全唐诗/poet.song.36000.json','["相逢同榜盛當年，喜復君來對此筵。", "花下莫辭頻把酒，月中曾是共登仙。", "左遷還有麤官樂，晚達何妨秀句傳。", "得失已看如塞馬，苦心勞力亦徒然。"]'),
('13a64936-e05b-4da5-ae3b-5f3e4e7a09e1','和李敷察推即席感舊二首  其二','范純仁','宋','宋诗','song-poetry','','[]','一榜登科二十年，江城偶得共盤筵。',64,'全唐诗/poet.song.36000.json','["一榜登科二十年，江城偶得共盤筵。", "鄭公雅喜中都職，梅福曾由邑吏僊。", "白首相期情契厚，素風猶待子孫傳。", "狂歌醉舞形骸外，吾道從來况坦然。"]'),
('9847ccbc-151e-4fff-aa3b-61443a16d4bd','送宋大卿歸淝上','范純仁','宋','宋诗','song-poetry','','[]','眉壽康寧位九卿，人間五福最難并。',64,'全唐诗/poet.song.36000.json','["眉壽康寧位九卿，人間五福最難并。", "丹心報國冰霜潔，白首還家里社榮。", "化日盡輸高世樂，野雲應似出門情。", "淮淝美事傳千載，何止孤風激後生。"]'),
('92361ce7-ac62-472b-87d1-e8965e992972','和孔宗翰郎中見寄','范純仁','宋','宋诗','song-poetry','','[]','聖人流澤到真賢，直節清名奕世傳。',64,'全唐诗/poet.song.36000.json','["聖人流澤到真賢，直節清名奕世傳。", "惠政謳謠騰楚甸，醉吟風月滿江天。", "嗟予濫典劭農印，歸老幾無坐客氈。", "一得新詩清百慮，黄粱未熟且安眠。"]'),
('f5c117eb-1603-4ea2-adca-e74d237f7573','和傅欽之見寄','范純仁','宋','宋诗','song-poetry','','[]','至道潛心信有功，目前超悟忽圓通。',64,'全唐诗/poet.song.36000.json','["至道潛心信有功，目前超悟忽圓通。", "三身不在諸塵外，萬象全歸一照中。", "念絕去來隨處樂，法無取舍自然空。", "護持雅屬當仁力，枉問麻陽懶鈍翁。"]'),
('bb1c406e-6633-446b-b8bd-86cb837bc91b','和余周郎中見寄','范純仁','宋','宋诗','song-poetry','','[]','宦遊從昔各艱難，方寸寧禁百慮干。',64,'全唐诗/poet.song.36000.json','["宦遊從昔各艱難，方寸寧禁百慮干。", "憂患早催顔鬢老，風波回念骨毛寒。", "詞場久託平生契，酒席方陪此日歡。", "致主庇民嗟晚矣，只堪相約挂塵冠。"]'),
('c94f86c0-7540-448d-9018-7a68f3b66e7c','章伯望郊居','范純仁','宋','宋诗','song-poetry','','[]','獨愛高居遠市廛，簷楹軒豁對江天。',64,'全唐诗/poet.song.36000.json','["獨愛高居遠市廛，簷楹軒豁對江天。", "門前一曲平橋水，舍側千畦附郭田。", "鷗鳥漸能親几杖，兒童應解愛林泉。", "朝廷方待忠賢急，莫厭京塵撲馬韉。"]'),
('7f48db91-aabd-41cb-a48d-77602dc870ae','和張掞侍郎見寄','范純仁','宋','宋诗','song-poetry','','[]','戀德懷賢出禁城，片心長挂若摇旌。',64,'全唐诗/poet.song.36000.json','["戀德懷賢出禁城，片心長挂若摇旌。", "留侯老棄人間事，白傅詩傳海外名。", "瀟灑琴尊資上壽，太平風月屬高情。", "已知世故無關慮，佳句猶煩訓後生。"]'),
('ccaf0af7-953a-41c1-8306-139c74c1bcd0','金陵懷古二首  其一','范純仁','宋','宋诗','song-poetry','','[]','天兵從昔度長橋，四海干戈一戰銷。',32,'全唐诗/poet.song.36000.json','["天兵從昔度長橋，四海干戈一戰銷。", "江叟豈能知帝力，醉憑漁艇亢秋潮。"]'),
('2d1aa205-92b4-4814-a4ef-56787714e1fa','金陵懷古二首  其二','范純仁','宋','宋诗','song-poetry','','[]','六朝文物今何在，千里江山自宛然。',32,'全唐诗/poet.song.36000.json','["六朝文物今何在，千里江山自宛然。", "英武南征無殺伐，至今樵牧尚能傳。"]'),
('de503d93-0be0-485f-bcc5-11f45ed0722c','和元子發學士見寄','范純仁','宋','宋诗','song-poetry','','[]','二紀區區困宦遊，相逢莫訝鬢先秋。',64,'全唐诗/poet.song.36000.json','["二紀區區困宦遊，相逢莫訝鬢先秋。", "清時無補身空老，往事難追涕旋流。", "舉世交情憐我少，經旬行色爲君留。", "何時歸去江湖上，風月同尋范蠡舟。"]'),
('2c866f6b-3774-4dc9-847c-067c1d9ccfc5','和王著作見寄','范純仁','宋','宋诗','song-poetry','','[]','疏慵齋閣晝常扃，忽喜君來病魄醒。',64,'全唐诗/poet.song.36000.json','["疏慵齋閣晝常扃，忽喜君來病魄醒。", "走訪禪山諸洞穴，醉吟詞客舊林亭。", "十年多難頭俱白，四友相看眼共青。", "別後新詩收滿軸，芝蘭雖遠有餘馨。"]'),
('88420926-7ca1-496c-9c70-b8ba383dace9','和李敷重九席上遣興','范純仁','宋','宋诗','song-poetry','','[]','謫居閒僻少朋游，珍重征帆肯暫收。',64,'全唐诗/poet.song.36000.json','["謫居閒僻少朋游，珍重征帆肯暫收。", "多難共驚霜遶鬢，重陽還喜菊盈甌。", "樓前雨洗千山翠，天際江橫萬里秋。", "節物相催人漸老，此身何日得歸休。"]'),
('c6fa1aaa-03a4-41a4-9f9e-e8cee9902e0b','和謝師厚見寄','范純仁','宋','宋诗','song-poetry','','[]','地僻官麤儔侶稀，鄉關回首隔殘暉。',64,'全唐诗/poet.song.36000.json','["地僻官麤儔侶稀，鄉關回首隔殘暉。", "鬢霑楚霧人空老，水落紅沙雁自歸。", "往事尋思都似夢，素期乖失謾知非。", "東風送雨長西去，心逐輕雲日夜飛。"]'),
('f8c9baa9-5dbd-486c-a9aa-dfa2c5b6888f','中秋賞月','范純仁','宋','宋诗','song-poetry','','[]','碧落無雲玉鑒飛，淨中毫髮了能窺。',64,'全唐诗/poet.song.36000.json','["碧落無雲玉鑒飛，淨中毫髮了能窺。", "光隨酒蟻斟銀榼，彩瑩歌人發瓠犀。", "露重已從巾角墊，輪傾欲把斗杓携。", "醉狂直好探蟾窟，安得陵空萬仞梯。"]'),
('ade60d7c-9401-455b-8c0f-d2a98039b7f7','和耿憲見贈','范純仁','宋','宋诗','song-poetry','','[]','仕途名迹本幽遐，諫省俄登忝世家。',64,'全唐诗/poet.song.36000.json','["仕途名迹本幽遐，諫省俄登忝世家。", "恩戴丘山宜盡瘁，言關社稷敢欹邪。", "獻芹寧識羔羊美，抱甕徒爲智士嗟。", "君子一言華衮重，此身被服愧無涯。"]'),
('f836f7f7-90d8-4d85-8463-ba102c7c9557','和徐郎中柏枝甘露','范純仁','宋','宋诗','song-poetry','','[]','素液濃甘勝醴飴，偏零翠柏瑞明時。',32,'全唐诗/poet.song.36000.json','["素液濃甘勝醴飴，偏零翠柏瑞明時。", "何如溥作豐年澤，萬物涵濡被福釐。"]'),
('482a8245-73c4-49dc-98ee-e40407997563','和曹職方至日','范純仁','宋','宋诗','song-poetry','','[]','宦遊將老愧蓬飄，逢節他鄉倍寂寥。',64,'全唐诗/poet.song.36000.json','["宦遊將老愧蓬飄，逢節他鄉倍寂寥。", "世網縈身難自解，鬢霜凝鑒不重消。", "隨陽鳴雁聞初急，向日丹楓惜半凋。", "飽暖全家盡君賜，忍看編戶獨無聊。"]'),
('1b0c2d5c-5b4a-461b-8b51-d12a406b0fbe','和耿憲秘校喜雨','范純仁','宋','宋诗','song-poetry','','[]','愆陽六月氣仍驕，多士身勞思亦焦。',64,'全唐诗/poet.song.36000.json','["愆陽六月氣仍驕，多士身勞思亦焦。", "膏澤俄隨恩詔溥，螟蝗半逐野雲飄。", "歲時敢望家聊給，賦歛能供政有條。", "鑿井耕田忘帝力，何當鼓腹播民謠。"]'),
('350e0a1f-b2d3-4e72-9cf1-88fc63867bab','題李子高虞部園四首  其一','范純仁','宋','宋诗','song-poetry','','[]','今時難得是高人，里社因君俗愈醇。',32,'全唐诗/poet.song.36000.json','["今時難得是高人，里社因君俗愈醇。", "松竹漸成風月好，只應終日聽韶鈞。"]'),
('9be421b0-6079-4ae8-9a9e-6e4344de0727','題李子高虞部園四首  其二','范純仁','宋','宋诗','song-poetry','','[]','脩鍊工夫合自然，河車潛引玉池泉。',32,'全唐诗/poet.song.36000.json','["脩鍊工夫合自然，河車潛引玉池泉。", "老君道德人難識，復見雲孫達二篇。"]'),
('ce83ac97-3625-40bc-b153-848b90e74013','題李子高虞部園四首  其三','范純仁','宋','宋诗','song-poetry','','[]','全家歸隠似前賢，碧酒醇醲白蟹鮮。',32,'全唐诗/poet.song.36000.json','["全家歸隠似前賢，碧酒醇醲白蟹鮮。", "心欲生民常富壽，高歌會樂太平年。"]'),
('ae11da35-2239-42f5-97b5-534a7b4d6a36','題李子高虞部園四首  其四','范純仁','宋','宋诗','song-poetry','','[]','不教外物翳襟懷，明合蓍龜亦信哉。',32,'全唐诗/poet.song.36000.json','["不教外物翳襟懷，明合蓍龜亦信哉。", "駑蹇自慚無駿骨，謾勞伯樂品題來。"]'),
('614478d1-fc50-4742-8611-065bfd0cf392','和曹演甫中秋見懷','范純仁','宋','宋诗','song-poetry','','[]','去年對月憶良朋，今夕誰同塞上情。',64,'全唐诗/poet.song.36000.json','["去年對月憶良朋，今夕誰同塞上情。", "華髮蒼顔人易老，賞心樂事古難并。", "戍樓笛響千山迥，沙漠霜寒萬里明。", "半夜歸鴻飛不斷，好將幽夢到淮城。"]'),
('ece6450c-76fd-40d0-9c22-6bab34af8d6c','和閻灝屯田五十歲元日感懷','范純仁','宋','宋诗','song-poetry','','[]','君緣直道阻橫飛，我愧無才振國威。',64,'全唐诗/poet.song.36000.json','["君緣直道阻橫飛，我愧無才振國威。", "同榜同僚忝契分，使秦使蜀重親依。", "裹糧衣帛身空老，學易知天志尚違。", "白首相期惟信義，世情徒是亦徒非。"]'),
('771be324-2692-480f-84cb-bf7daef8f1da','和吳仲舉通判見贈','范純仁','宋','宋诗','song-poetry','','[]','侍行曾見羽書飛，獨鶴歸遼想令威。',64,'全唐诗/poet.song.36000.json','["侍行曾見羽書飛，獨鶴歸遼想令威。", "三紀家聲幾泯泯，重來民俗尚依依。", "脫身負擔誠多幸，屏迹山林願正違。", "主諾已繄賢者助，第承先業愧才非。"]'),
('cb6af8a7-681b-4c64-9d76-2e837b7cd393','塞下追憶烏江之會寄李誠之待制','范純仁','宋','宋诗','song-poetry','','[]','主人忘倦客忘歸，長憶江邊惜別時。',64,'全唐诗/poet.song.36000.json','["主人忘倦客忘歸，長憶江邊惜別時。", "日下青山猶促席，風衝畫鷁正酬詩。", "盤堆白玉鱸腴美，手擘黄金蟹殻肥。", "今日相思孤戍裏，塵沙滿眼鬢垂絲。"]'),
('dca8730c-9615-47ae-b7cf-06ea3c4a9771','和閻灝重陽見贈二首  其一','范純仁','宋','宋诗','song-poetry','','[]','秋懷多感怯清笳，判向西風醉帽斜。',64,'全唐诗/poet.song.36000.json','["秋懷多感怯清笳，判向西風醉帽斜。", "塞上星霜人易老，幕中談笑客偏嘉。", "金英浮酒稠於蟻，丹葉妝林遠似花。", "身健幾逢佳節在，登臨尤更惜年華。"]'),
('b9e1d3b6-0ae1-47c6-b0f9-691d26a868dc','和閻灝重陽見贈二首  其二','范純仁','宋','宋诗','song-poetry','','[]','登高宜不負良期，須信時光似隙暉。',64,'全唐诗/poet.song.36000.json','["登高宜不負良期，須信時光似隙暉。", "碧穗引鑪香滿坐，黄金遶席菊成圍。", "物華旋逐鳴飆減，客思空隨去雁飛。", "莫訝尊前偏醉倒，醉鄉纔到便忘歸。"]'),
('0704d96b-c549-4891-833b-a0855432395e','和曹演甫秋日見寄','范純仁','宋','宋诗','song-poetry','','[]','九日天邊倚戍樓，他年江國想陪遊。',64,'全唐诗/poet.song.36000.json','["九日天邊倚戍樓，他年江國想陪遊。", "鱸腴滑與蓴絲薦，菊蘂香隨酒蟻浮。", "別後星霜催老態，秋來顔鬢染鄉愁。", "懷賢感舊情難盡，待向東西丐一州。"]'),
('8c583779-c616-4df9-a1bd-a0c2dab312da','王聖美太丞奉使西來喜而有贈','范純仁','宋','宋诗','song-poetry','','[]','賢愚雖間契稠重，科籍同兼甲子同。',64,'全唐诗/poet.song.36000.json','["賢愚雖間契稠重，科籍同兼甲子同。", "省斂劭農明主意，霽威問俗古人風。", "陽和煦物先春到，膏澤隨車大旱中。", "感舊知恩誰最篤，塞垣憔悴一衰翁。"]'),
('fc52c5ed-f56a-4675-93b5-df504fabde18','和聖美觀騎士翥坡','范純仁','宋','宋诗','song-poetry','','[]','翩翩飛鞚發雲間，壯士旁觀亦汗顔。',64,'全唐诗/poet.song.36000.json','["翩翩飛鞚發雲間，壯士旁觀亦汗顔。", "勢若投丸當峻坂，影如掣電下空山。", "漢兵神速從天落，楚騎飆馳取將還。", "聖主恩深懷獷俗，謾教角逐向安閒。"]'),
('cba1825a-f72b-40d8-b019-653d186d9688','和聖美壁間題','范純仁','宋','宋诗','song-poetry','','[]','胡懾天威自走藏，腐儒焉用合還鄉。',64,'全唐诗/poet.song.36000.json','["胡懾天威自走藏，腐儒焉用合還鄉。", "駑駘戀主心終在，鼯鼠營身技不長。", "晚歲胸襟成濩落，故山林壑謾青蒼。", "進趨無術歸無計，聊得君詩浣肺腸。"]'),
('b7327376-1a49-4fbe-86ee-0940040edb50','和聖美三岔鋪留題','范純仁','宋','宋诗','song-poetry','','[]','今日天涯同一笑，當年澤畔共長吟。',32,'全唐诗/poet.song.36000.json','["今日天涯同一笑，當年澤畔共長吟。", "還朝未復中臺職，報主長存國士心。"]'),
('beed692f-ee40-4902-9690-e843c310c74e','蕃舞','范純仁','宋','宋诗','song-poetry','','[]','低昂坐作疾如風，羌管夷歌唱和同。',32,'全唐诗/poet.song.36000.json','["低昂坐作疾如風，羌管夷歌唱和同。", "應爲降胡能蹈抃，不妨全活向軍中。"]'),
('e0daca6e-e30c-49d0-a874-2b8fbe81f413','觀疆人翥坡','范純仁','宋','宋诗','song-poetry','','[]','蟻分突騎向高岑，馳下危塗萬丈深。',32,'全唐诗/poet.song.36000.json','["蟻分突騎向高岑，馳下危塗萬丈深。", "獷俗輕生唯鬭險，垂堂寧復戒千金。"]'),
('b3c4d447-5ba7-4342-a5cb-46d08a118faa','和聖美華池感事','范純仁','宋','宋诗','song-poetry','','[]','聖主憂勤百職脩，忠臣那復作身謀。',64,'全唐诗/poet.song.36000.json','["聖主憂勤百職脩，忠臣那復作身謀。", "遐方民力資周度，晚歲人情樂小休。", "郭震能僵烏質脛，陳湯解斬郅支頭。", "知賢獨恨官疏遠，珠璧何時免暗投。"]'),
('0a8d8561-058c-4fe4-97fd-221430341ea4','寄陳述古賓客萬璉郎中二首  其一','范純仁','宋','宋诗','song-poetry','','[]','智淺才疏合竄流，生逢堯舜忍空休。',64,'全唐诗/poet.song.36000.json','["智淺才疏合竄流，生逢堯舜忍空休。", "猶慙世舊垂青眼，未報君恩已白頭。", "貴老何由操几杖，愛賢曾是繼箕裘。", "新春遥祝增眉壽，阻向賓筵跪一甌。"]'),
('f4e32578-0cbb-473f-a418-a867bf390577','寄陳述古賓客萬璉郎中二首  其二','范純仁','宋','宋诗','song-poetry','','[]','欣欣萬物占芳春，對景那知放逐身。',64,'全唐诗/poet.song.36000.json','["欣欣萬物占芳春，對景那知放逐身。", "粗守素風諳左宦，擬投白社愧高人。", "漢疏蚤命東門駕，商老方爲少海賓。", "空辱忘年微報稱，浪酬佳唱恃心親。"]'),
('229413c4-f749-43e7-b468-4d7631cee984','和王定國見寄','范純仁','宋','宋诗','song-poetry','','[]','危蹤俄復罣刑書，得喪情懷久已無。',64,'全唐诗/poet.song.36000.json','["危蹤俄復罣刑書，得喪情懷久已無。", "憂道不知身竄逐，登山未敵世崎嶇。", "戀軒無計慚疲馬，向日低飛作晚烏。", "薄祿未拋生事拙，涸鱗徒憶縱江湖。"]'),
('30966cff-dfb9-4480-8ae7-b748828c5058','和張伯常見寄','范純仁','宋','宋诗','song-poetry','','[]','芳信初傳喜滿胸，開緘氣燄若長虹。',64,'全唐诗/poet.song.36000.json','["芳信初傳喜滿胸，開緘氣燄若長虹。", "文牆目視曹劉短，詩將壇登李杜雄。", "一別寒暄迷甲子，十年塵土謾西東。", "知君善誘存先契，不欲疏頑墜素風。"]'),
('576d9bed-df3c-4b14-8743-6904c8d219d7','春日寄許州韓持國','范純仁','宋','宋诗','song-poetry','','[]','湖上春游阻重陪，朱轓紅旆想徘徊。',32,'全唐诗/poet.song.36000.json','["湖上春游阻重陪，朱轓紅旆想徘徊。", "鶑花對席應相覓，不見頻携醉客來。"]'),
('f1dea06f-50bd-4415-adb5-cf3a103c6164','和李康侯屯田見寄韵二首  其一','范純仁','宋','宋诗','song-poetry','','[]','心爲積仁唯豈弟，官因任直少升遷。',64,'全唐诗/poet.song.36000.json','["心爲積仁唯豈弟，官因任直少升遷。", "處常自享榮期樂，早退皆輸白傅賢。", "官路風波今免矣，善人福壽固宜然。", "謫居未遂歸田計，猶欲希風向暮年。"]'),
('d0b30b64-e78b-4ee3-aaea-8aede2461dd6','和李康侯屯田見寄韵二首  其二','范純仁','宋','宋诗','song-poetry','','[]','仕途三黜信多難，名迹常憂不自完。',64,'全唐诗/poet.song.36000.json','["仕途三黜信多難，名迹常憂不自完。", "幸頼聖恩寬罪戾，敢辭閒地儘盤桓。", "孟生墜甑何能顧，貢禹塵冠豈復彈。", "俸入雖貧家世事，釜魚前世已稱丹。"]'),
('0eee6ce4-15cf-4fdf-9f89-b24076fad8ec','雪中池上','范純仁','宋','宋诗','song-poetry','','[]','碧玉爲池白玉堤，千林萬木盡花開。',32,'全唐诗/poet.song.36000.json','["碧玉爲池白玉堤，千林萬木盡花開。", "携賓欲覓開尊處，祇得清香辨野梅。"]'),
('018dbf05-b454-47ac-bc65-796a6ffee967','和管滂著作見寄韵','范純仁','宋','宋诗','song-poetry','','[]','生平迂拙畏非彝，苦愛曾顔道甚夷。',64,'全唐诗/poet.song.36000.json','["生平迂拙畏非彝，苦愛曾顔道甚夷。", "麋鹿豈堪嬰組紱，漁樵只合在山陂。", "遭時不歎馮唐老，忍恥空慚鮑叔知。", "盈紙更煩佳句贈，雅情深厚俗難窺。"]'),
('16130d2d-2eef-40fd-b80c-0fe21f8b4d3a','又和席上見贈','范純仁','宋','宋诗','song-poetry','','[]','官舍荒凉近古城，園林七月起秋聲。',64,'全唐诗/poet.song.36000.json','["官舍荒凉近古城，園林七月起秋聲。", "偶來嘉客從芸省，似對清冰滿玉罌。", "談笑從容誠吏隠，逢迎疏野愧朝英。", "田廬未得長歸去，山鳥知人半夜鳴。"]'),
('3d346b51-3370-476d-a0b2-53fd9a0d1683','和任夔節推見寄','范純仁','宋','宋诗','song-poetry','','[]','暗拙行身足險艱，青雲有路敢思攀。',96,'全唐诗/poet.song.36000.json','["暗拙行身足險艱，青雲有路敢思攀。", "學承詩禮難窺奧，仕偶唐虞樂抱關。", "掌諫何能裨衮職，護邊無術勒燕山。", "風波忽起人情外，瓜李終由自處間。", "白髮報君嗟已晚，清朝謫宦愧多閒。", "夫君年壯才方劭，豈合迂遲與我班。"]'),
('237d5b47-e387-4f67-bd0a-2c47a50b9138','和王樂道西湖席上','范純仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春湖景物畫圖中，朱閣偏宜翠柳籠。',64,'全唐诗/poet.song.36000.json','["春湖景物畫圖中，朱閣偏宜翠柳籠。", "上客縱談髯奮白，佳人醉舞臉舒紅。", "鋪張錦繡花邊日，堆疊琉璃水面風。", "民俗歡游魚鳥樂，主人才合代天工。"]'),
('f58542bc-959a-4512-bea5-f6718a9f63d7','和王定國見寄','范純仁','宋','宋诗','song-poetry','','[]','謫居終日省愆尤，貝錦雖成職我由。',64,'全唐诗/poet.song.36000.json','["謫居終日省愆尤，貝錦雖成職我由。", "萍梗屢嗟罹放逐，風波更險信沈浮。", "生還故里誠多幸，坐廢明時敢不憂。", "自是無才速官謗，非關有命壓人頭。"]'),
('861b60cc-fba3-4e8c-bede-04805f42848a','病起和李康侯屯田見寄','范純仁','宋','宋诗','song-poetry','','[]','養生不達嵇康論，知止聊遵老氏書。',64,'全唐诗/poet.song.36000.json','["養生不達嵇康論，知止聊遵老氏書。", "左宦行將三歲許，羸痾復卧四旬餘。", "手扶瘦竹形相稱，鬢擬新霜色一如。", "獨枉故人詩意重，涅磨無改是璠璵。"]'),
('9adcf615-a4ec-4093-9a86-730e1ce85ed2','和郭昌朝寺丞見寄二首  其一','范純仁','宋','宋诗','song-poetry','','[]','岷峨秀氣入京華，鵬翼摶風勢莫涯。',64,'全唐诗/poet.song.36000.json','["岷峨秀氣入京華，鵬翼摶風勢莫涯。", "崑玉照人呈美璞，楚蘭芬畹擢新芽。", "朝廷遷陟先諸彥，閭里光榮在一家。", "不鄙義陽疲病守，肯來同醉岸烏紗。"]'),
('084d8da4-a6ff-4b5f-a1cd-74671e41dfca','和郭昌朝寺丞見寄二首  其二','范純仁','宋','宋诗','song-poetry','','[]','言路再居無少補，護邊三歲乏微勛。',64,'全唐诗/poet.song.36000.json','["言路再居無少補，護邊三歲乏微勛。", "非才自合投閑地，竭節終期報聖君。", "老去年光流似水，病來世味薄如雲。", "讀書記一將忘十，少壯誰教不自勤。"]'),
('05b7d950-c4ef-4ded-9938-ed0ce8d74914','和王微之同持國泛舟登樓','范純仁','宋','宋诗','song-poetry','','[]','故人還喜笑言同，把酒相看似夢中。',64,'全唐诗/poet.song.36000.json','["故人還喜笑言同，把酒相看似夢中。", "老去卜鄰逢晏子，從來解榻頼陳公。", "畫船穩泛平溪淥，層觀高橫落日紅。", "莫訝狂歌先盡醉，預愁羈旅向山東。"]'),
('33fa5c9a-4b47-4e1a-a3fb-f3f687162454','和鄭通議青州范公泉','范純仁','宋','宋诗','song-poetry','','[]','勝概因人得久存，此泉疏鑿自先君。',64,'全唐诗/poet.song.36000.json','["勝概因人得久存，此泉疏鑿自先君。", "發源不負當時意，清影猶涵昔日雲。", "養正迥當深澗下，朝宗應與衆流分。", "今逢賢帥光陳迹，名逐新詩海內聞。"]'),
('0fd6f6b1-d10d-492e-8477-25e1932948eb','張掞侍郎讀書堂','范純仁','宋','宋诗','song-poetry','','[]','三紀仁皇侍從臣，當時文學動簪紳。',64,'全唐诗/poet.song.36000.json','["三紀仁皇侍從臣，當時文學動簪紳。", "高明已入儒林傳，舊室長存歷水濱。", "峴首空留王粲宅，香山猶識白公真。", "他年遺跡應無廢，不墜詩書世有人。"]'),
('72223a63-7669-4e5d-ad06-9b0c6149a664','和劉孝叔吏部見寄','范純仁','宋','宋诗','song-poetry','','[]','一自淮陽阻見賢，俄驚壯齒變衰年。',64,'全唐诗/poet.song.36000.json','["一自淮陽阻見賢，俄驚壯齒變衰年。", "宦游嗟我身名玷，早退輸君福壽延。", "別後童顔應不改，何時醉袂復相連。", "白頭猶忝山城守，常愧君恩未盡宣。"]'),
('01d81c36-3837-45b0-bf92-ff8630392094','和北都王宣徽贈覺海大師','范純仁','宋','宋诗','song-poetry','','[]','心鏡如如絕斷常，人天魔怨詎能傷。',64,'全唐诗/poet.song.36000.json','["心鏡如如絕斷常，人天魔怨詎能傷。", "本來面目超諸相，自在威儀遍十方。", "石火電光隨事過，龜毛兔角竟誰長。", "真風到處堪行化，何必江西選佛場。"]'),
('0e8d0a0c-7e11-4bdd-826d-eb47b8b7b6e2','和黄康侯推官二首  其一','范純仁','宋','宋诗','song-poetry','','[]','得請西臺鬢已班，便乘驄馬出齊山。',64,'全唐诗/poet.song.36000.json','["得請西臺鬢已班，便乘驄馬出齊山。", "舉頭桑梓休懷土，信脚伊嵩勝抱關。", "憔悴精神宜早退，太平官職自多閒。", "三公天下稱人傑，名迹何堪比數間。"]'),
('176e9659-3dbb-478e-8ba7-363a5e648fca','和黄康侯推官二首  其二','范純仁','宋','宋诗','song-poetry','','[]','少多狂拙老慚非，富貴功名得已遲。',64,'全唐诗/poet.song.36000.json','["少多狂拙老慚非，富貴功名得已遲。", "六秩筋骸難任事，十年臺閣謾逢時。", "聖朝貧賤雖堪恥，吏隠優閒合作知。", "回首螭頭嚴近日，恍如曾夢到龍墀。"]'),
('887f8b73-d5e4-4ec4-b878-e48a8db261c6','以府會阻赴王安之招集次安之韵二首  其一','范純仁','宋','宋诗','song-poetry','','[]','西都風物最繁華，真率相延有幾家。',32,'全唐诗/poet.song.36000.json','["西都風物最繁華，真率相延有幾家。", "遊賞直判連日醉，殘春可忍負鶑花。"]'),
('16b06744-1653-4aee-992a-98374f4f12cf','以府會阻赴王安之招集次安之韵二首  其二','范純仁','宋','宋诗','song-poetry','','[]','洛陽春色古稱奇，况復名花世所希。',32,'全唐诗/poet.song.36000.json','["洛陽春色古稱奇，况復名花世所希。", "偶阻嬉遊同一醉，任從旭日麗朝暉。"]'),
('38f46c16-24ff-404c-8ad6-16e5505306a5','和文太師真率會','范純仁','宋','宋诗','song-poetry','','[]','賢者規模衆所遵，屏除外飾貴全真。',64,'全唐诗/poet.song.36000.json','["賢者規模衆所遵，屏除外飾貴全真。", "盍簪既屢宜從簡，爲具雖疏不愧貧。", "免事獻酬脩末節，都將誠實奉嘉賓。", "豈唯同志欣相照，清約猶能化後人。"]'),
('bcc94ad5-cab4-42b4-8154-0894372a7a10','上文潞公同甲會','范純仁','宋','宋诗','song-poetry','','[]','四公眉壽復均年，此會前脩未省傳。',64,'全唐诗/poet.song.36000.json','["四公眉壽復均年，此會前脩未省傳。", "筋力輕安同少壯，風標蕭灑似神僊。", "分司東洛榮難並，聚德西豪事莫肩。", "今夕天官應有奏，老人星彩近台躔。"]'),
('1287a6ba-3a53-4601-a786-c65baa94d43b','送司馬伯康君實歸夏縣','范純仁','宋','宋诗','song-poetry','','[]','金昆玉季老相親，孝弟傳家四海聞。',64,'全唐诗/poet.song.36000.json','["金昆玉季老相親，孝弟傳家四海聞。", "白首還鄉疑廣受，清朝得志異機雲。", "塤箎迭奏聲相應，鴻雁連飛翼不分。", "一夜西風響黄葉，蕭騷助我歎離群。"]'),
('3a577097-66ae-4e7c-bec5-db447e1a3f1a','潞國公生日','范純仁','宋','宋诗','song-poetry','','[]','一陽將復昴當躔，毓粹儲精降巨賢。',64,'全唐诗/poet.song.36000.json','["一陽將復昴當躔，毓粹儲精降巨賢。", "啟迪先朝承大統，贊襄仁祖格皇天。", "備膺百順人誰擬，達有三尊我獨全。", "嵩嶽穹崇河水遠，高名遐壽與之肩。"]'),
('577677ef-d0f7-4e47-a0a5-6b8891cd7bfa','安之家庭甘結實三首  其一','范純仁','宋','宋诗','song-poetry','','[]','溫甘移種自君家，香雪年年只吐花。',32,'全唐诗/poet.song.36000.json','["溫甘移種自君家，香雪年年只吐花。", "結實定非江北枳，新詩先費主人誇。"]'),
('0d79d404-4170-4f1e-ba49-243d9961768d','安之家庭甘結實三首  其二','范純仁','宋','宋诗','song-poetry','','[]','遮藏霜雪免摧殘，綠實初垂未滿欄。',32,'全唐诗/poet.song.36000.json','["遮藏霜雪免摧殘，綠實初垂未滿欄。", "想見主人珍惜意，一回出戶一回看。"]'),
('1c2238d3-3cc4-4ff6-9b89-0a97ed4ffacc','安之家庭甘結實三首  其三','范純仁','宋','宋诗','song-poetry','','[]','花果從來盛洛都，黄甘結實古來無。',32,'全唐诗/poet.song.36000.json','["花果從來盛洛都，黄甘結實古來無。", "分金未足均閭里，就賞應須倒百壺。"]'),
('f942fab9-9524-4ba2-bc27-bafd5e0fd869','子駿作真率會招安之不至二首  其一','范純仁','宋','宋诗','song-poetry','','[]','鄉閭貴老寧牽彊，德齒俱尊合便安。',32,'全唐诗/poet.song.36000.json','["鄉閭貴老寧牽彊，德齒俱尊合便安。", "况是耆英會中客，須同八十主人看。"]'),
('c683becc-89e0-44fe-b6f3-a5e3bb600f7c','子駿作真率會招安之不至二首  其二','范純仁','宋','宋诗','song-poetry','','[]','齊眉舉案人誰似，異膳常珍必自調。',32,'全唐诗/poet.song.36000.json','["齊眉舉案人誰似，異膳常珍必自調。", "真率攀邀宜莫應，蚍蜉大木固難摇。"]'),
('0fb05811-de48-4c2e-90be-64db8a5380bd','八月十六日張伯常見訪賞月四首  其一','范純仁','宋','宋诗','song-poetry','','[]','空庭待月喜佳賓，杯杓頻傳酒易醺。',64,'全唐诗/poet.song.36000.json','["空庭待月喜佳賓，杯杓頻傳酒易醺。", "長笛悠揚侵萬籟，圓蟾瀲灧出重雲。", "辭榮風節輕三事，破的功能伏一軍。", "高興未闌天宇靜，笑談不覺夜將分。"]'),
('b41faf73-7103-40b4-8e39-842b339ac138','八月十六日張伯常見訪賞月四首  其二','范純仁','宋','宋诗','song-poetry','','[]','老來尤喜見朋游，况是才名第一流。',64,'全唐诗/poet.song.36000.json','["老來尤喜見朋游，况是才名第一流。", "今日偶逢甘共醉，他年相憶苦三秋。", "高吟灑落過千首，遺愛深濃在幾州。", "我亦官閒少拘檢，留連寧復問更籌。"]'),
('5612871f-3f22-4174-ba43-4bb10c710a2c','八月十六日張伯常見訪賞月四首  其三','范純仁','宋','宋诗','song-poetry','','[]','白首相知有幾人，良宵難惜醉醺醺。',64,'全唐诗/poet.song.36000.json','["白首相知有幾人，良宵難惜醉醺醺。", "此心直欲清如月，外物何妨薄似雲。", "飲若長鯨吞巨浪，詩如老將納降軍。", "過從幸得閒中樂，好惡榮枯莫彊分。"]'),
('be9b7e14-5343-454b-a41f-41a0088427cf','八月十六日張伯常見訪賞月四首  其四','范純仁','宋','宋诗','song-poetry','','[]','今夕無煩秉燭遊，露華垂葉若珠流。',64,'全唐诗/poet.song.36000.json','["今夕無煩秉燭遊，露華垂葉若珠流。", "翰林偏愛尊中月，詞客休悲洛下秋。", "金谷池臺多勝概，伊川山水近神州。", "從茲只合追清景，世故何煩妄計籌。"]'),
('beee12dc-53a2-4df0-9ea6-610c0b136dac','和子駿洛中書事','范純仁','宋','宋诗','song-poetry','','[]','周公作邑遺成康，玉帛從茲走萬方。',64,'全唐诗/poet.song.36000.json','["周公作邑遺成康，玉帛從茲走萬方。", "四向山河圍殿閣，千家花竹間田桑。", "遊人選勝停車馬，詞客尋春雜詠觴。", "幸得閒官陪几杖，欲酬佳句愧荒唐。"]'),
('23078392-9f8e-46b7-af97-04b229813746','和君實姚黄玉玲瓏二品牡丹二首  其一','范純仁','宋','宋诗','song-poetry','','[]','洛城花美四方歸，獨有姚黄得見稀。',32,'全唐诗/poet.song.36000.json','["洛城花美四方歸，獨有姚黄得見稀。", "曾入黼闈參近侍，分明新染赭黄衣。"]'),
('107a671b-a5ee-428d-aa71-474954aae99e','和君實姚黄玉玲瓏二品牡丹二首  其二','范純仁','宋','宋诗','song-poetry','','[]','花得新朋自我公，潔如明玉狀玲瓏。',32,'全唐诗/poet.song.36000.json','["花得新朋自我公，潔如明玉狀玲瓏。", "芳心有待人難見，小圃深藏洛水東。"]'),
('2a94a2e0-9c87-458f-8562-ef24fabda99b','元日分壺酒贈楊舜俞大卿','范純仁','宋','宋诗','song-poetry','','[]','一別年光已浹辰，相逢重憶蜀江春。',32,'全唐诗/poet.song.36000.json','["一別年光已浹辰，相逢重憶蜀江春。", "欲知盈榼分甘意，旨酒思柔屬故人。"]'),
('03f60e5d-89e6-4eb4-89ba-1a67aefcff09','寄和浮光曹九章大夫','范純仁','宋','宋诗','song-poetry','','[]','賢守班條俗易從，戴其仁厚服其功。',64,'全唐诗/poet.song.36000.json','["賢守班條俗易從，戴其仁厚服其功。", "虛心足以求民瘼，實效應須柬帝衷。", "繾綣交情由道合，連綿榜契復官同。", "當時賜第今無幾，共喜優游作老翁。"]'),
('c41af44e-937d-404c-9c40-576d15751fa5','妙覺晚吟呈席上諸公','范純仁','宋','宋诗','song-poetry','','[]','半生奔走困塵埃，晚得優游掌舊臺。',64,'全唐诗/poet.song.36000.json','["半生奔走困塵埃，晚得優游掌舊臺。", "庭柏歲寒青獨在，林烏朝夕倦重來。", "閒霑薄祿誠多愧，老向清朝信不才。", "唯喜洛城儔侶盛，從容相遇即銜杯。"]'),
('1408c5ef-d2de-4fd2-83a9-381c5333fea2','送伯常歸郢中','范純仁','宋','宋诗','song-poetry','','[]','穰鄧相看少壯時，中間薄宦阻親依。',64,'全唐诗/poet.song.36000.json','["穰鄧相看少壯時，中間薄宦阻親依。", "幸君西洛休官早，值我東齊謝病歸。", "春色滿城游騎縱，月光照席酒觥飛。", "遥知漢上幽棲樂，飽暖全家卧翠微。"]'),
('5542b283-3383-4b44-ab66-0f8c6b34aa40','和韓子華相公同游王君貺園二首  其一','范純仁','宋','宋诗','song-poetry','','[]','隅陪旌旆縱春游，好景偏銷倦客愁。',32,'全唐诗/poet.song.36000.json','["隅陪旌旆縱春游，好景偏銷倦客愁。", "紅杏都開如趁賞，夭桃欲坼尚含羞。"]'),
('1f4361e0-ad0a-40d1-ab8c-d6e6b6acd6dc','和韓子華相公同游王君貺園二首  其二','范純仁','宋','宋诗','song-poetry','','[]','善政多閒若解牛，尋春選勝遍深幽。',32,'全唐诗/poet.song.36000.json','["善政多閒若解牛，尋春選勝遍深幽。", "紅芳翠竹圍松島，彊醉清尊蓋自由。"]'),
('ca2133c8-eb33-44b9-980c-0b46cc4b3ac3','和君實雨中即事二首  其一','范純仁','宋','宋诗','song-poetry','','[]','放盡群花春欲歸，惜春遊樂幸相依。',32,'全唐诗/poet.song.36000.json','["放盡群花春欲歸，惜春遊樂幸相依。", "不堪風雨成暌阻，卧聽蕭騷灑竹扉。"]'),
('202c393b-ed00-47d5-b355-aa90e985649c','和君實雨中即事二首  其二','范純仁','宋','宋诗','song-poetry','','[]','熟寢翻知計慮長，閒齋一枕事都忘。',32,'全唐诗/poet.song.36000.json','["熟寢翻知計慮長，閒齋一枕事都忘。", "自然便是無何境，夢到華胥亦異鄉。"]'),
('80f8dfe3-fb28-4704-8983-926ac79fedce','君實邀遊南園雨止','范純仁','宋','宋诗','song-poetry','','[]','名園選勝許參陪，游騎俄衝急雨回。',64,'全唐诗/poet.song.36000.json','["名園選勝許參陪，游騎俄衝急雨回。", "花裏不聞鶑弄舌，甕頭空愛蟻浮醅。", "寒雲重結三冬雪，暖律虛飛二紀灰。", "深恐群芳便彫落，主人還引上春臺。"]'),
('44e95d80-3ace-4da4-9fd9-78e688a759e9','子華相公應天院行香歸洛川','范純仁','宋','宋诗','song-poetry','','[]','春色鮮明滿洛川，青蕪白鳥望中閒。',64,'全唐诗/poet.song.36000.json','["春色鮮明滿洛川，青蕪白鳥望中閒。", "千門金碧明初日，四面煙嵐簇遠山。", "橋偃長虹當上苑，水淙鳴玉過通闤。", "乘驄幸託車塵後，時頼清尊破客顔。"]'),
('41690227-2a45-4f09-bad7-c6e59adea298','和君實南園獨酌三首  其一','范純仁','宋','宋诗','song-poetry','','[]','晚年光景更關心，尤向芳時惜寸陰。',32,'全唐诗/poet.song.36000.json','["晚年光景更關心，尤向芳時惜寸陰。", "每到園林花好處，常思貰醉解貂金。"]'),
('0b495b7a-7a65-4c35-8a55-c1bfd1d0244d','和君實南園獨酌三首  其二','范純仁','宋','宋诗','song-poetry','','[]','寒食三春氣候深，落英榆莢滿牆陰。',32,'全唐诗/poet.song.36000.json','["寒食三春氣候深，落英榆莢滿牆陰。", "未甘密葉成翠幄，不愛黄花如散金。"]'),
('70c17474-5a2a-4d6a-b21a-b17d1daa3040','和君實南園獨酌三首  其三','范純仁','宋','宋诗','song-poetry','','[]','累日懷賢痗寸心，誰知獨酌醉花陰。',32,'全唐诗/poet.song.36000.json','["累日懷賢痗寸心，誰知獨酌醉花陰。", "公詩字字如珠玉，併得三篇勝萬金。"]'),
('2528ab3e-139b-4373-b163-084dba4ff8ff','酬韓持國','范純仁','宋','宋诗','song-poetry','','[]','獨想當年春宴遊，湖邊日日醉金甌。',32,'全唐诗/poet.song.36000.json','["獨想當年春宴遊，湖邊日日醉金甌。", "三年阻作登龍客，不謂相思已白頭。"]'),
('8f73a745-4e25-4c0a-a476-6b1ffa3f290d','牡丹二首  其一','范純仁','宋','宋诗','song-poetry','','[]','牡丹奇擅洛都春，百卉千花浪糾紛。',64,'全唐诗/poet.song.36000.json','["牡丹奇擅洛都春，百卉千花浪糾紛。", "國色鮮明舒嫩臉，僊冠重疊剪紅雲。", "競馳經品供天賞，旋立佳名竦衆聞。", "園吏遮藏恐凋落，直欹青蓋過殘曛。"]'),
('db3e1dbb-1ff3-45ad-9791-249725bb0e40','牡丹二首  其二','范純仁','宋','宋诗','song-poetry','','[]','奪盡春光勝盡花，都人巧植鬭鮮華。',64,'全唐诗/poet.song.36000.json','["奪盡春光勝盡花，都人巧植鬭鮮華。", "搜奇不憚過民舍，醉賞唯愁污相車。", "密蘂攢心承曉露，繁紅添色映朝霞。", "何妨縱步家家到，園圃相望幸不賒。"]'),
('c42d1f01-3397-4e44-8043-c4c6727abc40','上巳泛舟酬子華相公','范純仁','宋','宋诗','song-poetry','','[]','佳節仍逢善政初，熙然民物在華胥。',64,'全唐诗/poet.song.36000.json','["佳節仍逢善政初，熙然民物在華胥。", "龍樓影裏回仙棹，隼旆光中從相車。", "明媚山川鋪晚照，啁啾絲管響清虛。", "太平應似羲皇世，早晚重看洛出書。"]'),
('f5031056-71c7-47e2-963d-eea9104711b6','和文潞公歸洛賞花','范純仁','宋','宋诗','song-poetry','','[]','公從帝所享鈞天，歸及三春景物妍。',64,'全唐诗/poet.song.36000.json','["公從帝所享鈞天，歸及三春景物妍。", "洛鯉烹鮮隨玉饌，姚黄開晚待瓊筵。", "身同五福居周分，心似南風助舜絃。", "花木只堪供暫賞，直須嵩少伴長年。"]'),
('aa339833-a1b4-4703-bbc8-48e456157cf2','文潞公謝事歸洛二首  其一','范純仁','宋','宋诗','song-poetry','','[]','雲漢成章湛露晞，都門宴餞羽觴飛。',32,'全唐诗/poet.song.36000.json','["雲漢成章湛露晞，都門宴餞羽觴飛。", "謝安不復東山起，爭似阿衡得謝歸。"]'),
('d9e1e327-32a0-4f4e-9fb7-18e12f6cd297','文潞公謝事歸洛二首  其二','范純仁','宋','宋诗','song-poetry','','[]','相國東郊迓帝師，紅幢交映碧參差。',32,'全唐诗/poet.song.36000.json','["相國東郊迓帝師，紅幢交映碧參差。", "都人共喜安輿到，正是餘花可惜時。"]'),
('f6da53db-d985-4cc8-bd68-546e841d0311','和子華陪文潞公宴東田','范純仁','宋','宋诗','song-poetry','','[]','湍流湱湱走平田，清曠園林未暑天。',64,'全唐诗/poet.song.36000.json','["湍流湱湱走平田，清曠園林未暑天。", "遶圃曲堤都種竹，泛舟雙沼不栽蓮。", "沙邊白鷺翹來靜，叢上幽花晚更妍。", "乘月陪歡忘夜久，莎間潛有露珠圓。"]'),
('98119a48-7ddf-4064-8dbc-0f2d30e448a3','效宮詞體上文太師十絕  其一','范純仁','宋','宋诗','song-poetry','','[]','三紀中書更有誰，致君堯舜似臯夔。',32,'全唐诗/poet.song.36000.json','["三紀中書更有誰，致君堯舜似臯夔。", "頻年力請方歸第，天子臨軒冊太師。"]'),
('09ebdb32-af74-439c-888d-8abedb51c7e2','效宮詞體上文太師十絕  其二','范純仁','宋','宋诗','song-poetry','','[]','太師還政異尋常，前殿鋪張冊禮忙。',32,'全唐诗/poet.song.36000.json','["太師還政異尋常，前殿鋪張冊禮忙。", "入對誰知年八十，身輕拜舞謝吾皇。"]'),
('b7b2ba1d-1880-43e1-8155-0c61fda60fa2','效宮詞體上文太師十絕  其三','范純仁','宋','宋诗','song-poetry','','[]','吾皇重喜見儀形，對御排場結綵棚。',32,'全唐诗/poet.song.36000.json','["吾皇重喜見儀形，對御排場結綵棚。", "纔見罷時先賜宴，御前親勸一金觥。"]'),
('e4826136-a3d8-4323-8c8f-72c86673070a','效宮詞體上文太師十絕  其四','范純仁','宋','宋诗','song-poetry','','[]','上前一飲釂金觥，侍宴群公喜且驚。',32,'全唐诗/poet.song.36000.json','["上前一飲釂金觥，侍宴群公喜且驚。", "呂尚鬻熊今復見，神仙不必在蓬瀛。"]'),
('c58328c5-4490-4cdd-8de0-2fed74fe3b67','效宮詞體上文太師十絕  其五','范純仁','宋','宋诗','song-poetry','','[]','蓬瀛聞說有仙居，甲第園林想亦如。',32,'全唐诗/poet.song.36000.json','["蓬瀛聞說有仙居，甲第園林想亦如。", "遶圃琅玕抽翠竹，平流瑟瑟走清渠。"]'),
('a76bb714-6fef-49f2-ab27-61c618f17d09','效宮詞體上文太師十絕  其六','范純仁','宋','宋诗','song-poetry','','[]','清渠瀉水灌東田，十頃方塘不種蓮。',32,'全唐诗/poet.song.36000.json','["清渠瀉水灌東田，十頃方塘不種蓮。", "白鳥往來明鏡裏，畫船安穩坐青天。"]'),
('08e4e9c3-4c85-4127-8802-ba92ca7797aa','效宮詞體上文太師十絕  其七','范純仁','宋','宋诗','song-poetry','','[]','天上雖傳周伯星，應期爲瑞有常經。',32,'全唐诗/poet.song.36000.json','["天上雖傳周伯星，應期爲瑞有常經。", "未如全享康寧福，訪水尋山到處行。"]'),
('867a1aa0-8896-4280-9f2c-7e34040109d9','效宮詞體上文太師十絕  其八','范純仁','宋','宋诗','song-poetry','','[]','行樂心清日日添，詩豪酒健獨能兼。',32,'全唐诗/poet.song.36000.json','["行樂心清日日添，詩豪酒健獨能兼。", "從容對客忘威重，自是天真不是謙。"]'),
('d48168c6-89aa-4172-a442-b8fcf90a5c1e','效宮詞體上文太師十絕  其九','范純仁','宋','宋诗','song-poetry','','[]','謙虛久已得民心，三尹西都惠愛深。',32,'全唐诗/poet.song.36000.json','["謙虛久已得民心，三尹西都惠愛深。", "一自安車朝闕去，萬人側耳聽歸音。"]'),
('47d18391-ec05-48b2-a0f0-1dcfd82d9059','效宮詞體上文太師十絕  其一○','范純仁','宋','宋诗','song-poetry','','[]','歸日天恩賜畫船，傾城士女盡迎觀。',32,'全唐诗/poet.song.36000.json','["歸日天恩賜畫船，傾城士女盡迎觀。", "園家連夜驚筠籠，爲趁明朝獻牡丹。"]'),
('376bdeca-47de-4443-9538-79a94790e008','和子華游韓王園懷故園池蓮紅薇二首  其一','范純仁','宋','宋诗','song-poetry','','[]','丞相園池冠壁田，娉婷次第坼紅蓮。',32,'全唐诗/poet.song.36000.json','["丞相園池冠壁田，娉婷次第坼紅蓮。", "主人居守麟符重，誰見新妝照水妍。"]'),
('aac288ae-42fa-4bed-95fa-98df08f2bca8','和子華游韓王園懷故園池蓮紅薇二首  其二','范純仁','宋','宋诗','song-poetry','','[]','鮮葩嫩蘂吐香濃，千朵妖饒顫晚風。',32,'全唐诗/poet.song.36000.json','["鮮葩嫩蘂吐香濃，千朵妖饒顫晚風。", "却想許園僊品盛，姝衣輕透玉肌紅。"]');
